import React, { useEffect, useState } from 'react';
import { useParams } from 'react-router-dom';
import useGameStore from '../../stores/use-game-store';
import useRoomStore from '../../stores/use-room-store';
import socketService from '../../services/socket-service';
import '../../styles/components/room/game-play.css';

/**
 * GamePlay Component - Real-time quiz gameplay
 * Similar to Kahoot/Quizizz game interface
 */
const GamePlay = ({ isHost, onLeave }) => {
    const { roomId } = useParams();

    const {
        currentQuestion,
        currentQuestionIndex,
        totalQuestions,
        timeRemaining,
        selectedAnswer,
        hasAnswered,
        answerResult,
        players,
        submitAnswer,
        nextQuestion
    } = useGameStore();

    const [showResults, setShowResults] = useState(false);

    useEffect(() => {
        // Show results for 3 seconds after answering
        if (hasAnswered && answerResult) {
            setShowResults(true);
            const timer = setTimeout(() => {
                setShowResults(false);
            }, 3000);
            return () => clearTimeout(timer);
        }
    }, [hasAnswered, answerResult]);

    /**
     * Handle answer selection
     */
    const handleAnswerClick = (answerId) => {
        if (hasAnswered) return;
        submitAnswer(answerId);
    };

    /**
     * Handle next question (host only)
     */
    const handleNextQuestion = () => {
        if (isHost) {
            nextQuestion();
        }
    };

    if (!currentQuestion) {
        return (
            <div className="game-play-container">
                <div className="loading-question">
                    <div className="spinner"></div>
                    <p>Đang tải câu hỏi...</p>
                </div>
            </div>
        );
    }

    return (
        <div className="game-play-container">
            {/* Header */}
            <div className="game-header">
                <div className="question-progress">
                    <span>Câu {currentQuestionIndex}/{totalQuestions}</span>
                </div>
                <div className="timer-display">
                    <span className={timeRemaining <= 5 ? 'timer-critical' : ''}>
                        ⏱️ {timeRemaining}s
                    </span>
                </div>
                <button className="btn-leave" onClick={onLeave}>
                    Rời phòng
                </button>
            </div>

            {/* Question Display */}
            <div className="question-section">
                <h2 className="question-text">{currentQuestion.questionText}</h2>

                {currentQuestion.imageUrl && (
                    <img
                        src={currentQuestion.imageUrl}
                        alt="Question"
                        className="question-image"
                    />
                )}
            </div>

            {/* Answer Options */}
            {!showResults ? (
                <div className="answers-grid">
                    {currentQuestion.answers?.map((answer, index) => (
                        <button
                            key={answer.id}
                            className={`answer-option ${selectedAnswer === answer.id ? 'selected' : ''
                            } ${hasAnswered ? 'disabled' : ''}`}
                            onClick={() => handleAnswerClick(answer.id)}
                            disabled={hasAnswered}
                            style={{
                                animationDelay: `${index * 0.1}s`,
                                backgroundColor: getAnswerColor(index)
                            }}
                        >
                            <span className="answer-icon">{getAnswerIcon(index)}</span>
                            <span className="answer-text">{answer.answerText}</span>
                        </button>
                    ))}
                </div>
            ) : (
                <div className="answer-result-section">
                    <div className={`result-card ${answerResult?.isCorrect ? 'correct' : 'incorrect'}`}>
                        <div className="result-icon">
                            {answerResult?.isCorrect ? '✅' : '❌'}
                        </div>
                        <h3>
                            {answerResult?.isCorrect ? 'Chính xác!' : 'Sai rồi!'}
                        </h3>
                        <p className="points-earned">
                            +{answerResult?.score || 0} điểm
                        </p>

                        {/* Show correct answer if wrong */}
                        {!answerResult?.isCorrect && (
                            <div className="correct-answer-display">
                                <p>Đáp án đúng:</p>
                                <p className="correct-answer-text">
                                    {currentQuestion.answers?.find(a => a.isCorrect)?.answerText}
                                </p>
                            </div>
                        )}
                    </div>

                    {/* Players who answered */}
                    <div className="players-answered">
                        <h4>Đã trả lời: {players.filter(p => p.hasAnswered).length}/{players.length}</h4>
                    </div>

                    {/* Next button for host */}
                    {isHost && (
                        <button
                            className="btn-next-question"
                            onClick={handleNextQuestion}
                        >
                            Câu tiếp theo →
                        </button>
                    )}
                </div>
            )}

            {/* Mini Leaderboard */}
            <div className="mini-leaderboard">
                <h4>🏆 Top 3</h4>
                <div className="top-players">
                    {players.slice(0, 3).map((player, index) => (
                        <div key={player.userId} className="top-player">
                            <span className="rank">#{index + 1}</span>
                            <span className="name">{player.username}</span>
                            <span className="score">{player.totalScore || 0}</span>
                        </div>
                    ))}
                </div>
            </div>
        </div>
    );
};

/**
 * Get color for answer option
 */
const getAnswerColor = (index) => {
    const colors = ['#e74c3c', '#3498db', '#f39c12', '#2ecc71'];
    return colors[index % colors.length];
};

/**
 * Get icon for answer option
 */
const getAnswerIcon = (index) => {
    const icons = ['△', '◇', '○', '□'];
    return icons[index % icons.length];
};

export default GamePlay;

import React from 'react';
import { useNavigate } from 'react-router-dom';
import { MdCelebration } from 'react-icons/md';
import useGameStore from '../../stores/use-game-store';
import '../../styles/components/room/game-results.css';

/**
 * GameResults Component - Final leaderboard and statistics
 * Similar to Kahoot/Quizizz results screen
 */
const GameResults = ({ onExit, gameResults }) => {
    const navigate = useNavigate();

    const {
        leaderboard: storeLeaderboard,
        totalQuestions,
        players
    } = useGameStore();

    const leaderboard = gameResults?.ranking || storeLeaderboard;
    const totalQs = gameResults?.totalQuestions || totalQuestions;

    /**
     * Handle play again
     */
    const handlePlayAgain = () => {
        // Navigate back to dashboard to create/join new game
        navigate('/dashboard');
    };

    /**
     * Get medal emoji for ranking
     */
    const getMedal = (rank) => {
        switch (rank) {
            case 1: return '🥇';
            case 2: return '🥈';
            case 3: return '🥉';
            default: return '🏅';
        }
    };

    /**
     * Get podium position class
     */
    const getPodiumClass = (rank) => {
        switch (rank) {
            case 1: return 'podium-first';
            case 2: return 'podium-second';
            case 3: return 'podium-third';
            default: return '';
        }
    };

    /**
     * Calculate player accuracy percentage
     */
    const calculateAccuracy = (player) => {
        if (!player.correctAnswers && !player.totalAnswers) return 0;
        const correct = player.correctAnswers || 0;
        const total = player.totalAnswers || totalQs || 0;
        if (total === 0) return 0;
        return Math.round((correct / total) * 100);
    };

    return (
        <div className="game-results-container">
            {/* Confetti animation */}
            <div className="confetti-container">
                {[...Array(50)].map((_, i) => (
                    <div key={i} className="confetti" style={{
                        left: `${Math.random() * 100}%`,
                        animationDelay: `${Math.random() * 3}s`,
                        backgroundColor: ['#e74c3c', '#3498db', '#f39c12', '#2ecc71'][Math.floor(Math.random() * 4)]
                    }} />
                ))}
            </div>

            {/* Header */}
            <div className="results-header">
                <h1><MdCelebration size={40} color="#FFD700" style={{verticalAlign: 'middle'}} /> Trò chơi kết thúc!</h1>
                <p className="game-stats">
                    Tổng số câu: {totalQs} | Người chơi: {leaderboard.length}
                </p>
            </div>

            {/* Podium - Top 3 */}
            <div className="podium-section">
                <h2>🏆 Podium</h2>
                <div className="podium">
                    {leaderboard.slice(0, 3).map((player, index) => {
                        const podiumOrder = index === 0 ? 0 : index === 1 ? 2 : 1; // Center winner
                        const rank = player.rank || (index + 1);
                        return (
                            <div
                                key={player.userId}
                                className={`podium-place ${getPodiumClass(rank)}`}
                                style={{ order: podiumOrder }}
                            >
                                <div className="player-avatar">
                                    <img
                                        src={player.avatar || '/default-avatar.png'}
                                        alt={player.userName || 'Player'}
                                        onError={(e) => {
                                            e.target.src = '/default-avatar.png';
                                        }}
                                    />
                                </div>
                                <div className="medal">{getMedal(rank)}</div>
                                <h3>{player.userName || `User${player.userId}`}</h3>
                                <p className="score">{player.totalScore || 0} điểm</p>
                                <div className={`podium-base rank-${rank}`}>
                                    <span className="rank-number">#{rank}</span>
                                </div>
                            </div>
                        );
                    })}
                </div>
            </div>

            {/* Full Leaderboard */}
            <div className="leaderboard-section">
                <h2>📊 Bảng xếp hạng</h2>
                <div className="leaderboard-table">
                    <div className="leaderboard-header">
                        <span>Hạng</span>
                        <span>Tên</span>
                        <span>Điểm</span>
                        <span>Độ chính xác</span>
                    </div>
                    <div className="leaderboard-body">
                        {leaderboard.map((player, index) => {
                            const rank = player.rank || (index + 1);
                            return (
                                <div
                                    key={player.userId}
                                    className={`leaderboard-row ${rank <= 3 ? 'top-three' : ''}`}
                                >
                                    <span className="rank">
                                        {rank <= 3 ? getMedal(rank) : `#${rank}`}
                                    </span>
                                    <span className="player-name">
                                        <img
                                            src={player.avatar || '/default-avatar.png'}
                                            alt={player.userName || 'Player'}
                                            className="mini-avatar"
                                            onError={(e) => {
                                                e.target.src = '/default-avatar.png';
                                            }}
                                        />
                                        {player.userName || `User${player.userId}`}
                                    </span>
                                    <span className="score">{player.totalScore || 0}</span>
                                    <span className="accuracy">
                                        {calculateAccuracy(player)}%
                                    </span>
                                </div>
                            );
                        })}
                    </div>
                </div>
            </div>

            {/* Action buttons */}
            <div className="results-actions">
                <button className="btn-primary" onClick={handlePlayAgain}>
                    Chơi lại
                </button>
                <button className="btn-secondary" onClick={onExit}>
                    Về trang chủ
                </button>
            </div>
        </div>
    );
};

