import React, { useState, useEffect, useRef } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { FaCrown } from 'react-icons/fa6';
import { FaMedal } from 'react-icons/fa';
import socketService from '../../services/socket-service';
import authStore from '../../stores/auth-store';
import useRoomStore from '../../stores/use-room-store-realtime';
import AnswerResultPopup from './AnswerResultPopup';
import NotificationPopup from './NotificationPopup';
import GameStartPopup from './GameStartPopup';
import CompletionPopup from './CompletionPopup';
import '../../styles/components/room/game-room.css';

const GameRoom = () => {
    const { roomCode } = useParams();
    const navigate = useNavigate();
    const currentUser = authStore((state) => state.user);
    const { currentRoom } = useRoomStore();

    const [gameState, setGameState] = useState(null);
    const [currentQuestion, setCurrentQuestion] = useState(null);
    const [selectedAnswer, setSelectedAnswer] = useState(null);
    const [timeRemaining, setTimeRemaining] = useState(0);
    const [hasAnswered, setHasAnswered] = useState(false);
    const [isConnected, setIsConnected] = useState(true); 
    const [gameResults, setGameResults] = useState(null);
    const [isLoading, setIsLoading] = useState(true);
    const [answerResult, setAnswerResult] = useState(null);

    // ✅ NEW: States cho các popup thay thế toast
    const [notification, setNotification] = useState(null);
    const [showGameStart, setShowGameStart] = useState(false);
    const [showCompletion, setShowCompletion] = useState(false);

    const timerRef = useRef(null);
    const questionStartTimeRef = useRef(null);

    // Khởi tạo với dữ liệu sự kiện game-started từ WaitingRoom
    useEffect(() => {
        if (!currentUser || !roomCode) {
            navigate('/');
            return;
        }

        // Socket nên đã kết nối từ WaitingRoom
        if (socketService.isConnected()) {
            setIsConnected(true);
            setupGameSubscriptions();

            // Sửa: Yêu cầu trạng thái game hiện tại để lấy câu hỏi đang diễn ra nếu game đã bắt đầu
            if (currentRoom?.id) {
                socketService.emit('get-game-state', { roomId: currentRoom.id }, (response) => {
                    if (response && response.currentQuestion) {
                        setCurrentQuestion(response.currentQuestion);
                        setSelectedAnswer(null);
                        setHasAnswered(false);
                        setTimeRemaining(response.currentQuestion.timeLimit || 30);
                        questionStartTimeRef.current = Date.now();
                        startQuestionTimer(response.currentQuestion.timeLimit || 30);
                    }
                    if (response && response.players) {
                        setGameState(response);
                    }
                });
            }
        } else {
            initializeWebSocket();
        }

        return () => {
            if (timerRef.current) {
                clearInterval(timerRef.current);
            }
            // KHÔNG ngắt kết nối khỏi phòng - để người dùng ở lại phòng
        };
    }, [roomCode, currentUser]);

    const initializeWebSocket = async () => {
        try {
            const token = localStorage.getItem('accessToken') || sessionStorage.getItem('accessToken');
            if (!token) {
                throw new Error('No authentication token found');
            }

            await socketService.connect(token);
            setIsConnected(true);
            setupGameSubscriptions();

        } catch (error) {
            setNotification({ type: 'error', message: 'Không thể kết nối đến game. Vui lòng thử lại!' });
            // Không chuyển hướng ngay lập tức, cho người dùng có cơ hội thử lại
            setIsLoading(false);
        }
    };

    const setupGameSubscriptions = () => {

        // Sửa: Xóa các listener tồn tại trước khi thêm mới để tránh trùng lặp
        socketService.off('game-started');
        socketService.off('next-question');
        socketService.off('answer-submitted');
        socketService.off('player-answered');
        socketService.off('game-ended');
        socketService.off('game-finished');

        // Lắng nghe sự kiện game-started (chứa câu hỏi đầu tiên)
        socketService.on('game-started', (data) => {
            handleGameMessage({ type: 'GAME_STARTED', data });
        });

        // Lắng nghe sự kiện next-question
        socketService.on('next-question', (data) => {
            handleGameMessage({ type: 'NEXT_QUESTION', data });
        });

        // Lắng nghe sự kiện answer-submitted (kết quả cá nhân) - MỘT LẦN mỗi câu trả lời
        const answerSubmittedHandler = (data) => {
            handlePersonalMessage({ type: 'ANSWER_RESULT', data });
        };
        socketService.on('answer-submitted', answerSubmittedHandler);

        // Lắng nghe sự kiện player-answered (người chơi khác)
        socketService.on('player-answered', (data) => {
            // Chỉ cập nhật trạng thái của người chơi khác, không cập nhật điểm
            setGameState(prev => {
                if (!prev || !prev.players) return prev;
                return {
                    ...prev,
                    players: prev.players.map(p =>
                        p.userId === data.userId
                            ? { ...p, hasAnswered: true }
                            : p
                    )
                };
            });
        });

        // Lắng nghe sự kiện game-ended/game-finished
        socketService.on('game-ended', (data) => {
            handleGameMessage({ type: 'GAME_ENDED', data });
        });

        socketService.on('game-finished', (data) => {
            handleGameMessage({ type: 'GAME_ENDED', data });
        });

        setIsLoading(false);
    };

    const handleGameMessage = (message) => {

        switch (message.type) {
            case 'GAME_STARTED':
                // Trích xuất câu hỏi đầu tiên từ sự kiện game-started
                if (message.data.question) {
                    // Sửa: Khởi tạo gameState với players từ currentRoom
                    if (currentRoom?.players) {
                        setGameState({
                            players: currentRoom.players.map(p => ({
                                ...p,
                                score: 0, 
                                hasAnswered: false
                            }))
                        });
                    }

                    setCurrentQuestion(message.data.question);
                    setSelectedAnswer(null);
                    setHasAnswered(false);
                    setTimeRemaining(message.data.question.timeLimit || 30);
                    questionStartTimeRef.current = Date.now();
                    startQuestionTimer(message.data.question.timeLimit || 30);
                    setShowGameStart(true); // Hiển thị popup bắt đầu game
                }
                break;

            case 'NEXT_QUESTION':

                // Cần lấy từ message.data.question, KHÔNG phải message.data trực tiếp
                const nextQuestionData = message.data.question || message.data;

                setCurrentQuestion(nextQuestionData);
                setSelectedAnswer(null);
                setHasAnswered(false);
                setTimeRemaining(nextQuestionData.timeLimit || 30);
                questionStartTimeRef.current = Date.now();
                startQuestionTimer(nextQuestionData.timeLimit || 30);
                setNotification({ type: 'info', message: `Câu hỏi ${nextQuestionData.questionNumber}/${nextQuestionData.totalQuestions}` });
                break;

            case 'GAME_ENDED':
                setGameResults(message.data);
                setCurrentQuestion(null);
                if (timerRef.current) {
                    clearInterval(timerRef.current);
                }
                setShowCompletion(true); // Hiển thị popup hoàn thành
                break;

            default:
                break;
        }
    };

    const handlePersonalMessage = (message) => {
        if (message.type === 'ANSWER_RESULT') {
            const result = message.data.result || message.data;

            // Cập nhật điểm cục bộ ngay lập tức
            const earnedScore = result.score || result.pointsEarned || 0;

            // Cập nhật gameState với điểm mới
            setGameState(prev => {
                if (!prev || !prev.players) return prev;
                return {
                    ...prev,
                    players: prev.players.map(p =>
                        p.userId === currentUser.id
                            ? { ...p, score: (p.score || 0) + earnedScore, hasAnswered: true }
                            : p
                    )
                };
            });

            setAnswerResult({
                isCorrect: result.isCorrect,
                score: earnedScore,
                streak: result.streak || 0,
                streakMultiplier: result.streakMultiplier || 1.0
            });

            // Kiểm tra xem có câu hỏi tiếp theo không
            if (message.data.hasNextQuestion && message.data.nextQuestion) {
                // Có câu tiếp theo - tự động chuyển sau khi popup hiển thị

                const nextQ = message.data.nextQuestion;

                // Delay 2.5 giây để người chơi xem kết quả trước khi chuyển câu
                setTimeout(() => {
                    setAnswerResult(null); // Đóng popup
                    setCurrentQuestion(nextQ);
                    setSelectedAnswer(null);
                    setHasAnswered(false);
                    setTimeRemaining(nextQ.timeLimit || 30);
                    questionStartTimeRef.current = Date.now();
                    startQuestionTimer(nextQ.timeLimit || 30);
                }, 2500);

            } else if (message.data.completed) {
                // Player này đã hoàn thành tất cả câu hỏi
                setTimeout(() => {
                    setAnswerResult(null);
                    setCurrentQuestion(null);
                    setHasAnswered(false);

                    if (timerRef.current) {
                        clearInterval(timerRef.current);
                    }

                    setShowCompletion(true); // Hiển thị popup hoàn thành
                }, 2500);
            }
        }
    };

    const startQuestionTimer = (seconds) => {
        if (timerRef.current) {
            clearInterval(timerRef.current);
        }

        timerRef.current = setInterval(() => {
            setTimeRemaining(prev => {
                if (prev <= 1) {
                    clearInterval(timerRef.current);
                    if (!hasAnswered) {
                        // Tự động gửi câu trả lời trống khi hết thời gian
                        submitAnswer();
                    }
                    return 0;
                }
                return prev - 1;
            });
        }, 1000);
    };

    const submitAnswer = () => {
        if (hasAnswered || !currentQuestion) return;

        const roomId = currentRoom?.id;
        const questionId = currentQuestion.questionId || currentQuestion.id;
        const questionOptions = currentQuestion.answers || currentQuestion.options || [];
        const selectedAnswerObj = questionOptions.find(opt =>
            (opt.text || opt.answerText || opt) === selectedAnswer
        );
        const selectedOptionIndex = questionOptions.findIndex(opt =>
            (opt.text || opt.answerText || opt) === selectedAnswer
        );
        const answerId = selectedAnswerObj?.id;

        const timeTaken = questionStartTimeRef.current ? Date.now() - questionStartTimeRef.current : 0;

        // Gửi đến backend với tất cả các trường bắt buộc
        socketService.emit('submit-answer', {
            roomId: roomId,
            questionId: questionId,
            answerId: answerId,
            selectedAnswer: selectedAnswer,
            selectedOptionIndex: selectedOptionIndex,
            answerText: selectedAnswer,
            timeTaken: timeTaken
        });

        setHasAnswered(true);

        if (timerRef.current) {
            clearInterval(timerRef.current);
        }
    };

    const startGame = () => {
        socketService.emit('startGame', { roomCode });
    };

    const formatTime = (seconds) => {
        const mins = Math.floor(seconds / 60);
        const secs = seconds % 60;
        return `${mins}:${secs.toString().padStart(2, '0')}`;
    };

    const getPlayerRankColor = (rank) => {
        switch (rank) {
            case 1: return '#FFD700'; // Gold
            case 2: return '#C0C0C0'; // Silver
            case 3: return '#CD7F32'; // Bronze
            default: return '#666';
        }
    };

    if (!isConnected) {
        return (
            <div className="game-room loading">
                <div className="loading-spinner">
                    <div className="spinner"></div>
                    <p>Đang kết nối đến game...</p>
                </div>
            </div>
        );
    }

    // Show results screen
    if (gameResults) {
        const rankings = gameResults.result?.ranking || gameResults.ranking || [];

        return (
            <div className="game-room results">
                <div className="results-container">
                    <h2 className="results-title">Kết Quả Game</h2>

                    <div className="final-leaderboard">
                        {rankings.length > 0 ? (
                            rankings.map((player, index) => (
                                <div key={player.userId} className={`result-item rank-${index + 1}`}>
                                    <div className="rank-badge" style={{ backgroundColor: getPlayerRankColor(index + 1) }}>
                                        <span className="rank-number">#{index + 1}</span>
                                        {index === 0 && <FaCrown className="rank-icon" />}
                                    </div>
                                    <div className="player-info">
                                        <div className="player-details">
                                            <h3 className="player-name">
                                                {player.userName || `User ${player.userId}`}
                                                {player.userId === currentUser?.id && <span className="you-badge"> (Bạn)</span>}
                                            </h3>
                                            <div className="player-stats">
                                                <span className="stat-item">
                                                    <strong>{player.totalScore || 0}</strong> điểm
                                                </span>
                                                <span className="stat-separator">•</span>
                                                <span className="stat-item">
                                                    <strong>{(player.totalTime / 1000).toFixed(1)}s</strong>
                                                </span>
                                            </div>
                                        </div>
                                    </div>
                                    {index < 3 && (
                                        <div className="medal-icon">
                                            {index === 0 && <FaMedal style={{ color: 'gold', fontSize: '24px' }} />}
                                            {index === 1 && <FaMedal style={{ color: 'silver', fontSize: '24px' }} />}
                                            {index === 2 && <FaMedal style={{ color: '#cd7f32', fontSize: '24px' }} />}
                                        </div>
                                    )}
                                </div>
                            ))
                        ) : (
                            <div className="no-results">
                                <p>Không có kết quả</p>
                            </div>
                        )}
                    </div>

                    <div className="results-actions">
                        <button onClick={() => navigate('/dashboard')} className="btn-primary">
                            Về Dashboard
                        </button>
                        <button onClick={() => navigate('/rooms')} className="btn-primary">
                            Tìm phòng khác
                        </button>
                    </div>
                </div>
            </div>
        );
    }

    // Show question screen
    if (currentQuestion) {
        // FIX: Backend returns 'answers' with field 'text', not 'answerText'
        const questionOptions = currentQuestion.answers || currentQuestion.options || [];

        return (
            <div className="game-room playing">
                <div className="game-header">
                    <div className="question-progress">
                        Câu {currentQuestion.questionNumber || 1}/{currentQuestion.totalQuestions || '?'}
                    </div>
                    <div className={`timer ${timeRemaining <= 10 ? 'urgent' : ''}`}>
                        ⏱️ {formatTime(timeRemaining)}
                    </div>
                    <div className="score">
                        {gameState?.players?.find(p => p.userId === currentUser.id)?.score || 0} điểm
                    </div>
                </div>

                <div className="question-container">
                    {currentQuestion.imageUrl && (
                        <div className="question-image">
                            <img src={currentQuestion.imageUrl} alt="Question" />
                        </div>
                    )}

                    <h2 className="question-text">{currentQuestion.questionText}</h2>

                    <div className="options-container">
                        {questionOptions.length > 0 ? (
                            questionOptions.map((option, index) => {
                                // FIX: Backend returns {id, text} not {id, answerText}
                                const optionText = option.text || option.answerText || option;
                                const optionId = option.id || index;

                                return (
                                    <button
                                        key={optionId}
                                        className={`option-btn ${selectedAnswer === optionText ? 'selected' : ''} ${hasAnswered ? 'disabled' : ''}`}
                                        onClick={() => !hasAnswered && setSelectedAnswer(optionText)}
                                        disabled={hasAnswered}
                                    >
                                        <span className="option-letter">{String.fromCharCode(65 + index)}</span>
                                        <span className="option-text">{optionText}</span>
                                    </button>
                                );
                            })
                        ) : (
                            <div className="no-options">
                                <p>⚠️ Không có đáp án nào được tải</p>
                                <p>Debug info: {JSON.stringify(currentQuestion, null, 2)}</p>
                            </div>
                        )}
                    </div>

                    <div className="question-actions">
                        <button
                            className={`submit-btn ${!selectedAnswer || hasAnswered ? 'disabled' : ''}`}
                            onClick={submitAnswer}
                            disabled={!selectedAnswer || hasAnswered}
                        >
                            {hasAnswered ? 'Đã trả lời' : 'Gửi đáp án'}
                        </button>
                    </div>
                </div>

                {/* Real-time player status */}
                {gameState?.players && (
                    <div className="players-status">
                        <h3>Trạng thái người chơi:</h3>
                        <div className="players-grid">
                            {gameState.players.map(player => (
                                <div key={player.userId} className={`player-status ${player.hasAnswered ? 'answered' : 'waiting'}`}>
                                    <img
                                        src={player.avatarUrl || '/default-avatar.png'}
                                        alt={player.displayName}
                                        className="mini-avatar"
                                    />
                                    <span className="player-name">{player.displayName}</span>
                                    <span className="status-indicator">
                                        {player.hasAnswered ? '✅' : '⏳'}
                                    </span>
                                </div>
                            ))}
                        </div>
                    </div>
                )}

                {/* Popup kết quả câu trả lời */}
                {answerResult && (
                    <AnswerResultPopup
                        result={answerResult}
                        onClose={() => setAnswerResult(null)}
                    />
                )}

                {/* Popup thông báo bắt đầu game */}
                {showGameStart && (
                    <GameStartPopup
                        onClose={() => setShowGameStart(false)}
                    />
                )}

                {/* Popup hoàn thành game */}
                {showCompletion && (
                    <CompletionPopup
                        onClose={() => setShowCompletion(false)}
                    />
                )}
            </div>
        );
    }

    // Show waiting/lobby screen
    return (
        <div className="game-room waiting">
            <div className="waiting-container">
                <h2>🎮 Phòng Game: {roomCode}</h2>

                {gameState && (
                    <div className="game-info">
                        <p>Trạng thái: <span className="status">{gameState.gameStatus}</span></p>
                        <p>Tổng câu hỏi: {gameState.totalQuestions}</p>

                        <div className="players-list">
                            <h3>Người chơi ({gameState.players?.length || 0}):</h3>
                            {gameState.players?.map(player => (
                                <div key={player.userId} className="player-item">
                                    <img
                                        src={player.avatarUrl || '/default-avatar.png'}
                                        alt={player.displayName}
                                        className="player-avatar"
                                    />
                                    <span className="player-name">
                                        {player.displayName}
                                        {player.userId === currentUser.id && ' (Bạn)'}
                                    </span>
                                    <span className={`player-status ${player.status.toLowerCase()}`}>
                                        {player.status}
                                    </span>
                                </div>
                            ))}
                        </div>
                    </div>
                )}

                <div className="waiting-actions">
                    {gameState?.isHost && (
                        <button onClick={startGame} className="btn-primary start-btn">
                            Bắt đầu Game
                        </button>
                    )}

                    <button onClick={() => navigate('/rooms')} className="btn-secondary">
                        Rời phòng
                    </button>
                </div>

                {/* Popup thông báo chung */}
                {notification && (
                    <NotificationPopup
                        type={notification.type}
                        message={notification.message}
                        onClose={() => setNotification(null)}
                        autoClose={notification.autoClose !== false}
                    />
                )}
            </div>
        </div>
    );
};

export default GameRoom;

import React, { useState } from 'react';
import { FiAlertCircle, FiHash, FiInfo, FiX, FiKey, FiArrowRight } from 'react-icons/fi';
import { toast } from 'react-toastify';
import { useTheme } from '../../contexts/theme-context';
import useRoomStore from '../../stores/use-room-store';
import '../../styles/components/room/join-by-code-modal.css';

const JoinByCodeModal = ({ isOpen, onClose, onJoin, onSuccess }) => {
  const [roomCode, setRoomCode] = useState('');
  const { theme } = useTheme();
  const { joinRoomByCode, isLoading, error: storeError } = useRoomStore();

  const validateRoomCode = (code) => {
    return /^[A-Z0-9]{8}$/.test(code);
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!roomCode.trim()) {
      toast.error('Vui lòng nhập mã phòng');
      return;
    }
    if (!validateRoomCode(roomCode)) {
      toast.error('Mã phòng phải gồm 8 ký tự chữ cái hoặc số');
      return;
    }

    try {
      const result = await joinRoomByCode(roomCode);
      if (result.success) {
        toast.success('Tham gia phòng thành công!');
        onJoin?.(roomCode);
        onSuccess?.(result);
        handleClose();
      } else {
        toast.error(result.error || 'Không thể tham gia phòng');
      }
    } catch (err) {
      toast.error(err.message || 'Có lỗi xảy ra khi tham gia phòng');
    }
  };

  const handleInputChange = (e) => {
    const value = e.target.value.toUpperCase().replace(/[^A-Z0-9]/g, '');
    setRoomCode(value.substring(0, 8));
  };

  const handleKeyDown = (e) => {
    if (roomCode.length >= 8 && e.key !== 'Backspace' && e.key !== 'Delete' && !e.ctrlKey && !e.metaKey) {
      e.preventDefault();
    }
  };

  const handlePaste = (e) => {
    if (roomCode.length >= 8) {
      e.preventDefault();
      return;
    }
    const paste = e.clipboardData.getData('text');
    const cleanedPaste = paste.toUpperCase().replace(/[^A-Z0-9]/g, '');
    setRoomCode((roomCode + cleanedPaste).substring(0, 8));
    e.preventDefault();
  };

  const handleClose = () => {
    setRoomCode('');
    onClose();
  };

  const handleOverlayClick = (e) => {
    if (e.target.classList.contains('jbc-overlay')) {
      handleClose();
    }
  };

  if (!isOpen) return null;

  return (
      <div className={`jbc-overlay ${theme}`} onClick={handleOverlayClick}>
        <div className="jbc-container">
          <div className="jbc-header">
            <div className="jbc-header-content">
              <div className="jbc-header-icon">
                <FiKey />
              </div>
              <div className="jbc-header-text">
                <h2 className="jbc-title">Tham gia phòng</h2>
                <p className="jbc-subtitle">Nhập mã phòng để bắt đầu</p>
              </div>
            </div>
            <button className="jbc-close" onClick={handleClose}>
              <FiX />
            </button>
          </div>

          <form onSubmit={handleSubmit} className="jbc-form">
            <div className="jbc-form-group">
              <label htmlFor="roomCode">
                <FiHash style={{ marginRight: '8px' }} />
                Mã phòng (8 ký tự)
              </label>
              <div className={`jbc-code-input-container has-${roomCode.length}-char`}>
                <input
                    id="roomCode"
                    type="text"
                    value={roomCode}
                    onChange={handleInputChange}
                    onKeyDown={handleKeyDown}
                    onPaste={handlePaste}
                    placeholder="ABC12345"
                    maxLength={8}
                    autoFocus
                    disabled={isLoading}
                    className="jbc-input"
                />
                <div className="jbc-code-icon">
                  <FiHash />
                </div>
              </div>
              <div className="jbc-input-hint">
                {roomCode.length === 8
                    ? validateRoomCode(roomCode)
                        ? 'Mã phòng hợp lệ! Nhấn tham gia để tiếp tục'
                        : 'Mã phòng không hợp lệ'
                    : roomCode.length > 0
                        ? `Đã nhập ${roomCode.length}/8 ký tự`
                        : 'Chỉ nhập chữ cái và số, không có khoảng trắng'}
              </div>
            </div>

            {storeError && (
                <div className="jbc-error">
                  <FiAlertCircle />
                  <span>{storeError}</span>
                  <button onClick={() => setRoomCode('')} className="jbc-error-clear">
                    Thử lại
                  </button>
                </div>
            )}

            <div className="jbc-actions">
              <button
                  type="button"
                  className="jbc-button jbc-secondary-btn"
                  onClick={handleClose}
                  disabled={isLoading}
              >
                Hủy
              </button>
              <button
                  type="submit"
                  className="jbc-button jbc-primary-btn"
                  disabled={!validateRoomCode(roomCode) || isLoading}
              >
                {isLoading ? (
                    <>
                      <div className="jbc-loading-spinner"></div>
                      Đang tham gia...
                    </>
                ) : (
                    <>
                      Tham gia
                      <FiArrowRight style={{ marginLeft: '4px' }} />
                    </>
                )}
              </button>
            </div>

            <div className="jbc-info">
              <FiInfo style={{ marginRight: '8px' }} />
              Mã phòng được chia sẻ bởi người tạo phòng
            </div>
          </form>
        </div>
      </div>
  );
};

export default JoinByCodeModal;

import React from 'react';
import { MdCheckCircle, MdError, MdWarning, MdInfo, MdClose } from 'react-icons/md';
import '../../styles/components/room/notification-popup.css';

/**
 * NotificationPopup - Popup thông báo thay thế cho toast
 * Hỗ trợ các loại: success, error, info, warning
 */
const NotificationPopup = ({ type = 'info', message, onClose, autoClose = true }) => {
    React.useEffect(() => {
        if (autoClose) {
            const timer = setTimeout(() => {
                onClose?.();
            }, 3000);
            return () => clearTimeout(timer);
        }
    }, [autoClose, onClose]);

    const getTypeConfig = () => {
        switch (type) {
            case 'success':
                return {
                    icon: <MdCheckCircle size={28} color="#fff" />,
                    bgColor: '#4CAF50',
                    title: 'Thành công!'
                };
            case 'error':
                return {
                    icon: <MdError size={28} color="#fff" />,
                    bgColor: '#f44336',
                    title: 'Lỗi!'
                };
            case 'warning':
                return {
                    icon: <MdWarning size={28} color="#fff" />,
                    bgColor: '#FF9800',
                    title: 'Cảnh báo!'
                };
            case 'info':
            default:
                return {
                    icon: <MdInfo size={28} color="#fff" />,
                    bgColor: '#2196F3',
                    title: 'Thông báo'
                };
        }
    };

    const config = getTypeConfig();

    return (
        <div className="notification-popup-overlay">
            <div
                className={`notification-popup ${type}`}
                style={{ backgroundColor: config.bgColor }}
            >
                <div className="notification-icon">{config.icon}</div>
                <div className="notification-content">
                    <h3 className="notification-title">{config.title}</h3>
                    <p className="notification-message">{message}</p>
                </div>
                {onClose && (
                    <button className="notification-close" onClick={onClose}>
                        <MdClose size={20} color="#fff" />
                    </button>
                )}
            </div>
        </div>
    );
};

export default NotificationPopup;

import React, { useEffect, useState } from 'react';
import { FiUser } from 'react-icons/fi';
import { FaCrown } from 'react-icons/fa';
import useRoomStore from '../../stores/use-room-store';
import '../../styles/components/room/player-list.css';

const PlayerList = ({ roomId, isHost }) => {
    const { roomPlayers, currentRoom } = useRoomStore();
    const [animatingPlayers, setAnimatingPlayers] = useState(new Set());
    const [playerStates, setPlayerStates] = useState(new Map());

    // Track player changes for animations
    useEffect(() => {
        const currentPlayerIds = new Set(roomPlayers.map(p => p.id));
        const previousPlayerIds = new Set(Array.from(playerStates.keys()));

        // Find newly joined players
        const newPlayers = roomPlayers.filter(p => !previousPlayerIds.has(p.id));
        // Find players who left
        const leftPlayerIds = Array.from(previousPlayerIds).filter(id => !currentPlayerIds.has(id));

        // Animate new players
        newPlayers.forEach(player => {
            setAnimatingPlayers(prev => new Set(prev).add(`join-${player.id}`));
            setTimeout(() => {
                setAnimatingPlayers(prev => {
                    const newSet = new Set(prev);
                    newSet.delete(`join-${player.id}`);
                    return newSet;
                });
            }, 600);
        });

        // Animate leaving players (remove from DOM after animation)
        leftPlayerIds.forEach(playerId => {
            setAnimatingPlayers(prev => new Set(prev).add(`leave-${playerId}`));
            setTimeout(() => {
                setPlayerStates(prev => {
                    const newMap = new Map(prev);
                    newMap.delete(playerId);
                    return newMap;
                });
                setAnimatingPlayers(prev => {
                    const newSet = new Set(prev);
                    newSet.delete(`leave-${playerId}`);
                    return newSet;
                });
            }, 400);
        });

        // Update player states
        const newStates = new Map();
        roomPlayers.forEach(player => {
            newStates.set(player.id, player);
        });
        setPlayerStates(newStates);

    }, [roomPlayers]);

    const isPlayerHost = (playerId) => {
        return currentRoom?.hostId === playerId || currentRoom?.ownerId === playerId;
    };

    const getPlayerDisplayName = (player) => {
        return player.username || player.name || `Player ${player.id}`;
    };

    const allPlayers = Array.from(playerStates.values()).concat(
        // Include leaving players for animation
        Array.from(animatingPlayers)
            .filter(key => key.startsWith('leave-'))
            .map(key => ({ id: key.replace('leave-', ''), username: 'Rời phòng...', isLeaving: true }))
    );

    return (
        <div className="player-list">
            <div className="player-list-header">
                <h3>
                    <FiUser />
                    Người chơi ({roomPlayers.length}/{currentRoom?.maxPlayers || 10})
                </h3>
            </div>

            <div className="player-list-content">
                {allPlayers.map(player => {
                    const isJoining = animatingPlayers.has(`join-${player.id}`);
                    const isLeaving = animatingPlayers.has(`leave-${player.id}`) || player.isLeaving;
                    const isHost = isPlayerHost(player.id);

                    return (
                        <div
                            key={player.id}
                            className={`player-item ${isJoining ? 'joining' : ''} ${isLeaving ? 'leaving' : ''} ${isHost ? 'host' : ''}`}
                        >
                            <div className="player-avatar">
                                {isHost && <FaCrown className="host-crown" />}
                                <FiUser />
                            </div>

                            <div className="player-info">
                                <span className="player-name">
                                    {getPlayerDisplayName(player)}
                                    {isHost && <span className="host-badge">Host</span>}
                                </span>
                                <span className="player-status">
                                    {isLeaving ? 'Đang rời...' : 'Sẵn sàng'}
                                </span>
                            </div>

                            {isJoining && (
                                <div className="join-indicator">
                                    <span>Vào phòng</span>
                                </div>
                            )}
                        </div>
                    );
                })}

                {roomPlayers.length === 0 && (
                    <div className="empty-player-list">
                        <FiUser size={48} />
                        <p>Chưa có người chơi nào</p>
                        <span>Chia sẻ mã phòng để mời bạn bè!</span>
                    </div>
                )}
            </div>
        </div>
    );
};

export default PlayerList;

import React, { useState } from 'react';
import { IoPeople, IoPlay } from 'react-icons/io5';
import { FiHash, FiLock, FiUnlock } from 'react-icons/fi';
import useRoomStore from '../../stores/use-room-store';
import '../../styles/components/room/room-card.css';

const RoomCard = ({ room, onJoinPublic }) => {
  const { animatingRooms, newRoomIds } = useRoomStore();
  const [isJoining, setIsJoining] = useState(false);

  const isAnimating = animatingRooms.has(room.id);
  const isNew = newRoomIds.has(room.id);

  const getStatusColor = (status) => {
    switch (status?.toLowerCase()) {
      case 'waiting': return '#10b981';
      case 'playing': return '#f59e0b';
      case 'finished': return '#6b7280';
      default: return '#6b7280';
    }
  };

  const getStatusText = (status) => {
    switch (status?.toLowerCase()) {
      case 'waiting': return 'Sẵn sàng';
      case 'playing': return 'Đang chơi';
      case 'finished': return 'Đã kết thúc';
      default: return 'Không xác định';
    }
  };

  const getGameModeText = (gameMode) => {
    return gameMode?.toLowerCase() === 'one_vs_one' ? '1 vs 1' : 'Battle Royale';
  };

  const handleJoin = async () => {
    setIsJoining(true);
    await onJoinPublic(room.roomCode);
    setIsJoining(false);
  };

  return (
      <div className={`room-card ${isAnimating ? 'animating' : ''} ${isNew ? 'new-room' : ''}`}>
        {isNew && <div className="new-room-badge">MỚI</div>}
        <div className="room-card-header">
          <div className="room-card-main-info">
            <h3 className="room-card-title">{room.roomName}</h3>
            <div className="room-card-meta">
              <div className="room-card-status">
                <div
                    className="room-card-status-dot"
                    style={{ backgroundColor: getStatusColor(room.status) }}
                ></div>
                <span>{getStatusText(room.status)}</span>
              </div>
              <div className="room-card-privacy">
                {room.isPrivate ? <FiLock /> : <FiUnlock />}
                <span>{room.isPrivate ? 'Riêng tư' : 'Công khai'}</span>
              </div>
            </div>
          </div>

          {!room.isPrivate && room.roomCode && (
              <div className="room-card-code">
                <FiHash />
                <span>{room.roomCode}</span>
              </div>
          )}
        </div>

        <div className="room-card-content">
          <div className="room-card-details">
            <div className="room-card-detail-item">
              <span className="room-card-detail-label">Chủ đề:</span>
              <span className="room-card-detail-value">{room.topicName || 'Chưa xác định'}</span>
            </div>
            {room.examTitle && (
              <div className="room-card-detail-item">
                <span className="room-card-detail-label">Bộ đề:</span>
                <span className="room-card-detail-value">{room.examTitle}</span>
              </div>
            )}
            <div className="room-card-detail-item">
              <span className="room-card-detail-label">Chế độ:</span>
              <span className="room-card-detail-value">{getGameModeText(room.roomMode)}</span>
            </div>
            <div className="room-card-detail-item">
              <IoPeople />
              <span className="room-card-detail-label">Người chơi:</span>
              <span className="room-card-detail-value">
              {room.currentPlayers || 0}/{room.maxPlayers}
            </span>
            </div>
          </div>
        </div>

        <div className="room-card-footer">
          <button
              className="room-card-join-btn"
              onClick={handleJoin}
              disabled={room.status?.toLowerCase() !== 'waiting' || isJoining || room.isPrivate}
          >
            {isJoining ? (
                <span className="loading-spinner">Đang tham gia...</span>
            ) : room.isPrivate ? (
                <>
                  <FiLock />
                  <span>Phòng riêng tư</span>
                </>
            ) : (
                <>
                  <IoPlay />
                  <span>Tham gia</span>
                </>
            )}
          </button>
        </div>
      </div>
  );
};

export default RoomCard;

import React, { useEffect, useState, useRef } from 'react';
import { useParams, useNavigate, useLocation } from 'react-router-dom';
import {
    FiUsers,
    FiCopy,
    FiPlay,
    FiArrowLeft,
    FiSettings,
    FiStar,
    FiLogOut,
    FiUser
} from 'react-icons/fi';
import useRoomStore from '../../stores/use-room-store-realtime';
import roomApi from '../../services/room-api';
import authStore from '../../stores/auth-store';
import socketService from '../../services/socket-service';
import { useTheme } from '../../contexts/theme-context';
import '../../styles/components/room/waiting-room.css';

const WaitingRoom = () => {
    const { roomCode } = useParams();
    const navigate = useNavigate();
    const location = useLocation();
    const { theme } = useTheme();
    const {
        currentRoom,
        roomPlayers,
        isLoading,
        error,
        connectToRoom,
        disconnectFromRoom,
        leaveRoom,
        startGame,
        fetchRoomPlayers,
        setCurrentRoom,
        setLoading,
        setError,
        setRoomPlayers
    } = useRoomStore();

    const [copied, setCopied] = useState(false);
    const [fetchingRoom, setFetchingRoom] = useState(false);
    const isNavigatingToGameRef = useRef(false);
    const currentUser = authStore((state) => state.user);

    useEffect(() => {
        const fetchRoomData = async () => {
            if (!roomCode) {
                setError('Mã phòng không hợp lệ');
                return;
            }

            if (location.state?.room && location.state?.fromCreate) {
                const roomData = location.state.room;
                setCurrentRoom(roomData);

                if (roomData.id) {
                    await connectToRoom(roomData.id);
                }

                setLoading(false);
                return;
            }

            if (currentRoom && currentRoom.roomCode === roomCode) {
                if (currentRoom.id) {
                    await connectToRoom(currentRoom.id);
                }
                return;
            }

            setFetchingRoom(true);
            setLoading(true);
            setError(null);

            try {
                let room = null;
                try {
                    const roomInfoResponse = await roomApi.getRoomByCode(roomCode);
                    if (roomInfoResponse.success) {
                        room = roomInfoResponse.data;
                    }
                } catch (infoError) {
                }

                if (!room) {
                    const joinResponse = await roomApi.joinRoomByCode(roomCode);
                    if (joinResponse.success && joinResponse.data) {
                        room = joinResponse.data;
                    } else {
                        setError(joinResponse.error || 'Không tìm thấy phòng');
                        return;
                    }
                }

                setCurrentRoom(room);

                if (room.id) {
                    await connectToRoom(room.id);
                }
            } catch (err) {
                setError('Có lỗi xảy ra khi tải phòng');
            } finally {
                setFetchingRoom(false);
                setLoading(false);
            }
        };

        fetchRoomData();
    }, [roomCode]);

    useEffect(() => {
        const handleGameStarted = (event) => {
            const { roomId } = event.detail;

            if (currentRoom && roomId === currentRoom.id) {
                isNavigatingToGameRef.current = true;
                navigate(`/game/${currentRoom.roomCode || currentRoom.code}`);
            }
        };

        window.addEventListener('gameStarted', handleGameStarted);

        return () => {
            window.removeEventListener('gameStarted', handleGameStarted);
        };
    }, [currentRoom, navigate]);

    useEffect(() => {
        return () => {
            if (currentRoom?.id) {
                if (isNavigatingToGameRef.current) {
                    socketService.unsubscribeFromRoom(currentRoom.id);
                } else {
                    disconnectFromRoom(currentRoom.id);
                }
            }
        };
    }, [currentRoom?.id, disconnectFromRoom]);

    const handleCopyCode = async () => {
        if (currentRoom?.roomCode || currentRoom?.code) {
            try {
                await navigator.clipboard.writeText(currentRoom.roomCode || currentRoom.code);
                setCopied(true);
                setTimeout(() => setCopied(false), 2000);
            } catch (err) {
            }
        }
    };

    const handleLeaveRoom = async () => {
        try {
            leaveRoom().catch(() => { });

            navigate('/rooms', { replace: true });
        } catch (error) {
            navigate('/rooms', { replace: true });
        }
    };

    const handleStartGame = async () => {
        const result = await startGame();
        if (result.success) {
            // Navigate to game room
            navigate(`/game/${roomCode}`);
        }
    };

    // Loading state
    if (isLoading || fetchingRoom) {
        return (
            <div className={`waiting-room ${theme}`}>
                <div className="waiting-room-container">
                    <div className="loading-section">
                        <div className="loading-spinner"></div>
                        <p>Đang tải thông tin phòng...</p>
                    </div>
                </div>
            </div>
        );
    }

    // Error state
    if (error) {
        return (
            <div className={`waiting-room ${theme}`}>
                <div className="waiting-room-container">
                    <div className="error-section">
                        <h3>Có lỗi xảy ra</h3>
                        <p>{error}</p>
                        <div className="error-actions">
                            <button
                                className="retry-button"
                                onClick={() => {
                                    setError(null);
                                    setCurrentRoom(null);
                                    window.location.reload();
                                }}
                            >
                                Thử lại
                            </button>
                            <button
                                className="back-button"
                                onClick={() => navigate('/dashboard')}
                            >
                                Quay lại Dashboard
                            </button>
                        </div>
                    </div>
                </div>
            </div>
        );
    }

    // No room state
    if (!currentRoom) {
        return (
            <div className={`waiting-room ${theme}`}>
                <div className="waiting-room-container">
                    <div className="not-found-section">
                        <h3>Không tìm thấy phòng</h3>
                        <p>Phòng có mã "{roomCode}" không tồn tại hoặc đã bị xóa.</p>
                        <button
                            className="back-button"
                            onClick={() => navigate('/dashboard')}
                        >
                            Quay lại Dashboard
                        </button>
                    </div>
                </div>
            </div>
        );
    }

    const isHost = currentRoom && currentUser &&
        (currentRoom.ownerId === currentUser.id || currentRoom.hostId === currentUser.id);

    return (
        <div className={`waiting-room ${theme}`}>
            <div className="waiting-room-container">
                {/* Header */}
                <div className="waiting-room-header">
                    <h1>{currentRoom.roomName || currentRoom.name}</h1>
                    <button
                        className="leave-button"
                        onClick={handleLeaveRoom}
                    >
                        <FiLogOut />
                        Rời phòng
                    </button>
                </div>

                {/* Room Info */}
                <div className="room-info-section">
                    <div className="room-code-display">
                        <h3>Mã phòng</h3>
                        <div className="code-container">
                            <span className="room-code">
                                {currentRoom.roomCode || currentRoom.code}
                            </span>
                            <button
                                className="copy-button"
                                onClick={handleCopyCode}
                            >
                                <FiCopy />
                                {copied ? 'Đã sao chép' : 'Sao chép'}
                            </button>
                        </div>
                    </div>

                    <div className="room-settings">
                        <h3>
                            <FiSettings />
                            Cài đặt phòng
                        </h3>
                        <div className="settings-grid">
                            <div className="setting-item">
                                <span>Chế độ chơi:</span>
                                <span>{currentRoom.roomMode || currentRoom.Settings?.gameMode}</span>
                            </div>
                            <div className="setting-item">
                                <span>Chủ đề:</span>
                                <span>{currentRoom.topicName || currentRoom.TopicName}</span>
                            </div>
                            <div className="setting-item">
                                <span>Số người tối đa:</span>
                                <span>{currentRoom.maxPlayers || currentRoom.MaxPlayers}</span>
                            </div>
                            <div className="setting-item">
                                <span>Số câu hỏi:</span>
                                <span>{currentRoom.questionCount || currentRoom.Settings?.questionCount}</span>
                            </div>
                            <div className="setting-item">
                                <span>Thời gian:</span>
                                <span>{currentRoom.countdownTime || currentRoom.Settings?.timeLimit}s</span>
                            </div>
                            <div className="setting-item">
                                <span>Trạng thái:</span>
                                <span className={`status ${(currentRoom.status || currentRoom.Status)?.toLowerCase()}`}>
                                    {currentRoom.status || currentRoom.Status}
                                </span>
                            </div>
                        </div>
                    </div>
                </div>

                {/* ✅ FIXED: Players Section with real-time updates */}
                <div className="players-section">
                    <h3>
                        <FiUsers />
                        Người chơi ({roomPlayers.length}/{currentRoom.maxPlayers || currentRoom.MaxPlayers})
                    </h3>
                    <div className="players-grid">
                        {roomPlayers.map((player, index) => (
                            <div key={player.id || player.userId || index} className="player-card">
                                <div className="player-avatar">
                                    <FiUser />
                                </div>
                                <div className="player-info">
                                    <span className="player-name">
                                        {player.username || player.name || `Player ${index + 1}`}
                                    </span>
                                    {player.isHost && (
                                        <span className="host-badge">
                                            <FiStar />
                                            Host
                                        </span>
                                    )}
                                </div>
                            </div>
                        ))}
                    </div>
                </div>

                {/* Host Controls */}
                {isHost && (
                    <div className="host-controls">
                        <button
                            className="start-game-button"
                            onClick={handleStartGame}
                            disabled={roomPlayers.length < 2}
                        >
                            <FiPlay />
                            Bắt đầu game
                        </button>
                    </div>
                )}

                {/* Waiting Message for Non-Host */}
                {!isHost && (
                    <div className="waiting-message">
                        <p>Đang chờ host bắt đầu game...</p>
                    </div>
                )}
            </div>
        </div>
    );
};

export default WaitingRoom;

import React, { createContext, useContext, useEffect, useState } from "react";

const ThemeContext = createContext();

export const ThemeProvider = ({ children }) => {
  const [theme, setTheme] = useState(() => {
    const saved = localStorage.getItem("theme");
    return saved || "light";
  });

  useEffect(() => {
    document.documentElement.setAttribute("data-theme", theme);
    localStorage.setItem("theme", theme);
  }, [theme]);

  const toggleTheme = () => {
    setTheme((prev) => (prev === "light" ? "dark" : "light"));
  };

  return (
    <ThemeContext.Provider value={{ theme, toggleTheme }}>
      {children}
    </ThemeContext.Provider>
  );
};


export const useTheme = () => useContext(ThemeContext);

