                                                </div>
                                            )}
                                        </div>
                                    </td>
                                </tr>
                            ))
                        )}
                    </tbody>
                </table>
            </div>

            {totalPages > 1 && (
                <div className="pagination">
                    <button className="pagination-btn" onClick={() => handlePageChange(currentPage - 1)} disabled={currentPage === 0}>
                        <FiChevronLeft /> Trước
                    </button>
                    <div className="pagination-pages">
                        {[...Array(totalPages)].map((_, index) => {
                            if (index === 0 || index === totalPages - 1 || (index >= currentPage - 1 && index <= currentPage + 1)) {
                                return (
                                    <button key={index} className={`pagination-page ${index === currentPage ? 'active' : ''}`} onClick={() => handlePageChange(index)}>
                                        {index + 1}
                                    </button>
                                );
                            } else if (index === currentPage - 2 || index === currentPage + 2) {
                                return <span key={index} className="pagination-ellipsis">...</span>;
                            }
                            return null;
                        })}
                    </div>
                    <button className="pagination-btn" onClick={() => handlePageChange(currentPage + 1)} disabled={currentPage === totalPages - 1}>
                        Sau <FiChevronRight />
                    </button>
                </div>
            )}

            {showModal && (
                <div className="modal-overlay" onClick={() => setShowModal(false)}>
                    <div className="modal-content" onClick={(e) => e.stopPropagation()}>
                        <h2>{editingTopic ? 'Cập nhật chủ đề' : 'Thêm chủ đề mới'}</h2>
                        <form onSubmit={handleSubmit}>
                            <div className="form-group">
                                <label>Tên chủ đề *</label>
                                <input type="text" value={formData.name} onChange={(e) => setFormData({ ...formData, name: e.target.value })} required />
                            </div>
                            <div className="form-group">
                                <label>Mô tả</label>
                                <textarea value={formData.description} onChange={(e) => setFormData({ ...formData, description: e.target.value })} rows={4} />
                            </div>
                            <div className="modal-actions">
                                <button type="button" className="btn-cancel" onClick={() => setShowModal(false)}>Hủy</button>
                                <button type="submit" className="btn-submit">{editingTopic ? 'Cập nhật' : 'Tạo mới'}</button>
                            </div>
                        </form>
                    </div>
                </div>
            )}
            
            <PopupNotification
                type={popup.type}
                title={popup.title}
                message={popup.message}
                isVisible={popup.isVisible}
                onClose={hidePopup}
                showConfirm={popup.showConfirm}
                onConfirm={popup.onConfirm}
                onCancel={popup.onCancel}
                confirmText={popup.confirmText}
                cancelText={popup.cancelText}
            />
        </div>
    );
};

export default TopicManagement;

import { useState, useEffect } from 'react';
import { FiPlus, FiEdit2, FiTrash2, FiSearch, FiMoreVertical, FiArrowLeft, FiArrowRight } from 'react-icons/fi';
import adminApi from '../services/admin-api';
import PopupNotification from '../../../components/PopupNotification';
import { usePopup } from '../../../hooks/use-popup';
import '../../../styles/features/teacher/management.css';

const UserManagement = () => {
    const [users, setUsers] = useState([]);
    const [loading, setLoading] = useState(true);
    const [searchTerm, setSearchTerm] = useState('');
    const [showModal, setShowModal] = useState(false);
    const [editingUser, setEditingUser] = useState(null);
    const [formData, setFormData] = useState({ 
        username: '', 
        email: '', 
        password: '', 
        fullName: '', 
        phoneNumber: '', 
        address: '', 
        dob: '', 
        typeAccount: 'PLAYER',
        emailVerified: false 
    });
    const [dropdownOpen, setDropdownOpen] = useState(null);
    
    const [currentPage, setCurrentPage] = useState(0);
    const [totalPages, setTotalPages] = useState(0);
    const [totalElements, setTotalElements] = useState(0);
    
    const { popup, showSuccess, showError, showConfirm, hidePopup } = usePopup();



    useEffect(() => {
        const timer = setTimeout(() => {
            loadUsers();
        }, 300);
        return () => clearTimeout(timer);
    }, [searchTerm]);

    useEffect(() => {
        loadUsers();
    }, [currentPage]);

    useEffect(() => {
        const handleClickOutside = () => setDropdownOpen(null);
        if (dropdownOpen) {
            document.addEventListener('click', handleClickOutside);
            return () => document.removeEventListener('click', handleClickOutside);
        }
    }, [dropdownOpen]);



    const loadUsers = async () => {
        try {
            setLoading(true);
            const response = await adminApi.searchUsers(searchTerm, currentPage, 10);
            if (response.data) {
                setUsers(response.data.content || []);
                setTotalPages(response.data.totalPages || 0);
                setTotalElements(response.data.totalElements || 0);
            }
        } catch (error) {
            showError('Không thể tải danh sách người dùng');
            setUsers([]);
        } finally {
            setLoading(false);
        }
    };

    const handleSubmit = async (e) => {
        e.preventDefault();
        try {
            if (editingUser) {
                const updateData = { ...formData };
                if (!updateData.password) {
                    delete updateData.password;
                }
                await adminApi.updateUser(editingUser.id, updateData);
                showSuccess('Cập nhật người dùng thành công');
            } else {
                await adminApi.createUser(formData);
                showSuccess('Tạo người dùng thành công');
            }
            setShowModal(false);
            setFormData({ 
                username: '', 
                email: '', 
                password: '', 
                fullName: '', 
                phoneNumber: '', 
                address: '', 
                dob: '', 
                typeAccount: 'PLAYER',
                emailVerified: false 
            });
            setEditingUser(null);
            setCurrentPage(0);
            loadUsers();
        } catch (error) {
            showError(error.response?.data?.message || 'Có lỗi xảy ra');
        }
    };

    const handleEdit = (user) => {
        setEditingUser(user);
        setFormData({ 
            username: user.username, 
            email: user.email,
            password: '', // Không hiển thị mật khẩu khi edit
            fullName: user.fullName || '',
            phoneNumber: user.phoneNumber || '',
            address: user.address || '',
            dob: user.dob || '',
            typeAccount: user.typeAccount || 'PLAYER',
            emailVerified: user.emailVerified || false
        });
        setShowModal(true);
    };

    const handleDelete = async (id) => {
        showConfirm(
            'Bạn có chắc muốn xóa người dùng này? Hành động này không thể hoàn tác.',
            async () => {
                try {
                    await adminApi.deleteUser(id);
                    showSuccess('Xóa người dùng thành công');
                    loadUsers();
                } catch (error) {
                    showError('Không thể xóa người dùng');
                }
            },
            'Xác nhận xóa',
            'Xóa',
            'Hủy'
        );
    };

    const handlePageChange = (newPage) => {
        if (newPage >= 0 && newPage < totalPages) {
            setCurrentPage(newPage);
        }
    };

    if (loading && users.length === 0) return <div className="loading">Đang tải...</div>;

    return (
        <div className="management-page">
            <div className="management-header">
                <h1>Quản lý Người dùng</h1>
                <button className="btn-primary" onClick={() => { 
                    setShowModal(true); 
                    setEditingUser(null); 
                    setFormData({ 
                        username: '', 
                        email: '', 
                        password: '', 
                        fullName: '', 
                        phoneNumber: '', 
                        address: '', 
                        dob: '', 
                        typeAccount: 'PLAYER',
                        emailVerified: false 
                    }); 
                }}>
                    <FiPlus /> Thêm người dùng
                </button>
            </div>

            <div className="filter-section">
                <div className="search-bar-compact">
                    <FiSearch />
                    <input
                        type="text"
                        placeholder="Tìm kiếm người dùng..."
                        value={searchTerm}
                        onChange={(e) => setSearchTerm(e.target.value)}
                    />
                </div>
            </div>

            <div className="table-info">
                <span>Hiển thị {users.length > 0 ? currentPage * 10 + 1 : 0} - {Math.min((currentPage + 1) * 10, totalElements)} trong tổng số {totalElements} người dùng</span>
            </div>

            <div className="table-container">
                <table>
                    <thead>
                        <tr>
                            <th style={{ width: '60px' }}>STT</th>
                            <th>Tên đăng nhập</th>
                            <th>Email</th>
                            <th>Vai trò</th>
                            <th>Trạng thái</th>
                            <th>Ngày tạo</th>
                            <th>Cập nhật</th>
                            <th style={{ width: '100px' }}>Thao tác</th>
                        </tr>
                    </thead>
                    <tbody>
                        {loading ? (
                            <tr>
                                <td colSpan="8" style={{ textAlign: 'center', padding: '2rem' }}>
                                    Đang tải...
                                </td>
                            </tr>
                        ) : users.length === 0 ? (
                            <tr>
                                <td colSpan="8" style={{ textAlign: 'center', padding: '2rem' }}>
                                    {searchTerm ? 'Không tìm thấy người dùng phù hợp' : 'Chưa có người dùng nào'}
                                </td>
                            </tr>
                        ) : (
                            users.map((user, index) => (
                                <tr key={user.id}>
                                    <td>{currentPage * 10 + index + 1}</td>
                                    <td style={{ fontWeight: '600' }}>{user.username}</td>
                                    <td>{user.email}</td>
                                    <td>{user.typeAccount || '-'}</td>
                                    <td>
                                        <span className={`status-badge ${user.emailVerified ? 'verified' : 'unverified'}`}>
                                            {user.emailVerified ? 'Đã xác thực' : 'Chưa xác thực'}
                                        </span>
                                    </td>
                                    <td>{user.createdAt ? new Date(user.createdAt).toLocaleDateString('vi-VN') : '-'}</td>
                                    <td>{user.updatedAt ? new Date(user.updatedAt).toLocaleDateString('vi-VN') : '-'}</td>
                                    <td>
                                        <div className="dropdown-container" style={{ position: 'relative' }}>
                                            <button 
                                                className="btn-dropdown" 
                                                onClick={(e) => {
                                                    e.stopPropagation();
                                                    setDropdownOpen(dropdownOpen === user.id ? null : user.id);
                                                }}
                                                title="Tùy chọn"
                                            >
                                                <FiMoreVertical />
                                            </button>
                                            {dropdownOpen === user.id && (
                                                <div className="dropdown-menu" style={{ zIndex: 1001 }}>
                                                    <button onClick={() => { handleEdit(user); setDropdownOpen(null); }}>
                                                        <FiEdit2 /> Chỉnh sửa
                                                    </button>
                                                    <button onClick={() => { handleDelete(user.id); setDropdownOpen(null); }} className="delete-option">
                                                        <FiTrash2 /> Xóa
                                                    </button>
                                                </div>
                                            )}
                                        </div>
                                    </td>
                                </tr>
                            ))
                        )}
                    </tbody>
                </table>
            </div>

            {totalPages > 1 && (
                <div className="pagination">
                    <button 
                        className="pagination-btn" 
                        onClick={() => handlePageChange(currentPage - 1)}
                        disabled={currentPage === 0}
                        title="Trang trước"
                    >
                        <FiArrowLeft size={18} />
                    </button>
                    
                    <div className="pagination-pages">
                        {[...Array(totalPages)].map((_, index) => {
                            if (
                                index === 0 || 
                                index === totalPages - 1 || 
                                (index >= currentPage - 1 && index <= currentPage + 1)
                            ) {
                                return (
                                    <button
                                        key={index}
                                        className={`pagination-page ${index === currentPage ? 'active' : ''}`}
                                        onClick={() => handlePageChange(index)}
                                    >
                                        {index + 1}
                                    </button>
                                );
                            } else if (index === currentPage - 2 || index === currentPage + 2) {
                                return <span key={index} className="pagination-ellipsis">...</span>;
                            }
                            return null;
                        })}
                    </div>
                    
                    <button 
                        className="pagination-btn" 
                        onClick={() => handlePageChange(currentPage + 1)}
                        disabled={currentPage === totalPages - 1}
                        title="Trang sau"
                    >
                        <FiArrowRight size={18} />
                    </button>
                </div>
            )}

            {showModal && (
                <div className="modal-overlay" onClick={() => setShowModal(false)}>
                    <div className="modal-content modal-large" onClick={(e) => e.stopPropagation()}>
                        <h2>{editingUser ? 'Cập nhật người dùng' : 'Thêm người dùng mới'}</h2>
                        <form onSubmit={handleSubmit}>
                            <div className="form-row">
                                <div className="form-group">
                                    <label>Tên đăng nhập *</label>
                                    <input
                                        type="text"
                                        value={formData.username}
                                        onChange={(e) => setFormData({ ...formData, username: e.target.value })}
                                        required
                                    />
                                </div>
                                <div className="form-group">
                                    <label>Họ tên *</label>
                                    <input
                                        type="text"
                                        value={formData.fullName}
                                        onChange={(e) => setFormData({ ...formData, fullName: e.target.value })}
                                        required
                                    />
                                </div>
                            </div>
                            
                            <div className="form-row">
                                <div className="form-group">
                                    <label>Email *</label>
                                    <input
                                        type="email"
                                        value={formData.email}
                                        onChange={(e) => setFormData({ ...formData, email: e.target.value })}
                                        required
                                    />
                                    {editingUser && (
                                        <label className="checkbox-label" style={{ marginTop: '0.5rem' }}>
                                            <input
                                                type="checkbox"
                                                checked={formData.emailVerified}
                                                onChange={(e) => setFormData({ ...formData, emailVerified: e.target.checked })}
                                            />
                                            <span>Email đã xác thực</span>
                                        </label>
                                    )}
                                </div>
                                <div className="form-group">
                                    <label>Số điện thoại</label>
                                    <input
                                        type="tel"
                                        value={formData.phoneNumber}
                                        onChange={(e) => setFormData({ ...formData, phoneNumber: e.target.value })}
                                    />
                                </div>
                            </div>
                            
                            <div className="form-group">
                                <label>Địa chỉ</label>
                                <input
                                    type="text"
                                    value={formData.address}
                                    onChange={(e) => setFormData({ ...formData, address: e.target.value })}
                                />
                            </div>
                            
                            <div className="form-row">
                                <div className="form-group">
                                    <label>Ngày sinh</label>
                                    <input
                                        type="date"
                                        value={formData.dob}
                                        onChange={(e) => setFormData({ ...formData, dob: e.target.value })}
                                    />
                                </div>
                                <div className="form-group">
                                    <label>Vai trò *</label>
                                    <select
                                        value={formData.typeAccount}
                                        onChange={(e) => setFormData({ ...formData, typeAccount: e.target.value })}
                                        required
                                    >
                                        <option value="PLAYER">Người chơi</option>
                                        <option value="TEACHER">Giáo viên</option>
                                        <option value="HOST">Chủ phòng</option>
                                        <option value="ADMIN">Quản trị viên</option>
                                    </select>
                                </div>
                            </div>
                            

                            
                            {!editingUser && (
                                <div className="form-group">
                                    <label>Mật khẩu *</label>
                                    <input
                                        type="password"
                                        value={formData.password}
                                        onChange={(e) => setFormData({ ...formData, password: e.target.value })}
                                        required
                                        placeholder="Tối thiểu 6 ký tự"
                                    />
                                </div>
                            )}

                            <div className="modal-actions">
                                <button type="button" className="btn-cancel" onClick={() => setShowModal(false)}>Hủy</button>
                                <button type="submit" className="btn-submit">
                                    {editingUser ? 'Cập nhật' : 'Tạo mới'}
                                </button>
                            </div>
                        </form>
                    </div>
                </div>
            )}
            
            <PopupNotification
                type={popup.type}
                title={popup.title}
                message={popup.message}
                isVisible={popup.isVisible}
                onClose={hidePopup}
                showConfirm={popup.showConfirm}
                onConfirm={popup.onConfirm}
                onCancel={popup.onCancel}
                confirmText={popup.confirmText}
                cancelText={popup.cancelText}
            />
        </div>
    );
};

export default UserManagement;

import "../../../styles/pages/dashboard.css";
import { useEffect } from 'react';
import HeroSection from '../../../pages/dashboard/hero-section';
import StatsSection from '../../../pages/dashboard/stats-section';
import QuickActionsSection from '../../../pages/dashboard/quick-actions-section';
import authStore from '../../../stores/auth-store';
import profileApi from '../../../services/profile-api';
import Decoration from "../../../components/Decoration";
import { useStats } from '../../../hooks/use-stats';

function Dashboard() {
    const { user, isAuthenticated, isLoading } = authStore();
    const { stats: apiStats, loading: statsLoading, error: statsError } = useStats('dashboard');

    useEffect(() => {
        const fetchUserProfile = async () => {
            try {
                const result = await profileApi.getMyProfile();
            } catch (error) {
            }
        };

        if (isAuthenticated && !user) {
            fetchUserProfile();
        }
    }, [isAuthenticated, user]);

    // Prepare user data for components
    const userName = user?.username || 'User';
    const stats = apiStats || {
        gamesPlayed: 0,
        highScore: 0,
        rank: 0
    };

    return (
        <div className="mp-main-layout">
            <Decoration />
            <main className="mp-main-content">
                <HeroSection userName={userName} stats={stats} />
                <StatsSection stats={stats} loading={statsLoading} />
                <QuickActionsSection />
            </main>
        </div>
    );
}

export default Dashboard;

import { useState, useEffect } from 'react';
import { FiTarget } from 'react-icons/fi';
import { FaTrophy, FaMedal } from 'react-icons/fa';
import leaderboardApi from '../../../services/leaderboard-api';
import topicApi from '../../../services/topic-api';
import Decoration from '../../../components/Decoration';
import '../../../styles/pages/leaderboard.css';

function Leaderboard() {
    const [topics, setTopics] = useState([]);
    const [selectedTopic, setSelectedTopic] = useState(null);
    const [leaderboard, setLeaderboard] = useState([]);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState('');

    useEffect(() => {
        fetchTopics();
    }, []);

    useEffect(() => {
        if (selectedTopic) {
            fetchLeaderboard(selectedTopic);
        }
    }, [selectedTopic]);

    const fetchTopics = async () => {
        try {
            const result = await topicApi.getAll();
            if (result.success && result.data.length > 0) {
                setTopics(result.data);
                setSelectedTopic(result.data[0].id);
            }
        } catch (err) {
            setError('Không thể tải danh sách chủ đề');
        }
    };

    const fetchLeaderboard = async (topicId) => {
        setLoading(true);
        setError('');
        try {
            const result = await leaderboardApi.getLeaderboardByTopic(topicId);
            if (result.success) {
                setLeaderboard(result.data);
            } else {
                setError(result.error);
            }
        } catch (err) {
            setError('Không thể tải bảng xếp hạng');
        } finally {
            setLoading(false);
        }
    };

    const getMedalIcon = (rank) => {
        if (rank === 1) return <FaTrophy style={{ color: '#FFD700' }} />;
        if (rank === 2) return <FaTrophy style={{ color: '#C0C0C0' }} />;
        if (rank === 3) return <FaTrophy style={{ color: '#CD7F32' }} />;
        return null;
    };

    const getTopicName = () => {
        const topic = topics.find(t => t.id === selectedTopic);
        return topic?.name || 'Tất cả';
    };

    return (
        <div className="lb-layout">
            <Decoration />
            <main className="lb-content">
                <div className="lb-container">
                    <div className="lb-header">
                        <div className="lb-title-section">
                            <FaTrophy className="lb-title-icon" />
                            <h1 className="lb-title">Bảng Xếp Hạng</h1>
                        </div>
                        <p className="lb-subtitle">Top 20 người chơi xuất sắc nhất</p>
                    </div>

                    <div className="lb-filter-section">
                        <label className="lb-filter-label">
                            <FiTarget />
                            Chủ đề:
                        </label>
                        <select
                            className="lb-filter-select"
                            value={selectedTopic || ''}
                            onChange={(e) => setSelectedTopic(Number(e.target.value))}
                        >
                            {topics.map(topic => (
                                <option key={topic.id} value={topic.id}>
                                    {topic.name}
                                </option>
                            ))}
                        </select>
                    </div>

                    {loading ? (
                        <div className="lb-loading">
                            <div className="lb-spinner"></div>
                            <p>Đang tải bảng xếp hạng...</p>
                        </div>
                    ) : error ? (
                        <div className="lb-error">
                            <p>{error}</p>
                        </div>
                    ) : leaderboard.length === 0 ? (
                        <div className="lb-empty">
                            <FaMedal className="lb-empty-icon" />
                            <p>Chưa có dữ liệu xếp hạng cho chủ đề này</p>
                        </div>
                    ) : (
                        <>
                            <div className="lb-topic-name">
                                Bảng xếp hạng: <strong>{getTopicName()}</strong>
                            </div>
                            <div className="lb-table-container">
                                <table className="lb-table">
                                    <thead>
                                        <tr>
                                            <th>Hạng</th>
                                            <th>Người chơi</th>
                                            <th>Điểm TB</th>
                                            <th>Số trận</th>
                                        </tr>
                                    </thead>
                                    <tbody>
                                        {leaderboard.map((entry) => (
                                            <tr key={entry.userId} className={`lb-row rank-${entry.rank}`}>
                                                <td className="lb-rank">
                                                    {getMedalIcon(entry.rank) || `#${entry.rank}`}
                                                </td>
                                                <td className="lb-player">
                                                    <div className="lb-player-info">
                                                        <div className="lb-avatar">
                                                            {entry.username.charAt(0).toUpperCase()}
                                                        </div>
                                                        <span className="lb-username">{entry.username}</span>
                                                    </div>
                                                </td>
                                                <td className="lb-score">{entry.averageScore.toFixed(2)}</td>
                                                <td className="lb-games">{entry.gamesPlayed}</td>
                                            </tr>
                                        ))}
                                    </tbody>
                                </table>
                            </div>
                        </>
                    )}
                </div>
            </main>
        </div>
    );
}

export default Leaderboard;

import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { IoClose, IoAdd, IoEnter, IoSearch, IoRefresh } from 'react-icons/io5';
import CreateRoomModal from '../../../../components/room/CreateRoomModal';
import RoomCard from '../../../../components/room/RoomCard';
import JoinByCodeModal from '../../../../components/room/JoinByCodeModal';
import PlayerList from '../../../../components/room/PlayerList';
import useRoomStore from '../../../../stores/use-room-store';
import authStore from '../../../../stores/auth-store';
import useWebSocketCleanup from '../../../../hooks/use-web-socket-cleanup';
import '../../../../styles/pages/room/room-page.css';
import Decoration from '../../../../components/Decoration';
import SimpleBackground from '../../../../components/SimpleBackground';

const RoomsPage = () => {
    // Navigation and user management
    const navigate = useNavigate();
    const { user, logout } = authStore();

    // WebSocket cleanup
    useWebSocketCleanup();

    // Room management state and actions
    const {
        rooms,
        loading,
        error,
        loadRooms,
        joinRoom,
        clearError,
        startAutoRefresh,
        stopAutoRefresh,
        subscribeToRoomList,
        unsubscribeFromRoomList
    } = useRoomStore();

    // Local component state
    const [showCreateModal, setShowCreateModal] = useState(false);
    const [showJoinModal, setShowJoinModal] = useState(false);
    const [joinError, setJoinError] = useState('');
    const [success, setSuccess] = useState('');
    const [joinLoading, setJoinLoading] = useState(false);
    const [searchQuery, setSearchQuery] = useState('');
    const [currentPage, setCurrentPage] = useState(1);
    const itemsPerPage = 6;


    useEffect(() => {
    }, [currentPage]);

    /**
     * Initialize room data and setup realtime updates
     * - Initial load via REST API
     * - Subscribe to Socket.IO for realtime broadcasts
     */
    useEffect(() => {
        // 1. Initial load
        loadRooms();

        // 2. Subscribe to realtime updates
        subscribeToRoomList();

        // 3. Cleanup on unmount
        return () => {
            unsubscribeFromRoomList();
            stopAutoRefresh();
        };
    }, []); // Empty dependency array to run only once

    /**
     * Handle joining a public room
     * @param {string} roomCode - The room code to join
     */
    const handleJoinPublic = async (roomCode) => {

        // Validation
        if (!roomCode) {

            setJoinError('Mã phòng không hợp lệ');
            return;
        }

        // Clear previous errors and messages
        setJoinError('');
        setSuccess('');
        clearError();

        const result = await joinRoom(roomCode, true);

        if (result.success) {
            setSuccess('Đang chuyển hướng vào phòng chờ...');
            const targetRoom = result.data?.Code || roomCode;
            navigate(`/waiting-room/${targetRoom}`);
        } else {
            setJoinError(result.error);
        }
    };

    /**
     * Handle joining a private room by code
     * @param {string} roomCode - The room code to join
     */
    const handleJoinPrivate = async (roomCode) => {
        setJoinLoading(true);
        setJoinError('');

        const result = await joinRoom(roomCode);

        if (result.success) {
            setSuccess('Đang chuyển hướng vào phòng chờ...');
            const targetRoom = result.data?.roomCode || result.data?.code || roomCode;
            setShowJoinModal(false);
            navigate(`/waiting-room/${targetRoom}`);
        } else {
            setJoinError(result.error);
        }

        setJoinLoading(false);
    };

    /**
     * Handle successful join from modal
     */
    const handleJoinSuccess = (result) => {
        if (result.success) {
            setSuccess('Đã tham gia phòng thành công!');
            const targetRoom = result.data?.roomCode || result.data?.code || result.data?.RoomCode;
            if (targetRoom) {
                navigate(`/waiting-room/${targetRoom}`);
            }
        }
    };

    /**
     * Handle user logout
     */
    const handleLogout = () => {
        logout(navigate);
    };

    /**
     * Filter rooms based on search query
     */
    const filteredRooms = rooms.filter(room => {
        if (!searchQuery) return true;
        const query = searchQuery.toLowerCase();
        return (
            (room.RoomName && room.RoomName.toLowerCase().includes(query)) ||
            (room.TopicName && room.TopicName.toLowerCase().includes(query)) ||
            (room.RoomCode && room.RoomCode.toLowerCase().includes(query))
        );
    });

    /**
     * Calculate pagination
     */
    const totalPages = Math.ceil(filteredRooms.length / itemsPerPage);
    const startIndex = (currentPage - 1) * itemsPerPage;
    const endIndex = startIndex + itemsPerPage;
    const currentRooms = filteredRooms.slice(startIndex, endIndex);

    /**
     * Generate smart pagination numbers
     * Shows first page, last page, current page and surrounding pages
     */
    const getPaginationNumbers = () => {
        const pages = [];
        const maxVisiblePages = 5;

        if (totalPages <= maxVisiblePages) {
            // Show all pages if total is small
            for (let i = 1; i <= totalPages; i++) {
                pages.push(i);
            }
        } else {
            // Smart pagination logic
            const halfVisible = Math.floor(maxVisiblePages / 2);

            let startPage = Math.max(1, currentPage - halfVisible);
            let endPage = Math.min(totalPages, startPage + maxVisiblePages - 1);

            // Adjust startPage if we're near the end
            if (endPage === totalPages) {
                startPage = Math.max(1, endPage - maxVisiblePages + 1);
            }

            // Add first page if not included
            if (startPage > 1) {
                pages.push(1);
                if (startPage > 2) {
                    pages.push('...');
                }
            }

            // Add visible pages
            for (let i = startPage; i <= endPage; i++) {
                pages.push(i);
            }

            // Add last page if not included
            if (endPage < totalPages) {
                if (endPage < totalPages - 1) {
                    pages.push('...');
                }
                pages.push(totalPages);
            }
        }

        return pages;
    };

    /**
     * Handle page change
     */
    const handlePageChange = (page) => {
        if (page >= 1 && page <= totalPages) {
            setCurrentPage(page);
            // Scroll to top of room grid
            const roomGrid = document.querySelector('.room-grid');
            if (roomGrid) {
                roomGrid.scrollIntoView({ behavior: 'smooth', block: 'start' });
            }
        } else {
        }
    };

    /**
     * Handle search change and reset to first page
     */
    const handleSearchChange = (e) => {
        setSearchQuery(e.target.value);
        setCurrentPage(1); // Reset to first page when searching
    };

    /**
     * Format remaining time for room display
     * @param {string} endTime - End time string
     * @returns {string} Formatted time string
     */
    const formatTimeLeft = (endTime) => {
        if (!endTime) return 'Không giới hạn';

        const now = new Date();
        const end = new Date(endTime);
        const diff = end - now;

        if (diff <= 0) return 'Đã kết thúc';

        const minutes = Math.floor(diff / 60000);
        const seconds = Math.floor((diff % 60000) / 1000);
        return `${minutes}:${seconds.toString().padStart(2, '0')}`;
    };

    return (
        <div className="room-page">
            <SimpleBackground />
            <main className="room-content">

                <div className="room-container">

                    <div className="room-wrapper">
                        <div className="room-header">
                            <div className="room-header-left">
                                <h1>Danh sách phòng</h1>
                            </div>

                            <div className="room-actions">
                                <button
                                    className="room-btn-action room-btn-create"
                                    onClick={() => setShowCreateModal(true)}
                                >
                                    <IoAdd className="room-btn-icon" />
                                    <span>Tạo phòng mới</span>
                                </button>
                                <button
                                    className="room-btn-action room-btn-join"
                                    onClick={() => setShowJoinModal(true)}
                                >
                                    <IoEnter className="room-btn-icon" />
                                    <span>Tham gia bằng mã</span>
                                </button>
                            </div>
                        </div>

                        <div className="room-filter">
                            <div className="room-search-container">
                                <IoSearch className="room-search-icon" />
                                <input
                                    type="text"
                                    className="room-search-input"
                                    placeholder="Tìm kiếm phòng..."
                                    value={searchQuery}
                                    onChange={handleSearchChange}
                                />
                            </div>
                        </div>

                        {loading && rooms.length === 0 ? (
                            <div className="room-loading-container">
                                <div className="room-loading-spinner">
                                    <IoRefresh className="room-spinner-icon" />
                                </div>
                                <p>Đang tải danh sách phòng...</p>
                            </div>
                        ) : (
                            <div className="room-grid">
                                {currentRooms.length === 0 ? (
                                    <div className="room-empty">
                                        <div className="room-empty-icon">
                                            <IoSearch size={48} />
                                        </div>
                                        <h3>Không tìm thấy phòng nào</h3>
                                        <p>Hãy tạo phòng mới hoặc tham gia bằng mã phòng</p>
                                    </div>
                                ) : (
                                    currentRooms.map((room, index) => (
                                        <RoomCard
                                            key={room.RoomCode || `room-${index}`}
                                            room={room}
                                            onJoinPublic={handleJoinPublic}
                                        />
                                    ))
                                )}
                            </div>
                        )}

                        {/* Pagination */}
                        {totalPages > 1 && (
                            <div className="room-pagination">
                                <button
                                    className="pagination-button pagination-nav pagination-prev"
                                    onClick={() => {
                                        handlePageChange(currentPage - 1);
                                    }}
                                    disabled={currentPage === 1}
                                    aria-label="Trang trước"
                                >
                                    <span className="pagination-arrow">‹</span>
                                    <span className="pagination-text">Trước</span>
                                </button>

                                <div className="pagination-numbers">
                                    {getPaginationNumbers().map((page, index) => (
                                        page === '...' ? (
                                            <span key={`ellipsis-${index}`} className="pagination-ellipsis">
                                                ...
                                            </span>
                                        ) : (
                                            <button
                                                key={page}
                                                className={`pagination-button pagination-number ${page === currentPage ? 'active' : ''
                                                }`}
                                                onClick={() => {
                                                    handlePageChange(page);
                                                }}
                                                aria-label={`Trang ${page}`}
                                                aria-current={page === currentPage ? 'page' : undefined}
                                            >
                                                {page}
                                            </button>
                                        )
                                    ))}
                                </div>

                                <button
                                    className="pagination-button pagination-nav pagination-next"
                                    onClick={() => {
                                        handlePageChange(currentPage + 1);
                                    }}
                                    disabled={currentPage === totalPages}
                                    aria-label="Trang sau"
                                >
                                    <span className="pagination-text">Sau</span>
                                    <span className="pagination-arrow">›</span>
                                </button>
                            </div>
                        )}

                        {/* Results info */}
                        {filteredRooms.length > 0 && (
                            <div className="room-results-info">
                                Hiển thị {startIndex + 1}-{Math.min(endIndex, filteredRooms.length)} của {filteredRooms.length} phòng
                            </div>
                        )}
                    </div>
                </div>
            </main>

            {showCreateModal && (
                <CreateRoomModal
                    onClose={() => setShowCreateModal(false)}
                    onSuccess={() => {
                        setShowCreateModal(false);
                        loadRooms();
                    }}
                    onNavigateToRoom={(roomCode) => navigate(`/waiting-room/${roomCode}`)}
                />
            )}

            <JoinByCodeModal
                isOpen={showJoinModal}
                onClose={() => {
                    setShowJoinModal(false);
                    setJoinError('');
                }}
                onJoin={handleJoinPrivate}
                onSuccess={handleJoinSuccess}
                loading={joinLoading}
                error={joinError}
            />

            {(error || joinError) && !showJoinModal && (
                <div className="room-notification room-error">
                    {error || joinError}
                    <button onClick={() => { clearError(); setJoinError(''); }}>
                        <IoClose />
                    </button>
                </div>
            )}

            {success && !showJoinModal && (

                <div className="room-notification room-success">
                    {success}
                </div>
            )}
        </div>
    );
};

export default RoomsPage;

import { useState } from 'react';
import { FiX, FiSend, FiLoader, FiCheck, FiEdit2, FiTrash2 } from 'react-icons/fi';
import '../../../styles/features/teacher/aiprompt-modal.css';

const AIPromptModal = ({ isOpen, onClose, onConfirm, loading, generatedQuestions, onEdit, onDelete }) => {
    const [prompt, setPrompt] = useState('');
    const [editingIndex, setEditingIndex] = useState(null);
    const [editedQuestion, setEditedQuestion] = useState(null);

    if (!isOpen) return null;

    const handleEdit = (index) => {
        setEditingIndex(index);
        setEditedQuestion({ ...generatedQuestions[index] });
    };

    const handleSaveEdit = () => {
        onEdit(editingIndex, editedQuestion);
        setEditingIndex(null);
        setEditedQuestion(null);
    };

    return (
        <div className="ai-modal-overlay" onClick={onClose}>
            <div className="ai-modal-content" onClick={(e) => e.stopPropagation()}>
                <div className="ai-modal-header">
                    <h2>✨ Tạo câu hỏi bằng AI</h2>
                    <button onClick={onClose} className="ai-close-btn">
                        <FiX />
                    </button>
                </div>

                {!generatedQuestions.length ? (
                    <div className="ai-prompt-section">
                        <label>Nhập yêu cầu của bạn:</label>
                        <textarea
                            value={prompt}
                            onChange={(e) => setPrompt(e.target.value)}
                            placeholder="Ví dụ: Tạo 5 câu hỏi trắc nghiệm về lịch sử Việt Nam thời kỳ Lý-Trần, mỗi câu có 4 đáp án, độ khó trung bình. Câu hỏi cần bao gồm cả sự kiện lịch sử, nhân vật quan trọng và ý nghĩa lịch sử."
                            rows={8}
                            disabled={loading}
                        />
                        <div className="ai-prompt-tips">
                            <strong>Mẹo viết prompt hiệu quả:</strong>
                            <ul>
                                <li>Chỉ rõ số lượng câu hỏi cần tạo</li>
                                <li>Mô tả rõ nội dung, phạm vi kiến thức</li>
                                <li>Nêu rõ độ khó mong muốn (dễ/trung bình/khó)</li>
                                <li>Yêu cầu thêm chi tiết về định dạng đáp án</li>
                            </ul>
                        </div>
                        <button
                            onClick={() => onConfirm(prompt)}
                            disabled={!prompt.trim() || loading}
                            className="ai-generate-btn"
                        >
                            {loading ? (
                                <>
                                    <FiLoader className="spin" /> Đang tạo câu hỏi...
                                </>
                            ) : (
                                <>
                                    <FiSend /> Tạo câu hỏi bằng AI
                                </>
                            )}
                        </button>
                    </div>
                ) : (
                    <div className="ai-results-section">
                        <h3>Câu hỏi đã tạo ({generatedQuestions.length})</h3>
                        <p className="ai-results-note">
                            Câu hỏi đã được lưu thành công. Bạn có thể xem lại trong phần Quản lý câu hỏi.
                        </p>
                        <div className="ai-questions-list">
                            {generatedQuestions.map((q, idx) => (
                                <div key={idx} className="ai-question-item">
                                    {editingIndex === idx ? (
                                        <div className="ai-edit-form">
                                            <input
                                                value={editedQuestion.questionText}
                                                onChange={(e) =>
                                                    setEditedQuestion({ ...editedQuestion, questionText: e.target.value })
                                                }
                                            />
                                            {editedQuestion.answers?.map((ans, aIdx) => (
                                                <div key={aIdx} className="ai-answer-edit">
                                                    <input
                                                        value={ans.answerText || ans.text}
                                                        onChange={(e) => {
                                                            const newAnswers = [...editedQuestion.answers];
                                                            newAnswers[aIdx] = { 
                                                                ...newAnswers[aIdx],
                                                                answerText: e.target.value,
                                                                text: e.target.value 
                                                            };
                                                            setEditedQuestion({ ...editedQuestion, answers: newAnswers });
                                                        }}
                                                    />
                                                    <label>
                                                        <input
                                                            type="checkbox"
                                                            checked={ans.isCorrect}
                                                            onChange={(e) => {
                                                                const newAnswers = [...editedQuestion.answers];
                                                                newAnswers[aIdx].isCorrect = e.target.checked;
                                                                setEditedQuestion({ ...editedQuestion, answers: newAnswers });
                                                            }}
                                                        />
                                                        Đúng
                                                    </label>
                                                </div>
                                            ))}
                                            <button onClick={handleSaveEdit} className="ai-save-btn">
                                                <FiCheck /> Lưu
                                            </button>
                                        </div>
                                    ) : (
                                        <>
                                            <div className="ai-question-content">
                                                <strong>Câu {idx + 1}:</strong> {q.questionText}
                                                <div className="ai-answers">
                                                    {q.answers?.map((ans, aIdx) => (
                                                        <div key={aIdx} className={ans.isCorrect ? 'correct' : ''}>
                                                            {String.fromCharCode(65 + aIdx)}. {ans.answerText || ans.text}
                                                            {ans.isCorrect && ' ✓'}
                                                        </div>
                                                    ))}
                                                </div>
                                            </div>
                                            <div className="ai-question-actions">
                                                <button onClick={() => handleEdit(idx)} title="Chỉnh sửa">
                                                    <FiEdit2 />
                                                </button>
                                                <button onClick={() => onDelete(idx)} title="Xóa">
                                                    <FiTrash2 />
                                                </button>
                                            </div>
                                        </>
                                    )}
                                </div>
                            ))}
                        </div>
                        <div className="ai-confirm-actions">
                            <button onClick={onConfirm} className="ai-confirm-btn">
                                Xác nhận & Đóng
                            </button>
                            <button onClick={onClose} className="ai-cancel-btn">
                                Hủy
                            </button>
                        </div>
                    </div>
                )}
            </div>
        </div>
    );
};

export default AIPromptModal;

import { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { toast } from 'react-toastify';
import { FiZap, FiBook, FiFileText } from 'react-icons/fi';
import AIPromptModal from '../components/AipromptModal';
import { useAIGenerator } from '../hooks/use-aigenerator';
import teacherApi from '../services/teacher-api';
import '../../../styles/features/teacher/aiquestion-generator.css';

const AIQuestionGenerator = () => {
    const [isModalOpen, setIsModalOpen] = useState(false);
    const [selectedTopic, setSelectedTopic] = useState('');
    const [selectedExam, setSelectedExam] = useState('');
    const [topics, setTopics] = useState([]);
    const [exams, setExams] = useState([]);
    const [filteredExams, setFilteredExams] = useState([]);
    const [loadingTopics, setLoadingTopics] = useState(true);
    const { loading, generatedQuestions, generateQuestions, setGeneratedQuestions } = useAIGenerator();
    const navigate = useNavigate();

    useEffect(() => {
        const loadData = async () => {
            try {
                const [topicsRes, examsRes] = await Promise.all([
                    teacherApi.getAllTopics(),
                    teacherApi.getAllExams()
                ]);
                setTopics(topicsRes.data || []);
                setExams(examsRes.data || []);
            } catch (error) {
                toast.error('Không thể tải dữ liệu');
            } finally {
                setLoadingTopics(false);
            }
        };
        loadData();
    }, []);

    useEffect(() => {
        if (selectedTopic) {
            setFilteredExams(exams.filter(e => e.topicId === parseInt(selectedTopic)));
            setSelectedExam('');
        } else {
            setFilteredExams(exams);
        }
    }, [selectedTopic, exams]);

    const handleGenerate = async (prompt) => {
        if (!selectedExam) {
            toast.error('Vui lòng chọn bộ đề trước');
            return;
        }
        
        const result = await generateQuestions(selectedExam, prompt);
        
        if (result.success) {
            toast.success(`${result.message || `Đã tạo ${result.totalGenerated} câu hỏi thành công!`}`);
        } else {
            toast.error('Không thể tạo câu hỏi: ' + result.error);
        }
    };

    const handleConfirm = () => {
        toast.success(`Đã lưu ${generatedQuestions.length} câu hỏi thành công!`);
        setIsModalOpen(false);
        setGeneratedQuestions([]);
        navigate('/teacher/questions');
    };

    const handleEdit = (index, editedQuestion) => {
        const updated = [...generatedQuestions];
        updated[index] = editedQuestion;
        setGeneratedQuestions(updated);
    };

    const handleDelete = (index) => {
        const updated = generatedQuestions.filter((_, i) => i !== index);
        setGeneratedQuestions(updated);
        toast.info(`Đã xóa câu hỏi. Còn lại ${updated.length} câu hỏi.`);
    };

    // Prompt examples
    const promptExamples = [
        {
            icon: <FiBook />,
            title: 'Trắc nghiệm cơ bản',
            text: 'Tạo 5 câu hỏi trắc nghiệm về [tên bộ đề], mỗi câu có 4 đáp án, độ khó trung bình'
        },
        {
            icon: <FiBook />,
            title: 'Câu hỏi nâng cao',
            text: 'Tạo 10 câu hỏi về [tên bộ đề] với độ khó cao, bao gồm cả câu hỏi tình huống và phân tích'
        },
        {
            icon: <FiZap />,
            title: 'Đa dạng định dạng',
            text: 'Tạo 8 câu hỏi về [tên bộ đề], bao gồm: 4 câu trắc nghiệm, 2 câu đúng/sai, 2 câu nhiều đáp án đúng'
        }
    ];

    const handleUseExample = (exampleText) => {
        if (!selectedExam) {
            toast.warning('Vui lòng chọn bộ đề trước');
            return;
        }
        
        const topicName = topics.find(t => t.id === parseInt(selectedTopic))?.name || 'chủ đề';
        const filledText = exampleText.replace('[chủ đề]', topicName);
        
        navigator.clipboard.writeText(filledText);
        toast.success('Đã copy mẫu prompt!');
        setIsModalOpen(true);
    };

    return (
        <div className="ai-generator-page">
            <div className="ai-page-header">
                <div>
                    <h1><FiZap /> Tạo câu hỏi bằng AI</h1>
                    <p className="ai-subtitle">Sử dụng AI để tự động tạo câu hỏi trắc nghiệm chất lượng cao</p>
                </div>
            </div>

            <div className="ai-generator-content">
                <div className="ai-selection-row">
                    <div className="ai-topic-selection">
                        <label>
                            <FiBook /> Chọn chủ đề:
                        </label>
                        <select 
                            value={selectedTopic} 
                            onChange={(e) => setSelectedTopic(e.target.value)}
                            disabled={loadingTopics}
                        >
                            <option value="">-- Chọn chủ đề --</option>
                            {topics.map(topic => (
                                <option key={topic.id} value={topic.id}>{topic.name}</option>
                            ))}
                        </select>
                    </div>

                    {selectedTopic && (
                        <div className="ai-topic-selection">
                            <label>
                                <FiFileText /> Chọn bộ đề:
                            </label>
                            <select 
                                value={selectedExam} 
                                onChange={(e) => {
                                    setSelectedExam(e.target.value);
                                    if (e.target.value) {
                                        const exam = filteredExams.find(e => e.id === parseInt(e.target.value));
                                        toast.success(`Đã chọn bộ đề: ${exam?.title || ''}`);
                                    }
                                }}
                                className={filteredExams.length === 0 ? 'empty' : ''}
                            >
                                <option value="">
                                    {filteredExams.length === 0 ? 'Chưa có bộ đề nào' : '-- Chọn bộ đề --'}
                                </option>
                                {filteredExams.map(exam => (
                                    <option key={exam.id} value={exam.id}>{exam.title}</option>
                                ))}
                            </select>
                            {filteredExams.length === 0 && (
                                <div className="topic-warning">
                                    <span>Chủ đề này chưa có bộ đề nào.</span>
                                    <button 
                                        onClick={() => navigate('/teacher/exams')}
                                        className="btn-create-topic"
                                    >
                                        Tạo bộ đề ngay
                                    </button>
                                </div>
                            )}
                        </div>
                    )}
                </div>

                <div className="ai-prompt-suggestions">
                    <h3><FiBook /> Gợi ý mẫu Prompt</h3>
                    <p className="suggestions-desc">Chọn một mẫu prompt bên dưới để bắt đầu nhanh chóng:</p>
                    
                    <div className="prompt-examples-grid">
                        {promptExamples.map((example, index) => (
                            <div key={index} className="prompt-example-card">
                                <div className="example-icon">{example.icon}</div>
                                <h4>{example.title}</h4>
                                <p>{example.text}</p>
                                <button 
                                    onClick={() => handleUseExample(example.text)}
                                    disabled={!selectedExam}
                                    className="btn-use-example"
                                >
                                    Sử dụng mẫu này
                                </button>
                            </div>
                        ))}
                    </div>
                </div>

                <div className="ai-action-section">
                    <button 
                        onClick={() => setIsModalOpen(true)} 
                        disabled={!selectedExam}
                        className="btn-open-ai"
                    >
                        <FiZap /> Mở AI Generator
                    </button>
                    {!selectedExam && (
                        <p className="ai-hint">Vui lòng chọn bộ đề trước khi tạo câu hỏi</p>
                    )}
                </div>
            </div>

            <AIPromptModal
                isOpen={isModalOpen}
                onClose={() => {
                    setIsModalOpen(false);
                    setGeneratedQuestions([]);
                }}
                onConfirm={generatedQuestions.length ? handleConfirm : handleGenerate}
                loading={loading}
                generatedQuestions={generatedQuestions}
                onEdit={handleEdit}
                onDelete={handleDelete}
            />
        </div>
    );
};

export default AIQuestionGenerator;

import { useState, useEffect, useCallback } from 'react';
import { FiPlus, FiEdit2, FiTrash2, FiSearch, FiChevronLeft, FiChevronRight } from 'react-icons/fi';
import PopupNotification from '../../../components/PopupNotification';
import { usePopup } from '../../../hooks/use-popup';
import teacherApi from '../services/teacher-api';
import '../../../styles/features/teacher/management.css';

const ExamManagement = () => {
    const { popup, showSuccess, showError, showConfirm, hidePopup } = usePopup();
    const [exams, setExams] = useState([]);
    const [topics, setTopics] = useState([]);
    const [loading, setLoading] = useState(true);
    const [searchTerm, setSearchTerm] = useState('');
    const [selectedTopic, setSelectedTopic] = useState('');
    const [showModal, setShowModal] = useState(false);
    const [editingExam, setEditingExam] = useState(null);
    const [formData, setFormData] = useState({ title: '', description: '', topicId: '' });
    
    const [currentPage, setCurrentPage] = useState(0);
    const [totalPages, setTotalPages] = useState(0);
    const [totalElements, setTotalElements] = useState(0);
    const [sortOrder, setSortOrder] = useState('desc');

    useEffect(() => {
        loadTopics();
    }, []);

    useEffect(() => {
        const timer = setTimeout(() => {
            loadExams();
        }, 300);
        return () => clearTimeout(timer);
    }, [searchTerm]);

    useEffect(() => {
        loadExams();
    }, [currentPage, sortOrder, selectedTopic]);

    const loadTopics = async () => {
        try {
            const response = await teacherApi.getAllTopics();
            setTopics(response.data || []);
        } catch (error) {
            showError('Không thể tải danh sách chủ đề');
        }
    };

    const loadExams = useCallback(async () => {
        try {
            setLoading(true);
            const sortParam = `id,${sortOrder}`;
            const topicIdParam = selectedTopic && selectedTopic !== '' ? parseInt(selectedTopic) : null;
            const response = await teacherApi.searchExams(searchTerm, topicIdParam, currentPage, 10, sortParam);
            
            if (response.data) {
                const pageData = response.data;
                setExams(pageData.content || []);
                setTotalPages(pageData.totalPages || 0);
                setTotalElements(pageData.totalElements || 0);
            }
        } catch (error) {
            console.error('Error loading exams:', error);
            showError('Không thể tải danh sách bộ đề');
            setExams([]);
        } finally {
            setLoading(false);
        }
    }, [currentPage, sortOrder, searchTerm, selectedTopic]);

    const handleSubmit = async (e) => {
        e.preventDefault();
        try {
            const payload = {
                title: formData.title,
                description: formData.description,
                topicId: parseInt(formData.topicId)
            };

            if (editingExam) {
                await teacherApi.updateExam(editingExam.id, payload);
                showSuccess('Cập nhật bộ đề thành công');
            } else {
                await teacherApi.createExam(payload);
                showSuccess('Tạo bộ đề thành công');
            }
            setShowModal(false);
            setFormData({ title: '', description: '', topicId: '' });
            setEditingExam(null);
            setCurrentPage(0);
            loadExams();
        } catch (error) {
            showError(editingExam ? 'Không thể cập nhật bộ đề' : 'Không thể tạo bộ đề');
        }
    };

    const handleSearch = (value) => {
        setSearchTerm(value);
        setCurrentPage(0);
    };

    const handleTopicFilter = (value) => {
        setSelectedTopic(value);
        setCurrentPage(0);
    };

    const handleSort = () => {
        setSortOrder(sortOrder === 'asc' ? 'desc' : 'asc');
        setCurrentPage(0);
    };

    const handlePageChange = (newPage) => {
        if (newPage >= 0 && newPage < totalPages) {
            setCurrentPage(newPage);
        }
    };

    const handleEdit = (exam) => {
        setEditingExam(exam);
        setFormData({ 
            title: exam.title, 
            description: exam.description,
            topicId: exam.topicId 
        });
        setShowModal(true);
    };

    const handleDelete = async (id) => {
        showConfirm(
            'Bạn có chắc muốn xóa bộ đề này? Tất cả câu hỏi trong bộ đề cũng sẽ bị xóa.',
            async () => {
                try {
                    await teacherApi.deleteExam(id);
                    showSuccess('Xóa bộ đề thành công');
                    loadExams();
                } catch (error) {
                    showError('Không thể xóa bộ đề');
                }
            },
            'Xác nhận xóa',
            'Xóa',
            'Hủy'
        );
    };

    const getSortIcon = () => {
        return sortOrder === 'asc' ? '↑' : '↓';
    };

    const getRowNumber = (index) => {
        return currentPage * 10 + index + 1;
    };

    if (loading && exams.length === 0) return <div className="loading">Đang tải...</div>;

    return (
        <div className="management-page">
            <div className="management-header">
                <h1>Quản lý Bộ đề</h1>
                <button className="btn-primary" onClick={() => { 
                    setShowModal(true); 
                    setEditingExam(null); 
                    setFormData({ title: '', description: '', topicId: '' }); 
                }}>
                    <FiPlus /> Thêm bộ đề
                </button>
            </div>

            <div className="filter-section">
                <div className="search-bar-compact">
                    <FiSearch />
                    <input
                        type="text"
                        placeholder="Tìm kiếm bộ đề..."
                        value={searchTerm}
                        onChange={(e) => handleSearch(e.target.value)}
                    />
                </div>
                <select 
                    value={selectedTopic} 
                    onChange={(e) => handleTopicFilter(e.target.value)}
                    className="filter-select"
                >
                    <option value="">Tất cả chủ đề</option>
                    {topics.map(topic => (
                        <option key={topic.id} value={topic.id}>{topic.name}</option>
                    ))}
                </select>
            </div>

            <div className="table-info">
                <span>Hiển thị {exams.length > 0 ? currentPage * 10 + 1 : 0} - {Math.min((currentPage + 1) * 10, totalElements)} trong tổng số {totalElements} bộ đề</span>
            </div>

            <div className="table-container">
                <table>
                    <thead>
                        <tr>
                            <th style={{ width: '80px' }}>STT</th>
                            <th style={{ cursor: 'pointer' }} onClick={handleSort}>
                                Tên bộ đề {getSortIcon()}
                            </th>
                            <th>Mô tả</th>
                            <th style={{ width: '150px' }}>Chủ đề</th>
                            <th style={{ width: '120px' }}>Thao tác</th>
                        </tr>
                    </thead>
                    <tbody>
                        {loading ? (
                            <tr>
                                <td colSpan="5" style={{ textAlign: 'center', padding: '2rem' }}>
                                    <div className="spinner-small"></div>
                                    Đang tải...
                                </td>
                            </tr>
                        ) : exams.length === 0 ? (
                            <tr>
                                <td colSpan="5" style={{ textAlign: 'center', padding: '2rem' }}>
                                    {searchTerm || selectedTopic ? 'Không tìm thấy bộ đề phù hợp' : 'Chưa có bộ đề nào'}
                                </td>
                            </tr>
                        ) : (
                            exams.map((exam, index) => (
                                <tr key={exam.id}>
                                    <td style={{ fontWeight: '600', color: 'var(--text-secondary)' }}>
                                        {getRowNumber(index)}
                                    </td>
                                    <td style={{ fontWeight: '600' }}>{exam.title}</td>
                                    <td style={{ maxWidth: '400px' }}>{exam.description}</td>
                                    <td>{topics.find(t => t.id === exam.topicId)?.name || '-'}</td>
                                    <td>
                                        <div className="action-buttons">
                                            <button className="btn-edit" onClick={() => handleEdit(exam)} title="Sửa">
                                                <FiEdit2 />
                                            </button>
                                            <button className="btn-delete" onClick={() => handleDelete(exam.id)} title="Xóa">
                                                <FiTrash2 />
                                            </button>
                                        </div>
                                    </td>
                                </tr>
                            ))
                        )}
                    </tbody>
                </table>
            </div>

            {totalPages > 1 && (
                <div className="pagination">
                    <button 
                        className="pagination-btn" 
                        onClick={() => handlePageChange(currentPage - 1)}
                        disabled={currentPage === 0}
                    >
                        <FiChevronLeft /> Trước
                    </button>
                    
                    <div className="pagination-pages">
                        {[...Array(totalPages)].map((_, index) => {
                            if (
                                index === 0 || 
                                index === totalPages - 1 || 
                                (index >= currentPage - 1 && index <= currentPage + 1)
                            ) {
                                return (
                                    <button
                                        key={index}
                                        className={`pagination-page ${index === currentPage ? 'active' : ''}`}
                                        onClick={() => handlePageChange(index)}
                                    >
                                        {index + 1}
                                    </button>
                                );
                            } else if (index === currentPage - 2 || index === currentPage + 2) {
                                return <span key={index} className="pagination-ellipsis">...</span>;
                            }
                            return null;
                        })}
                    </div>
                    
                    <button 
                        className="pagination-btn" 
                        onClick={() => handlePageChange(currentPage + 1)}
                        disabled={currentPage === totalPages - 1}
                    >
                        Sau <FiChevronRight />
                    </button>
                </div>
            )}

            {showModal && (
                <div className="modal-overlay" onClick={() => setShowModal(false)}>
                    <div className="modal-content" onClick={(e) => e.stopPropagation()}>
                        <h2>{editingExam ? 'Cập nhật bộ đề' : 'Thêm bộ đề mới'}</h2>
                        <form onSubmit={handleSubmit}>
                            <div className="form-group">
                                <label>Tên bộ đề *</label>
                                <input
                                    type="text"
                                    value={formData.title}
                                    onChange={(e) => setFormData({ ...formData, title: e.target.value })}
                                    required
                                    placeholder="Ví dụ: Đề thi giữa kỳ môn Toán"
                                />
                            </div>
                            <div className="form-group">
                                <label>Mô tả</label>
                                <textarea
                                    value={formData.description}
                                    onChange={(e) => setFormData({ ...formData, description: e.target.value })}
                                    rows={4}
                                    placeholder="Mô tả chi tiết về bộ đề..."
                                />
                            </div>
                            <div className="form-group">
                                <label>Chủ đề *</label>
                                <select
                                    value={formData.topicId}
                                    onChange={(e) => setFormData({ ...formData, topicId: e.target.value })}
                                    required
                                >
                                    <option value="">Chọn chủ đề</option>
                                    {topics.map(topic => (
                                        <option key={topic.id} value={topic.id}>{topic.name}</option>
                                    ))}
                                </select>
                            </div>
                            <div className="modal-actions">
                                <button type="button" className="btn-cancel" onClick={() => setShowModal(false)}>Hủy</button>
                                <button type="submit" className="btn-submit">
                                    {editingExam ? 'Cập nhật' : 'Tạo mới'}
                                </button>
                            </div>
                        </form>
                    </div>
                </div>
            )}
            
            <PopupNotification
                type={popup.type}
                title={popup.title}
                message={popup.message}
                isVisible={popup.isVisible}
                onClose={hidePopup}
                showConfirm={popup.showConfirm}
                onConfirm={popup.onConfirm}
                onCancel={popup.onCancel}
                confirmText={popup.confirmText}
                cancelText={popup.cancelText}
            />
        </div>
    );
};

export default ExamManagement;

import { useState, useEffect, useCallback } from 'react';
import { FiPlus, FiEdit2, FiTrash2, FiSearch, FiEye, FiChevronLeft, FiChevronRight, FiFilter } from 'react-icons/fi';
import PopupNotification from '../../../components/PopupNotification';
import { usePopup } from '../../../hooks/use-popup';
import teacherApi from '../services/teacher-api';
import '../../../styles/features/teacher/management.css';

const QuestionManagement = () => {
    const { popup, showSuccess, showError, showConfirm, hidePopup } = usePopup();
    const [questions, setQuestions] = useState([]);
    const [exams, setExams] = useState([]);
    const [loading, setLoading] = useState(true);
    const [searchTerm, setSearchTerm] = useState('');
    const [selectedExam, setSelectedExam] = useState('');
    const [selectedType, setSelectedType] = useState('ALL');
    const [showModal, setShowModal] = useState(false);
    const [showAnswersModal, setShowAnswersModal] = useState(false);
    const [editingQuestion, setEditingQuestion] = useState(null);
    const [viewingAnswers, setViewingAnswers] = useState([]);
    
    // Pagination states
    const [currentPage, setCurrentPage] = useState(0);
    const [totalPages, setTotalPages] = useState(0);
    const [totalElements, setTotalElements] = useState(0);
    const [sortOrder, setSortOrder] = useState('desc');
    
    const [formData, setFormData] = useState({
        questionText: '',
        questionType: 'MULTIPLE_CHOICE',
        examId: '',
        answers: [
            { answerText: '', isCorrect: false },
            { answerText: '', isCorrect: false },
            { answerText: '', isCorrect: false },
            { answerText: '', isCorrect: false }
        ]
    });

    useEffect(() => {
        loadExams();
    }, []);

    useEffect(() => {
        const timer = setTimeout(() => {
            loadQuestions();
        }, 300);
        return () => clearTimeout(timer);
    }, [searchTerm]);

    useEffect(() => {
        loadQuestions();
    }, [selectedExam, selectedType, currentPage, sortOrder]);

    const loadExams = async () => {
        try {
            const examsRes = await teacherApi.getAllExams();
            setExams(examsRes.data || []);
        } catch (error) {
            showError('Không thể tải danh sách bộ đề');
        }
    };

    const loadQuestions = useCallback(async () => {
        try {
            setLoading(true);
            const sortParam = `id,${sortOrder}`;
            const examIdParam = selectedExam && selectedExam !== '' ? parseInt(selectedExam) : null;
            const typeParam = selectedType === 'ALL' ? null : selectedType;
            
            const response = await teacherApi.searchQuestions(
                searchTerm,
                examIdParam,
                typeParam,
                currentPage,
                10,
                sortParam
            );
            
            if (response.data) {
                const pageData = response.data;
                setQuestions(pageData.content || []);
                setTotalPages(pageData.totalPages || 0);
                setTotalElements(pageData.totalElements || 0);
            }
        } catch (error) {
            console.error('Error loading questions:', error);
            showError('Không thể tải danh sách câu hỏi');
            setQuestions([]);
        } finally {
            setLoading(false);
        }
    }, [searchTerm, selectedExam, selectedType, currentPage, sortOrder]);

    const handleSubmit = async (e) => {
        e.preventDefault();
        try {
            const payload = {
                questionText: formData.questionText,
                questionType: formData.questionType,
                examId: parseInt(formData.examId),
                answers: formData.answers.filter(a => a.answerText.trim())
            };

            if (editingQuestion) {
                await teacherApi.updateQuestion(editingQuestion.id, payload);
                showSuccess('Cập nhật câu hỏi thành công');
            } else {
                await teacherApi.createQuestion(payload);
                showSuccess('Tạo câu hỏi thành công');
            }
            setShowModal(false);
            resetForm();
            setCurrentPage(0);
            loadQuestions();
        } catch (error) {
            showError(editingQuestion ? 'Không thể cập nhật câu hỏi' : 'Không thể tạo câu hỏi');
        }
    };

    const handleSearch = (value) => {
        setSearchTerm(value);
        setCurrentPage(0);
    };

    const handleExamFilter = (value) => {
        setSelectedExam(value);
        setCurrentPage(0);
    };

    const handleTypeFilter = (value) => {
        setSelectedType(value);
        setCurrentPage(0);
    };

    const handlePageChange = (newPage) => {
        if (newPage >= 0 && newPage < totalPages) {
            setCurrentPage(newPage);
        }
    };

    const handleSort = () => {
        setSortOrder(sortOrder === 'asc' ? 'desc' : 'asc');
        setCurrentPage(0);
    };

    const resetForm = () => {
        setFormData({
            questionText: '',
            questionType: 'MULTIPLE_CHOICE',
            examId: '',
            answers: [
                { answerText: '', isCorrect: false },
                { answerText: '', isCorrect: false },
                { answerText: '', isCorrect: false },
                { answerText: '', isCorrect: false }
            ]
        });
        setEditingQuestion(null);
    };

    const handleEdit = (question) => {
        setEditingQuestion(question);
        setFormData({
            questionText: question.questionText,
            questionType: question.questionType,
            examId: question.examId,
            answers: question.answers?.length ? question.answers : [
                { answerText: '', isCorrect: false },
                { answerText: '', isCorrect: false },
                { answerText: '', isCorrect: false },
                { answerText: '', isCorrect: false }
            ]
        });
        setShowModal(true);
    };

    const handleDelete = async (id) => {
        showConfirm(
            'Bạn có chắc muốn xóa câu hỏi này? Hành động này không thể hoàn tác.',
            async () => {
                try {
                    await teacherApi.deleteQuestion(id);
                    showSuccess('Xóa câu hỏi thành công');
                    loadQuestions();
                } catch (error) {
                    console.error('Error deleting question:', error);
                    showError('Không thể xóa câu hỏi');
                }
            },
            'Xác nhận xóa',
            'Xóa',
            'Hủy'
        );
    };

    const handleViewAnswers = (question) => {
        setEditingQuestion(question);
        setViewingAnswers(question.answers || []);
        setShowAnswersModal(true);
    };

    const handleEditAnswers = () => {
        if (editingQuestion) {
            setFormData({
                questionText: editingQuestion.questionText,
                questionType: editingQuestion.questionType,
                examId: editingQuestion.examId,
                answers: editingQuestion.answers?.length ? editingQuestion.answers.map(a => ({
                    answerText: a.answerText || a.text || '',
                    isCorrect: a.isCorrect || false,
                    id: a.id
                })) : [
                    { answerText: '', isCorrect: false },
                    { answerText: '', isCorrect: false },
                    { answerText: '', isCorrect: false },
                    { answerText: '', isCorrect: false }
                ]
            });
            setShowAnswersModal(false);
            setShowModal(true);
        }
    };

    const updateAnswer = (index, field, value) => {
        const newAnswers = [...formData.answers];
        newAnswers[index][field] = value;
        setFormData({ ...formData, answers: newAnswers });
    };

    const getRowNumber = (index) => {
        return currentPage * 10 + index + 1;
    };

    const getSortIcon = () => {
        return sortOrder === 'asc' ? '↑' : '↓';
    };

    const getQuestionTypeName = (type) => {
        const types = {
            'MULTIPLE_CHOICE': 'Trắc nghiệm',
            'TRUE_FALSE': 'Đúng/Sai'
        };
        return types[type] || type;
    };

    if (loading && questions.length === 0) return <div className="loading">Đang tải...</div>;

    return (
        <div className="management-page">
            <div className="management-header">
                <h1>Quản lý Câu hỏi</h1>
                <button className="btn-primary" onClick={() => { setShowModal(true); resetForm(); }}>
                    <FiPlus /> Thêm câu hỏi
                </button>
            </div>

            <div className="filter-section">
                <div className="search-bar-compact">
                    <FiSearch />
                    <input
                        type="text"
                        placeholder="Tìm kiếm câu hỏi..."
                        value={searchTerm}
                        onChange={(e) => handleSearch(e.target.value)}
                    />
                </div>
                
                <div className="filter-group">
                    <FiFilter style={{ color: 'var(--primary)' }} />
                    <select 
                        value={selectedExam} 
                        onChange={(e) => handleExamFilter(e.target.value)}
                        className="filter-select"
                    >
                        <option value="">Tất cả bộ đề</option>
                        {exams.map(exam => (
                            <option key={exam.id} value={exam.id}>{exam.title}</option>
                        ))}
                    </select>
                    
                    <select 
                        value={selectedType} 
                        onChange={(e) => handleTypeFilter(e.target.value)}
                        className="filter-select"
                    >
                        <option value="ALL">Tất cả loại</option>
                        <option value="MULTIPLE_CHOICE">Trắc nghiệm</option>
                        <option value="TRUE_FALSE">Đúng/Sai</option>
                    </select>
                </div>
            </div>

            <div className="table-info">
                <span>Hiển thị {questions.length > 0 ? currentPage * 10 + 1 : 0} - {Math.min((currentPage + 1) * 10, totalElements)} trong tổng số {totalElements} câu hỏi</span>
            </div>

            <div className="table-container">
                <table>
                    <thead>
                        <tr>
                            <th style={{ width: '60px' }}>STT</th>
                            <th style={{ minWidth: '300px' }}>Câu hỏi</th>
                            <th style={{ width: '120px' }}>Loại</th>
                            <th style={{ width: '150px' }}>Bộ đề</th>
                            <th style={{ width: '100px' }}>Đáp án</th>
                            <th style={{ width: '150px' }}>Thao tác</th>
                        </tr>
                    </thead>
                    <tbody>
                        {loading ? (
                            <tr>
                                <td colSpan="6" style={{ textAlign: 'center', padding: '2rem' }}>
                                    <div className="spinner-small"></div>
                                    Đang tải...
                                </td>
                            </tr>
                        ) : questions.length === 0 ? (
                            <tr>
                                <td colSpan="6" style={{ textAlign: 'center', padding: '2rem' }}>
                                    {searchTerm || selectedExam || selectedType !== 'ALL' 
                                        ? 'Không tìm thấy câu hỏi phù hợp' 
                                        : 'Chưa có câu hỏi nào'}
                                </td>
                            </tr>
                        ) : (
                            questions.map((question, index) => (
                                <tr key={question.id}>
                                    <td style={{ fontWeight: '600', color: 'var(--text-secondary)' }}>
                                        {getRowNumber(index)}
                                    </td>
                                    <td style={{ fontWeight: '500' }}>
                                        {question.questionText?.length > 100 
                                            ? question.questionText.substring(0, 100) + '...' 
                                            : question.questionText}
                                    </td>
                                    <td>
                                        <span className="badge-type">{getQuestionTypeName(question.questionType)}</span>
                                    </td>
                                    <td>{exams.find(e => e.id === question.examId)?.title || '-'}</td>
                                    <td style={{ textAlign: 'center' }}>
                                        <span className="badge-count">{question.answers?.length || 0}</span>
                                    </td>
                                    <td>
                                        <div className="action-buttons">
                                            <button 
                                                className="btn-view" 
                                                onClick={() => handleViewAnswers(question)}
                                                title="Xem đáp án"
                                            >
                                                <FiEye />
                                            </button>
                                            <button 
                                                className="btn-edit" 
                                                onClick={() => handleEdit(question)}
                                                title="Sửa"
                                            >
                                                <FiEdit2 />
                                            </button>
                                            <button 
                                                className="btn-delete" 
                                                onClick={() => handleDelete(question.id)}
                                                title="Xóa"
                                            >
                                                <FiTrash2 />
                                            </button>
                                        </div>
                                    </td>
                                </tr>
                            ))
                        )}
                    </tbody>
                </table>
            </div>

            {totalPages > 1 && (
                <div className="pagination">
                    <button 
                        className="pagination-btn" 
                        onClick={() => handlePageChange(currentPage - 1)}
                        disabled={currentPage === 0}
                    >
                        <FiChevronLeft /> Trước
                    </button>
                    
                    <div className="pagination-pages">
                        {[...Array(totalPages)].map((_, index) => {
                            if (
                                index === 0 || 
                                index === totalPages - 1 || 
                                (index >= currentPage - 1 && index <= currentPage + 1)
                            ) {
                                return (
                                    <button
                                        key={index}
                                        className={`pagination-page ${index === currentPage ? 'active' : ''}`}
                                        onClick={() => handlePageChange(index)}
                                    >
                                        {index + 1}
                                    </button>
                                );
                            } else if (index === currentPage - 2 || index === currentPage + 2) {
                                return <span key={index} className="pagination-ellipsis">...</span>;
                            }
                            return null;
                        })}
                    </div>
                    
                    <button 
                        className="pagination-btn" 
                        onClick={() => handlePageChange(currentPage + 1)}
                        disabled={currentPage === totalPages - 1}
                    >
                        Sau <FiChevronRight />
                    </button>
                </div>
            )}

            {showModal && (
                <div className="modal-overlay" onClick={() => setShowModal(false)}>
                    <div className="modal-content modal-question" onClick={(e) => e.stopPropagation()}>
                        <div className="modal-header-sticky">
                            <h2>{editingQuestion ? 'Cập nhật câu hỏi' : 'Thêm câu hỏi mới'}</h2>
                            <button 
                                type="button" 
                                className="modal-close-btn" 
                                onClick={() => setShowModal(false)}
                                aria-label="Đóng"
                            >
                                ✕
                            </button>
                        </div>
                        
                        <form onSubmit={handleSubmit} className="modal-form-scroll">
                            <div className="form-group">
                                <label>Câu hỏi *</label>
                                <textarea
                                    value={formData.questionText}
                                    onChange={(e) => setFormData({ ...formData, questionText: e.target.value })}
                                    required
                                    rows={4}
                                    placeholder="Nhập nội dung câu hỏi..."
                                />
                            </div>
                            
                            <div className="form-row">
                                <div className="form-group">
                                    <label>Loại câu hỏi *</label>
                                    <select
                                        value={formData.questionType}
                                        onChange={(e) => setFormData({ ...formData, questionType: e.target.value })}
                                        required
                                    >
                                        <option value="MULTIPLE_CHOICE">Trắc nghiệm</option>
                                        <option value="TRUE_FALSE">Đúng/Sai</option>
                                    </select>
                                </div>
                                <div className="form-group">
                                    <label>Bộ đề *</label>
                                    <select
                                        value={formData.examId}
                                        onChange={(e) => setFormData({ ...formData, examId: e.target.value })}
                                        required
                                    >
                                        <option value="">Chọn bộ đề</option>
                                        {exams.map(exam => (
                                            <option key={exam.id} value={exam.id}>{exam.title}</option>
                                        ))}
                                    </select>
                                </div>
                            </div>
                            
                            <div className="form-group answers-section">
                                <label className="answers-label">
                                    Đáp án (Chọn ít nhất 1 đáp án đúng) *
                                </label>
                                <div className="answers-grid">
                                    {formData.answers.map((answer, index) => (
                                        <div key={index} className="answer-row-improved">
                                            <div className="answer-number">{String.fromCharCode(65 + index)}</div>
                                            <input
                                                type="text"
                                                placeholder={`Nhập đáp án ${String.fromCharCode(65 + index)}`}
                                                value={answer.answerText}
                                                onChange={(e) => updateAnswer(index, 'answerText', e.target.value)}
                                                className="answer-input"
                                            />
                                            <label className="checkbox-label-improved">
                                                <input
                                                    type="checkbox"
                                                    checked={answer.isCorrect}
                                                    onChange={(e) => updateAnswer(index, 'isCorrect', e.target.checked)}
                                                />
                                                <span className="checkbox-text">Đúng</span>
                                            </label>
                                        </div>
                                    ))}
                                </div>
                            </div>
                            
                            <div className="modal-actions-sticky">
                                <button type="button" className="btn-cancel" onClick={() => setShowModal(false)}>
                                    Hủy
                                </button>
                                <button type="submit" className="btn-submit" disabled={loading}>
                                    {loading ? 'Đang xử lý...' : (editingQuestion ? 'Cập nhật' : 'Tạo mới')}
                                </button>
                            </div>
                        </form>
                    </div>
                </div>
            )}

            {showAnswersModal && (
                <div className="modal-overlay" onClick={() => setShowAnswersModal(false)}>
                    <div className="modal-content modal-answers" onClick={(e) => e.stopPropagation()}>
                        <div className="modal-header-inline">
                            <h2>Đáp án câu hỏi</h2>
                            <button 
                                type="button" 
                                className="modal-close-btn" 
                                onClick={() => setShowAnswersModal(false)}
                                aria-label="Đóng"
                            >
                                ✕
                            </button>
                        </div>
                        
                        {editingQuestion && (
                            <div className="question-preview">
                                <p className="question-text">{editingQuestion.questionText}</p>
                                <div className="question-meta">
                                    <span className="meta-badge">{getQuestionTypeName(editingQuestion.questionType)}</span>
                                    <span className="meta-badge">{exams.find(e => e.id === editingQuestion.examId)?.title}</span>
                                </div>
                            </div>
                        )}
                        
                        <div className="answers-list-view">
                            {viewingAnswers && viewingAnswers.length > 0 ? (
                                viewingAnswers.map((answer, index) => (
                                    <div key={answer.id || index} className={`answer-item-view ${answer.isCorrect ? 'correct' : ''}`}>
                                        <div className="answer-letter">{String.fromCharCode(65 + index)}</div>
                                        <div className="answer-content">
                                            <span className="answer-text">{answer.answerText || answer.text}</span>
                                            {answer.isCorrect && (
                                                <span className="badge-correct-inline">
                                                    <span className="check-icon">✓</span> Đáp án đúng
                                                </span>
                                            )}
                                        </div>
                                    </div>
                                ))
                            ) : (
                                <div className="no-answers">
                                    <p>Chưa có đáp án nào</p>
                                </div>
                            )}
                        </div>
                    </div>
                </div>
            )}
            
            <PopupNotification
                type={popup.type}
                title={popup.title}
                message={popup.message}
                isVisible={popup.isVisible}
                onClose={hidePopup}
                showConfirm={popup.showConfirm}
                onConfirm={popup.onConfirm}
                onCancel={popup.onCancel}
                confirmText={popup.confirmText}
                cancelText={popup.cancelText}
            />
        </div>
    );
};

