import { useState, useEffect, useCallback } from 'react';
import authApi from '../services/auth-api';
import apiInstance from '../services/api-instance';
import authStore from '../stores/auth-store';

export const useAvatarUpload = (profileData) => {
    const { isAuthenticated } = authStore();

    // State cho upload avatar
    const [uploadingAvatar, setUploadingAvatar] = useState(false);
    const [uploadError, setUploadError] = useState('');
    const [successMessage, setSuccessMessage] = useState('');
    const [showSuccessModal, setShowSuccessModal] = useState(false);

    // State cho avatar
    const [avatarUrl, setAvatarUrl] = useState(null);
    const [avatarLoading, setAvatarLoading] = useState(false);

    // Hàm xử lý avatar URL
    const getAvatarUrl = useCallback((avatarURL) => {
        if (!avatarURL) return '';

        // Nếu là full URL (http/https), trả về nguyên
        if (avatarURL.startsWith('http://') || avatarURL.startsWith('https://')) {
            return avatarURL;
        }

        // Backend URL - thay đổi theo cấu hình thực tế
        const BACKEND_URL = 'http://localhost:8080';

        // Nếu avatarURL chỉ là filename, tạo full URL
        if (!avatarURL.includes('/')) {
            return `${BACKEND_URL}/api/v1/profile/avatar/${avatarURL}`;
        }

        // Nếu đã có path, chỉ cần thêm base URL
        return `${BACKEND_URL}${avatarURL.startsWith('/') ? '' : '/'}${avatarURL}`;
    }, []);

    // Hàm fetch avatar
    const fetchAvatar = useCallback(async () => {
        if (avatarUrl || avatarLoading || !profileData?.avatarURL) return;

        try {
            setAvatarLoading(true);

            const response = await authApi.getAvatar();

            if (response.isSuccess && response.data) {
                setAvatarUrl(response.data);
                return;
            }

            if (response.status === 200 && response.data) {
                try {
                    new URL(response.data);
                    setAvatarUrl(response.data);
                } catch (urlError) {
                    setAvatarUrl(null);
                }
            } else {
                setAvatarUrl(null);
            }
        } catch (error) {
            setAvatarUrl(null);
        } finally {
            setAvatarLoading(false);
        }
    }, [avatarUrl, avatarLoading, profileData?.avatarURL]);

    // Hàm refresh avatar (luôn fetch lại từ API)
    const refreshAvatar = useCallback(async () => {
        try {
            setAvatarLoading(true);

            const response = await authApi.getAvatar();

            if (response.isSuccess && response.data) {
                setAvatarUrl(response.data);
                return response.data;
            }

            if (response.status === 200 && response.data) {
                try {
                    new URL(response.data);
                    setAvatarUrl(response.data);
                    return response.data;
                } catch (urlError) {
                    setAvatarUrl(null);
                    return null;
                }
            } else {
                setAvatarUrl(null);
                return null;
            }
        } catch (error) {
            setAvatarUrl(null);
            return null;
        } finally {
            setAvatarLoading(false);
        }
    }, []);

    // Fetch avatar khi có profileData
    useEffect(() => {
        if (profileData?.avatarURL && !avatarUrl && !avatarLoading) {
            fetchAvatar();
        }
    }, [profileData?.avatarURL, avatarUrl, avatarLoading, fetchAvatar]);

    // Hàm validate file ảnh
    const validateImageFile = useCallback((file) => {
        const maxSize = 5 * 1024 * 1024; // 5MB

        if (!file || !file.type || !file.type.startsWith('image/')) {
            throw new Error('Chỉ chấp nhận file ảnh (image/*)');
        }

        if (file.size > maxSize) {
            throw new Error('File ảnh không được vượt quá 5MB');
        }

        return true;
    }, []);

    // Hàm xử lý chọn file ảnh và upload trực tiếp
    const handleFileSelect = useCallback(async (event, setUser) => {
        const file = event.target.files[0];
        if (!file) return;

        try {
            // Validate file
            validateImageFile(file);

            // Set loading state
            setUploadingAvatar(true);
            setUploadError('');
            setSuccessMessage('');

            // Tạo FormData
            const formData = new FormData();
            formData.append('file', file, 'avatar.jpg');

            // Upload trực tiếp
            const response = await apiInstance.post('/profile/avatar', formData, {
                headers: {
                    'Content-Type': 'multipart/form-data',
                },
            });

            // Kiểm tra response - điều chỉnh logic dựa trên backend response
            if (response.status === 200 || response.data?.success || response.data?.data?.avatarUrl || response.data?.avatarUrl) {

                // Lấy avatarUrl từ response (có thể ở nhiều vị trí khác nhau)
                const newAvatarUrl = response.data?.data?.avatarUrl || response.data?.avatarUrl || response.data?.url;

                if (newAvatarUrl) {
                    setAvatarUrl(newAvatarUrl);

                    // Cập nhật user state - lưu filename thay vì full URL
                    if (typeof setUser === 'function') {
                        // Extract filename from URL if it's a full URL
                        let filename = newAvatarUrl;
                        try {
                            const url = new URL(newAvatarUrl);
                            // Nếu là full URL, lấy pathname làm filename
                            filename = url.pathname.split('/').pop() || newAvatarUrl;
                        } catch (e) {
                            // Nếu không phải URL, giữ nguyên
                            filename = newAvatarUrl;
                        }

                        setUser(prev => ({ ...prev, avatarURL: filename }));
                    }
                }

                // Luôn refresh avatar từ API để đảm bảo có URL mới nhất
                await refreshAvatar();

                setSuccessMessage('Avatar đã được cập nhật thành công!');
                setShowSuccessModal(true);

                // Trigger Header to refresh avatar immediately
                window.dispatchEvent(new CustomEvent('avatarUpdated'));

                setTimeout(() => {
                    setSuccessMessage('');
                    setShowSuccessModal(false);
                }, 3000);
            } else if (response.status === 200) {
                // Fallback: Nếu status 200 nhưng không có data.success, vẫn xem là thành công
                const refreshedAvatarUrl = await refreshAvatar();

                // Cập nhật user state với filename từ refreshed avatar
                if (refreshedAvatarUrl && typeof setUser === 'function') {
                    try {
                        const url = new URL(refreshedAvatarUrl);
                        const filename = url.pathname.split('/').pop() || refreshedAvatarUrl;
                        setUser(prev => ({ ...prev, avatarURL: filename }));
                    } catch (e) {
                        setUser(prev => ({ ...prev, avatarURL: refreshedAvatarUrl }));
                    }
                }
                setSuccessMessage('Avatar đã được cập nhật thành công!');
                setShowSuccessModal(true);

                // Trigger Header to refresh avatar immediately
                window.dispatchEvent(new CustomEvent('avatarUpdated'));

                setTimeout(() => {
                    setSuccessMessage('');
                    setShowSuccessModal(false);
                }, 3000);
            } else {
                throw new Error(response.data?.message || 'Upload failed');
            }

        } catch (error) {
            setUploadError(error?.response?.data?.message || error?.message || 'Lỗi khi tải avatar');
        } finally {
            setUploadingAvatar(false);
            event.target.value = ''; // Reset input
        }
    }, [validateImageFile]);

    // Hàm đóng success modal
    const closeSuccessModal = useCallback(() => {
        setShowSuccessModal(false);
        setSuccessMessage('');
    }, []);
    useEffect(() => {
        if (!isAuthenticated || !profileData?.avatarURL) return;

        const refreshAvatar = async () => {
            try {
                const response = await authApi.getAvatar();

                if (response.isSuccess && response.data) {
                    setAvatarUrl(response.data);
                    return;
                }

                if (response.status === 200 && response.data) {
                    try {
                        new URL(response.data);
                        setAvatarUrl(response.data);
                    } catch (urlError) {
                    }
                }
            } catch (error) {
            }
        };

        const refreshInterval = setInterval(refreshAvatar, 45 * 60 * 1000);

        return () => clearInterval(refreshInterval);
    }, [isAuthenticated, profileData?.avatarURL]);

    return {
        // Avatar display
        avatarUrl,
        avatarLoading,
        getAvatarUrl,

        // Upload states
        uploadingAvatar,
        uploadError,
        setUploadError,
        successMessage,
        setSuccessMessage,
        showSuccessModal,
        closeSuccessModal,

        // Handlers
        handleFileSelect,
        refreshAvatar
    };
};

import { useState, useEffect, useCallback } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import profileApi from '../services/profile-api';
import authStore from '../stores/auth-store';

export const useProfileData = () => {
    const { username } = useParams();
    const navigate = useNavigate();
    const { isAuthenticated, user, setUser } = authStore();
    const isOwnProfile = !username || username === user?.username;

    const [loading, setLoading] = useState(true);
    const [error, setError] = useState('');
    const [profileData, setProfileData] = useState(null);

    // Fetch profile data
    useEffect(() => {
        const fetchProfile = async () => {
            try {
                setLoading(true);
                setError('');
                let response;

                if (isOwnProfile) {
                    response = await profileApi.getMyProfile();
                } else {
                    throw new Error('Chức năng xem hồ sơ người khác chưa được implement');
                }

                if (response.isSuccess) {
                    setProfileData(response.data);
                    if (isOwnProfile) {
                        setUser(response.data);
                    }
                } else {
                    setError(response.message);
                }
            } catch (err) {
                setError(err.message || 'Lỗi kết nối đến server');
            } finally {
                setLoading(false);
            }
        };

        if (isAuthenticated) {
            fetchProfile();
        }
    }, [username, isOwnProfile, setUser, isAuthenticated]);

    // Redirect if not authenticated
    useEffect(() => {
        if (!isAuthenticated) {
            navigate('/login', { replace: true });
        }
    }, [isAuthenticated, navigate]);

    return {
        profileData,
        loading,
        error,
        isOwnProfile,
        setProfileData,
        setError
    };
};

import { useState, useCallback, useEffect } from 'react';
import profileApi from '../services/profile-api';

export const useProfileEdit = (profileData, setProfileData) => {
    const [isEditing, setIsEditing] = useState(false);
    const [formData, setFormData] = useState({
        fullName: '',
        phoneNumber: '',
        address: '',
        email: '',
        dob: ''
    });
    const [formErrors, setFormErrors] = useState({});
    const [updateLoading, setUpdateLoading] = useState(false);

    // Update formData when profileData changes
    useEffect(() => {
        if (profileData) {
            setFormData({
                fullName: profileData.fullName || '',
                phoneNumber: profileData.phoneNumber || '',
                address: profileData.address || '',
                email: profileData.email || '',
                dob: profileData.dob ? profileData.dob.split('T')[0] : '' // Format date for input
            });
        }
    }, [profileData]);

    const validateProfile = useCallback(() => {
        const errors = {};
        if (!formData.fullName.trim()) errors.fullName = 'Vui lòng nhập họ tên';
        if (!formData.email.trim()) errors.email = 'Vui lòng nhập email';
        else if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(formData.email)) errors.email = 'Email không hợp lệ';
        if (!formData.phoneNumber.trim()) errors.phoneNumber = 'Vui lòng nhập số điện thoại';
        else if (!/^\d{10}$/.test(formData.phoneNumber)) errors.phoneNumber = 'Số điện thoại phải có 10 chữ số';
        if (!formData.address.trim()) errors.address = 'Vui lòng nhập địa chỉ';
        if (!formData.dob) errors.dob = 'Vui lòng chọn ngày sinh';
        else {
            const birthDate = new Date(formData.dob);
            const today = new Date();
            const age = today.getFullYear() - birthDate.getFullYear();
            if (age < 13) errors.dob = 'Bạn phải từ 13 tuổi trở lên';
            if (birthDate > today) errors.dob = 'Ngày sinh không được lớn hơn ngày hiện tại';
        }
        setFormErrors(errors);
        return Object.keys(errors).length === 0;
    }, [formData]);

    const handleProfileChange = useCallback((e) => {
        const { name, value } = e.target;
        setFormData((prev) => ({ ...prev, [name]: value }));
        setFormErrors((prev) => ({ ...prev, [name]: '' }));
    }, []);

    const handleUpdateProfile = useCallback(async (setError, setSuccessMessage) => {
        if (!validateProfile()) return;

        try {
            setUpdateLoading(true);
            setError('');
            setSuccessMessage('');

            const updateData = {
                fullName: formData.fullName,
                phoneNumber: formData.phoneNumber,
                address: formData.address,
                email: formData.email,
                dob: formData.dob // Thêm dob vào request
            };

            const result = await profileApi.updateProfile(updateData);

            if (result.isSuccess) {
                setProfileData(result.data);
                setSuccessMessage('Cập nhật thông tin thành công!');
                setTimeout(() => setSuccessMessage(''), 3000);
                setIsEditing(false);
            } else {
                setError(result.message);
            }
        } catch (error) {
            setError(error.message || 'Không thể cập nhật thông tin');
        } finally {
            setUpdateLoading(false);
        }
    }, [formData, profileData, validateProfile, setProfileData]);

    return {
        isEditing,
        setIsEditing,
        formData,
        formErrors,
        updateLoading,
        handleProfileChange,
        handleUpdateProfile
    };
};

import { useState, useEffect } from 'react';
import topicApi from '../services/topic-api';

export const useTopics = () => {
    const [topics, setTopics] = useState([]);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState('');

    // Mock data for development when API is not available
    const mockTopics = [
        { id: 1, name: 'Toán học', description: 'Câu hỏi về toán học cơ bản và nâng cao' },
        { id: 2, name: 'Văn học', description: 'Câu hỏi về văn học Việt Nam và thế giới' },
        { id: 3, name: 'Lịch sử', description: 'Câu hỏi về lịch sử Việt Nam và thế giới' },
        { id: 4, name: 'Địa lý', description: 'Câu hỏi về địa lý tự nhiên và kinh tế' },
        { id: 5, name: 'Khoa học', description: 'Câu hỏi về vật lý, hóa học, sinh học' },
        { id: 6, name: 'Tiếng Anh', description: 'Câu hỏi về ngữ pháp và từ vựng tiếng Anh' },
        { id: 7, name: 'Thể thao', description: 'Câu hỏi về thể thao trong nước và quốc tế' },
        { id: 8, name: 'Giải trí', description: 'Câu hỏi về phim ảnh, âm nhạc, game' },
    ];

    const loadTopics = async () => {
        try {
            setLoading(true);
            setError('');
            const result = await topicApi.getAll();

            if (result.success && Array.isArray(result.data)) {
                if (result.data.length > 0) {
                    setTopics(result.data);
                } else {
                    setTopics(mockTopics);
                }
            } else {
                setTopics(mockTopics);
            }
        } catch (err) {
            setError('Không thể tải danh sách chủ đề');
            setTopics(mockTopics);
        } finally {
            setLoading(false);
        }
    };

    const getTopicById = (topicId) => {
        return topics.find(topic => topic.id.toString() === topicId.toString());
    };

    const searchTopics = async (query) => {
        try {
            const result = await topicApi.search(query);
            return result.success && Array.isArray(result.data) ? result.data : [];
        } catch (err) {
            console.error('Error searching topics:', err);
            return [];
        }
    };

    const searchTopicsPaginated = async (keyword = '', page = 0, size = 10, sort = 'id,desc') => {
        try {
            const result = await topicApi.searchPaginated(keyword, page, size, sort);
            return result.success ? result.data : { content: [], page: 0, size: 10, totalElements: 0, totalPages: 0 };
        } catch (err) {
            return { content: [], page: 0, size: 10, totalElements: 0, totalPages: 0 };
        }
    };

    const refreshTopics = () => {
        loadTopics();
    };

    useEffect(() => {
        loadTopics();
    }, []);

    return {
        topics,
        loading,
        error,
        getTopicById,
        searchTopics,
        searchTopicsPaginated,
        refreshTopics,
        setError
    };
};

export default useTopics;

import { useState, useCallback, useEffect } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { FaEnvelope, FaExclamationCircle } from 'react-icons/fa';
import { IoArrowBackSharp } from 'react-icons/io5';
import { FaBrain } from 'react-icons/fa6';
import authApi from '../../services/auth-api';
import authStore from '../../stores/auth-store';
import Decoration from '../../components/Decoration';
import PopupNotification from '../../components/PopupNotification';
import { usePopup } from '../../hooks/use-popup';
import '../../styles/pages/auth/forgot-password.css';

function ForgotPassword() {
  const navigate = useNavigate();
  const [email, setEmail] = useState('');
  const [error, setError] = useState('');
  const { popup, showSuccess, showError, hidePopup } = usePopup();
  const [successMessage, setSuccessMessage] = useState('');
  const [isSubmitting, setIsSubmitting] = useState(false);
  const { isAuthenticated } = authStore();

  useEffect(() => {
    if (isAuthenticated) {
      navigate('/dashboard', { replace: true });
    }
  }, [isAuthenticated, navigate]);

  const handleChange = useCallback((e) => {
    setEmail(e.target.value);
    setError('');
    setSuccessMessage('');
  }, []);

  const validateEmail = useCallback(() => {
    if (!email.trim()) {
      setError('Vui lòng nhập email');
      return false;
    }
    if (!/\S+@\S+\.\S+/.test(email)) {
      setError('Email không hợp lệ');
      return false;
    }
    if (email.length > 255) {
      setError('Email quá dài (tối đa 255 ký tự)');
      return false;
    }
    return true;
  }, [email]);

  const handleSubmit = useCallback(
    async (e) => {
      e.preventDefault();
      if (!validateEmail()) return;

      setIsSubmitting(true);
      setError('');
      setSuccessMessage('');

      try {
        await authApi.forgotPassword(email);
        setSuccessMessage('Mật khẩu mới đã được gửi đến email của bạn!');
        showSuccess('Vui lòng kiểm tra hộp thư để lấy mật khẩu mới.');
      } catch (error) {
        const errorMessage = error.response?.data?.message || error.message || 'Có lỗi xảy ra, vui lòng thử lại';
        setError(errorMessage);
        showError(errorMessage);
      } finally {
        setIsSubmitting(false);
      }
    },
    [email, validateEmail]
  );

  return (
    <div className="fp-container">
      <Decoration />
      <PopupNotification
        type={popup.type}
        title={popup.title}
        message={popup.message}
        isVisible={popup.isVisible}
        onClose={hidePopup}
        showConfirm={popup.showConfirm}
        onConfirm={popup.onConfirm}
        onCancel={popup.onCancel}
        confirmText={popup.confirmText}
        cancelText={popup.cancelText}
      />
      <div className="fp-card">
        {!successMessage && (
          <Link to="/login" className="fp-back-button" aria-label="Quay lại trang đăng nhập">
            <IoArrowBackSharp size={20} />
          </Link>
        )}

        <div className="fp-header">
          <div className="fp-logo">
            <div className="fp-logo-icon">
              <FaBrain size={40} color="#dd797a" />
            </div>
            <span className="fp-logo-text">BrainGame</span>
          </div>
          <h1 className="fp-title">
            {successMessage ? 'Email đã được gửi' : 'Quên mật khẩu'}
          </h1>
        </div>

        {successMessage && (
          <div className="fp-success-container">
            <div className="fp-success-message">
              <span className="fp-success-icon">✓</span>
              <span>{successMessage}</span>
            </div>
            <div className="fp-success-actions">
              <Link to="/login" className="fp-submit-button">
                Quay lại trang đăng nhập
              </Link>
            </div>
          </div>
        )}

        {!successMessage && (
          <>

            <form className="fp-form" onSubmit={handleSubmit}>
              <div className="fp-form-group">
                <label className="fp-form-label" htmlFor="email">
                  <FaEnvelope className="fp-input-icon" />
                  <span>Email</span>
                </label>
                <div className="fp-input-wrapper">
                  <input
                    type="email"
                    id="email"
                    name="email"
                    className={`fp-form-input ${error ? 'fp-input-error' : ''}`}
                    value={email}
                    onChange={handleChange}
                    placeholder="Nhập email của bạn"
                    disabled={isSubmitting}
                    autoComplete="email"
                  />
                  {error && (
                    <div className="fp-error-message">
                      <FaExclamationCircle size={14} />
                      <span>{error}</span>
                    </div>
                  )}
                </div>
              </div>

              <button
                className={`fp-submit-button ${isSubmitting ? 'loading' : ''}`}
                type="submit"
                disabled={isSubmitting}
              >
                {isSubmitting ? (
                  <>
                    <div className="fp-loading-spinner-container">
                      <div className="fp-loading-spinner"></div>
                    </div>
                    <span className="fp-button-text">Đang gửi email...</span>
                  </>
                ) : (
                  <span>Gửi email đặt lại mật khẩu</span>
                )}
              </button>
            </form>

            <div className="fp-divider">
              <span>hoặc</span>
            </div>

            <div className="fp-login-link">
              <span>Đã nhớ mật khẩu?</span>
              <Link to="/login">Đăng nhập ngay</Link>
            </div>
          </>
        )}
      </div>
    </div>
  );
}

export default ForgotPassword;

import { useEffect, useState, useCallback } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { FaExclamationCircle, FaEye, FaEyeSlash, FaLock, FaUser } from 'react-icons/fa';
import authApi from '../../services/auth-api';
import '../../styles/pages/auth/login.css';
import { FaBrain } from "react-icons/fa6";
import Decoration from '../../components/Decoration';
import PopupNotification from '../../components/PopupNotification';
import { usePopup } from '../../hooks/use-popup';
import authStore from '../../stores/auth-store';
import { jwtDecode } from 'jwt-decode';

function Login() {
    const [formData, setFormData] = useState({ username: '', password: '' });
    const [errors, setErrors] = useState({});
    const [isSubmitting, setIsSubmitting] = useState(false);
    const { popup, showSuccess, showError, showWarning, hidePopup } = usePopup();
    const [showPassword, setShowPassword] = useState(false);
    const navigate = useNavigate();

    const isAuthenticated = authStore((state) => state.isAuthenticated);
    const user = authStore((state) => state.user);

    useEffect(() => {
        if (isAuthenticated && user?.role) {
            let redirectPath = '/dashboard';
            if (user.role === 'ADMIN') redirectPath = '/admin/dashboard';
            else if (user.role === 'TEACHER') redirectPath = '/teacher/dashboard';
            else if (user.role === 'PLAYER') redirectPath = '/dashboard';
            navigate(redirectPath, { replace: true });
        }
    }, [isAuthenticated, user, navigate]);

    const validateForm = useCallback(() => {
        const newErrors = {};
        const username = formData.username.trim();
        const password = formData.password;

        if (!username) {
            newErrors.username = 'Vui lòng nhập tên đăng nhập';
        } else if (username.length < 3) {
            newErrors.username = 'Tên đăng nhập phải có ít nhất 3 ký tự';
        }

        if (!password) {
            newErrors.password = 'Vui lòng nhập mật khẩu';
        } else if (password.length < 6) {
            newErrors.password = 'Mật khẩu phải có ít nhất 6 ký tự';
        }

        setErrors(newErrors);
        return Object.keys(newErrors).length === 0;
    }, [formData]);

    const handleChange = useCallback((e) => {
        const { name, value } = e.target;
        setFormData((prev) => ({ ...prev, [name]: value }));
        setErrors((prev) => ({ ...prev, [name]: '' }));
    }, []);

    const handleSubmit = useCallback(
        async (e) => {
            e.preventDefault();
            
            if (!validateForm()) {
                return;
            }

            setIsSubmitting(true);

            try {
                const response = await authApi.login({
                    username: formData.username,
                    password: formData.password,
                });
                
                const userData = response.data;
                const accessToken = userData?.accessToken;
                
                // Decode JWT to get typeAccount
                const decoded = jwtDecode(accessToken);
                const userRole = decoded?.typeAccount;
                
                showSuccess('Đăng nhập thành công!');
                
                let redirectPath = '/dashboard';
                if (userRole === 'ADMIN') redirectPath = '/admin/dashboard';
                else if (userRole === 'TEACHER') redirectPath = '/teacher/dashboard';
                else if (userRole === 'PLAYER') redirectPath = '/dashboard';
                
                setTimeout(() => navigate(redirectPath, { replace: true }), 1000);
            } catch (error) {
                const status = error.response?.status;
                const errorMessage = error.response?.data?.message || error.message || 'Đăng nhập thất bại';
                
                // Xử lý trường hợp email chưa được xác thực
                if (status === 403 && errorMessage.includes('Email not verified')) {
                    showWarning('Email chưa được xác thực. Vui lòng kiểm tra email và xác thực tài khoản trước khi đăng nhập.');
                } else {
                    showError(errorMessage);
                }
                setIsSubmitting(false);
            }
        },
        [formData, validateForm, navigate]
    );

    const togglePasswordVisibility = useCallback(() => {
        setShowPassword((prev) => !prev);
    }, []);

    return (
        <div className="login-container">
            <Decoration />
            <PopupNotification
                type={popup.type}
                title={popup.title}
                message={popup.message}
                isVisible={popup.isVisible}
                onClose={hidePopup}
                showConfirm={popup.showConfirm}
                onConfirm={popup.onConfirm}
                onCancel={popup.onCancel}
                confirmText={popup.confirmText}
                cancelText={popup.cancelText}
            />
            <div className="login-card">
                <div className="login-header">
                    <div className="login-logo">
                        <FaBrain size={40} color="#dd797a" />
                        <span className="logo-text">BrainGame</span>
                    </div>
                    <h1 className="login-title">Đăng nhập</h1>
                </div>

                <form className="login-form" onSubmit={handleSubmit}>
                    <div className="form-group">
                        <label className="login-label" htmlFor="username">
                            <FaUser size={16} color="#667eea" />
                            Tên đăng nhập
                        </label>
                        <div className="input-wrapper">
                            <input
                                type="text"
                                id="username"
                                name="username"
                                className={`input ${errors.username ? 'input-error' : ''}`}
                                value={formData.username}
                                onChange={handleChange}
                                placeholder="Nhập tên đăng nhập hoặc email"
                                disabled={isSubmitting}
                                autoComplete="username"
                            />
                        </div>
                        {errors.username && (
                            <div className="error-message">
                                <FaExclamationCircle size={16} color="#dc2626" />
                                <span className="error-text">{errors.username}</span>
                            </div>
                        )}
                    </div>

                    <div className="form-group">
                        <label className="login-label" htmlFor="password">
                            <FaLock size={16} color="#667eea" />
                            Mật khẩu
                        </label>
                        <div className="input-wrapper password-wrapper">
                            <input
                                type={showPassword ? 'text' : 'password'}
                                id="password"
                                name="password"
                                className={`input ${errors.password ? 'input-error' : ''}`}
                                value={formData.password}
                                onChange={handleChange}
                                placeholder="Nhập mật khẩu"
                                disabled={isSubmitting}
                                autoComplete="current-password"
                            />
                            <button
                                type="button"
                                className="password-toggle"
                                onClick={togglePasswordVisibility}
                                disabled={isSubmitting}
                                aria-label={showPassword ? 'Ẩn mật khẩu' : 'Hiện mật khẩu'}
                            >
                                {showPassword ? (
                                    <FaEyeSlash size={20} color="#718096" />
                                ) : (
                                    <FaEye size={20} color="#718096" />
                                )}
                            </button>
                        </div>
                        <div className="forgot-password">
                            <Link to="/forgot-password">Quên mật khẩu?</Link>
                        </div>
                        {errors.password && (
                            <div className="error-message">
                                <FaExclamationCircle size={16} color="#dc2626" />
                                <span className="error-text">{errors.password}</span>
                            </div>
                        )}
                    </div>

                    <button
                        className={`submit-button ${isSubmitting ? 'loading' : ''}`}
                        type="submit"
                        disabled={isSubmitting}
                    >
                        {isSubmitting ? (
                            <span className="button-text">Đang đăng nhập...</span>
                        ) : (
                            <span>Đăng nhập</span>
                        )}
                    </button>
                </form>

                <div className="divider">
                    <span>hoặc</span>
                </div>
                
                <div className="register-link">
                    <span>Chưa có tài khoản? </span>
                    <Link to="/register">Đăng ký ngay</Link>
                </div>
            </div>
        </div>
    );
}

export default Login;

