import { useState, useCallback, useEffect, useRef } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { FaEnvelope, FaExclamationCircle, FaHome, FaLock, FaPhoneAlt, FaUser, FaCalendarAlt } from 'react-icons/fa';
import { FaBrain } from 'react-icons/fa6';
import authApi from '../../services/auth-api';
import authStore from '../../stores/auth-store';
import Decoration from '../../components/Decoration';
import PopupNotification from '../../components/PopupNotification';
import { usePopup } from '../../hooks/use-popup';
import '../../styles/pages/auth/register.css';

function Register() {
  const navigate = useNavigate();
  const [formData, setFormData] = useState({
    username: '',
    fullName: '',
    email: '',
    phoneNumber: '',
    address: '',
    password: '',
    confirmPassword: '',
    dob: '',
  });
  const [errors, setErrors] = useState({});
  const [isSubmitting, setIsSubmitting] = useState(false);
  const { popup, showSuccess, showError, hidePopup } = usePopup();
  const firstErrorInputRef = useRef(null);
  const { isAuthenticated } = authStore();

  useEffect(() => {
    if (isAuthenticated) {
      navigate('/dashboard', { replace: true });
    }
  }, [isAuthenticated, navigate]);

  const handleChange = useCallback((e) => {
    const { name, value } = e.target;
    setFormData((prev) => ({ ...prev, [name]: value }));
    setErrors((prev) => ({ ...prev, [name]: '' }));
  }, []);

  const validateField = useCallback((name, value) => {
    switch (name) {
      case 'username':
        if (!value.trim()) return 'Vui lòng nhập tên người dùng';
        if (value.length < 3) return 'Tên người dùng phải có ít nhất 3 ký tự';
        return '';
      case 'fullName':
        if (!value.trim()) return 'Vui lòng nhập họ tên';
        return '';
      case 'email':
        if (!value) return 'Vui lòng nhập email';
        if (!/\S+@\S+\.\S+/.test(value)) return 'Email không hợp lệ';
        return '';
      case 'phoneNumber':
        if (!value.trim()) return 'Vui lòng nhập số điện thoại';
        if (!/^\d{10}$/.test(value)) return 'Số điện thoại phải có 10 chữ số';
        return '';
      case 'address':
        if (!value.trim()) return 'Vui lòng nhập địa chỉ';
        return '';
      case 'dob':
        if (!value) return 'Vui lòng nhập ngày sinh';
        const birthDate = new Date(value);
        const today = new Date();
        if (birthDate > today) return 'Ngày sinh không thể ở tương lai';
        return '';
      case 'password':
        if (!value) return 'Vui lòng nhập mật khẩu';
        if (value.length < 6) return 'Mật khẩu phải có ít nhất 6 ký tự';
        return '';
      case 'confirmPassword':
        if (value !== formData.password) return 'Mật khẩu không khớp';
        return '';
      default:
        return '';
    }
  }, [formData.password]);

  const validateForm = useCallback(() => {
    const newErrors = {};
    Object.keys(formData).forEach((key) => {
      const error = validateField(key, formData[key]);
      if (error) newErrors[key] = error;
    });
    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  }, [formData, validateField]);

  const handleSubmit = useCallback(
    async (e) => {
      e.preventDefault();
      if (!validateForm()) {
        const firstErrorKey = Object.keys(errors)[0];
        if (firstErrorKey) {
          firstErrorInputRef.current = document.getElementById(firstErrorKey);
          firstErrorInputRef.current?.focus();
        }
        return;
      }

      setIsSubmitting(true);

      try {
        await authApi.register({
          username: formData.username,
          fullName: formData.fullName,
          email: formData.email,
          phoneNumber: formData.phoneNumber,
          address: formData.address,
          dob: formData.dob,
          password: formData.password,
          confirm_password: formData.confirmPassword,
        });

        showSuccess('Đăng ký thành công! Vui lòng kiểm tra email để xác thực tài khoản.');
        setTimeout(() => navigate('/login'), 3000);
      } catch (error) {
        const errorMessage = error.response?.data?.message || error.message || 'Đã xảy ra lỗi. Vui lòng thử lại.';
        if (error.response?.status === 400) {
          const newErrors = {};
          if (error.response?.data?.field === 'email') {
            newErrors.email = 'Email đã tồn tại';
            firstErrorInputRef.current = document.getElementById('email');
          } else if (error.response?.data?.field === 'username') {
            newErrors.username = 'Tên người dùng đã tồn tại';
            firstErrorInputRef.current = document.getElementById('username');
          } else {
            showError(errorMessage);
          }
          setErrors((prev) => ({ ...prev, ...newErrors }));
          firstErrorInputRef.current?.focus();
        } else {
          showError(errorMessage);
        }
      } finally {
        setIsSubmitting(false);
      }
    },
    [formData, validateForm, navigate]
  );

  return (
    <div className="register-container">
      <Decoration />
      <PopupNotification
        type={popup.type}
        title={popup.title}
        message={popup.message}
        isVisible={popup.isVisible}
        onClose={hidePopup}
        showConfirm={popup.showConfirm}
        onConfirm={popup.onConfirm}
        onCancel={popup.onCancel}
        confirmText={popup.confirmText}
        cancelText={popup.cancelText}
      />
      <div className="register-card">
        <div className="register-header">
          <div className="register-logo">
            <div className="logo-icon">
              <FaBrain size={40} color="#dd797a" />
            </div>
            <span className="logo-text">BrainGame</span>
          </div>
          <h1 className="register-title">Đăng ký</h1>
        </div>

        <form className="register-form" onSubmit={handleSubmit}>
          {[
            { name: 'username', label: 'Tên người dùng', icon: FaUser, type: 'text', placeholder: 'Nhập tên người dùng' },
            { name: 'fullName', label: 'Họ tên', icon: FaUser, type: 'text', placeholder: 'Nhập họ tên' },
            { name: 'email', label: 'Email', icon: FaEnvelope, type: 'email', placeholder: 'example@email.com' },
            { name: 'phoneNumber', label: 'Số điện thoại', icon: FaPhoneAlt, type: 'tel', placeholder: 'Nhập số điện thoại (10 chữ số)' },
            { name: 'address', label: 'Địa chỉ', icon: FaHome, type: 'text', placeholder: 'Nhập địa chỉ' },
            { name: 'dob', label: 'Ngày sinh', icon: FaCalendarAlt, type: 'date', placeholder: 'Chọn ngày sinh' },
            { name: 'password', label: 'Mật khẩu', icon: FaLock, type: 'password', placeholder: 'Nhập mật khẩu' },
            { name: 'confirmPassword', label: 'Xác nhận mật khẩu', icon: FaLock, type: 'password', placeholder: 'Nhập lại mật khẩu' },
          ].map(({ name, label, icon: Icon, type, placeholder }) => (
            <div className="form-group" key={name}>
              <label className="register-label" htmlFor={name}>
                <Icon size={16} color="#667eea" />
                {label}
              </label>
              <input
                type={type}
                id={name}
                name={name}
                className={`input ${errors[name] ? 'input-error' : ''}`}
                value={formData[name]}
                onChange={handleChange}
                placeholder={placeholder}
                disabled={isSubmitting}
                autoComplete={name.includes('password') ? name : 'off'}
              />
              {errors[name] && (
                <div className="error-message">
                  <FaExclamationCircle size={16} color="#dc2626" />
                  {errors[name]}
                </div>
              )}
            </div>
          ))}

          <button className="submit-button" type="submit" disabled={isSubmitting}>
            {isSubmitting ? (
              <>
                <div className="loading-spinner"></div>
                Đang đăng ký...
              </>
            ) : (
              <>Đăng ký</>
            )}
          </button>
        </form>

        <div className="divider">
          <span>hoặc</span>
        </div>

        <div className="login-link">
          <span>Đã có tài khoản?</span>
          <Link to="/login">Đăng nhập ngay</Link>
        </div>
      </div>
    </div>
  );
}

export default Register;

import React, { useEffect, useState } from 'react';
import { useNavigate, useSearchParams } from 'react-router-dom';
import { FiCheckCircle, FiXCircle, FiLoader } from 'react-icons/fi';
import authApi from '../../services/auth-api';
import '../../styles/pages/verify-email.css';

const VerifyEmail = () => {
  const [searchParams] = useSearchParams();
  const navigate = useNavigate();
  const [status, setStatus] = useState('loading');
  const [message, setMessage] = useState('');

  useEffect(() => {
    const token = searchParams.get('token');

    if (!token) {
      setStatus('error');
      setMessage('Token xác thực không hợp lệ.');
      return;
    }

    handleVerifyEmail(token);
  }, [searchParams]);

  const handleVerifyEmail = async (token) => {
    try {
      const response = await authApi.verifyEmail(token);

      if (response.isSuccess) {
        setStatus('success');
        setMessage('Email đã được xác thực thành công!');

        setTimeout(() => {
          navigate('/login');
        }, 3000);
      } else {
        setStatus('error');
        setMessage(response.message || 'Xác thực email thất bại.');
      }
    } catch (error) {
      setStatus('error');
      setMessage(error.message || 'Có lỗi xảy ra khi xác thực email.');
    }
  };

  const handleGoToLogin = () => {
    navigate('/login');
  };

  const handleResendEmail = async () => {
    setStatus('loading');
    setMessage('Đang gửi lại email...');
    setTimeout(() => {
      setStatus('error');
      setMessage('Vui lòng liên hệ hỗ trợ để gửi lại email xác thực.');
    }, 1000);
  };

  return (
    <div className="verify-email-container">
      <div className="verify-email-card">
        {status === 'loading' && (
          <div className="verify-content loading">
            <FiLoader className="icon spin" />
            <h2>Đang xác thực email...</h2>
            <p>Vui lòng đợi trong giây lát.</p>
          </div>
        )}

        {status === 'success' && (
          <div className="verify-content success">
            <FiCheckCircle className="icon" />
            <h2>Xác thực thành công!</h2>
            <p>{message}</p>
            <p className="redirect-message">Bạn sẽ được chuyển đến trang đăng nhập trong vài giây...</p>
            <button onClick={handleGoToLogin} className="btn-primary">
              Đăng nhập ngay
            </button>
          </div>
        )}

        {status === 'error' && (
          <div className="verify-content error">
            <FiXCircle className="icon" />
            <h2>Xác thực thất bại</h2>
            <p>{message}</p>
            <div className="error-actions">
              <button onClick={handleGoToLogin} className="btn-primary">
                Đăng nhập
              </button>
              <button onClick={handleResendEmail} className="btn-secondary">
                Gửi lại email
              </button>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default VerifyEmail;

import { useNavigate } from 'react-router-dom';
import { FiTrendingUp, FiZap } from 'react-icons/fi';
import { GiBrain } from 'react-icons/gi';
import WelcomeMessage from '../../contexts/data/welcome-message';
import '../../styles/pages/dashboard/hero-section.css';

function HeroSection({ userName, stats }) {
    const navigate = useNavigate();

    return (
        <div className="dh-hero-section">
            <div className="dh-hero-content">
                <div className="dh-hero-left">
                    <h1 className="dh-hero-title">Xin chào, {userName}!</h1>
                    <div className="dh-hero-subtitle">
                        <WelcomeMessage userName={userName} />
                    </div>
                    <div className="dh-hero-actions">
                        <button
                            className="dh-hero-button primary"
                            onClick={() => navigate('/rooms')}
                        >
                            <FiZap /> Bắt đầu ngay
                        </button>
                        <button
                            className="dh-hero-button secondary"
                            onClick={() => navigate('/leaderboard')}
                        >
                            <FiTrendingUp /> Xem xếp hạng
                        </button>
                    </div>
                </div>
                <div className="dh-hero-right">
                    <div className="dh-hero-decoration">
                        <div className="dh-brain-icon-container">
                            <GiBrain className="dh-brain-icon-main" />
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
}

export default HeroSection;

import { useNavigate } from 'react-router-dom';
import authStore from '../../stores/auth-store';
import '../../styles/pages/dashboard/quick-actions-section.css';

const quickActions = [
    { title: 'Chơi ngay', desc: 'Bắt đầu trò chơi mới', action: (navigate) => navigate('/rooms') },
    { title: 'Xem bảng xếp hạng', desc: 'Top người chơi', action: (navigate) => navigate('/leaderboard') },
    { title: 'Hồ sơ cá nhân', desc: 'Xem thống kê của bạn', action: (navigate) => navigate('/profile') },
];

function QuickActionsSection({ onLogout }) {
    const navigate = useNavigate();
    const { user } = authStore();

    if (!user) {
        return <div className="qa-actions-section">Vui lòng đăng nhập để tiếp tục.</div>;
    }

    return (
        <div className="qa-actions-section">
            <h2 className="qa-section-title">Hành động nhanh</h2>
            <div className="qa-actions-grid">
                {quickActions.map((action, index) => (
                    <button
                        key={index}
                        className="qa-action-card"
                        onClick={() => action.action(navigate)}
                    >
                        <h3>{action.title}</h3>
                        <p>{action.desc}</p>
                    </button>
                ))}
            </div>
        </div>
    );
}

export default QuickActionsSection;

import React from 'react';
import { Link } from 'react-router-dom';
import '../styles/pages/error-page.css';
import authStore from '../stores/auth-store';

const ErrorPage = () => {
  const isAuthenticated = authStore((state) => state.isAuthenticated);
  const homePath = isAuthenticated ? '/dashboard' : '/';

  return (
    <div className="error-container">
      <div className="error-content">
        <h1 className="error-code">404</h1>
        <h2 className="error-title">Oops! Page Not Found</h2>
        <p className="error-message">
          It looks like the page you're looking for has vanished or never existed.
        </p>
        <Link to={homePath} className="error-button">
          <span className="button-text">Back to Home</span>
          <svg
            className="button-icon"
            xmlns="http://www.w3.org/2000/svg"
            fill="none"
            viewBox="0 0 24 24"
            stroke="currentColor"
          >
            <path
              strokeLinecap="round"
              strokeLinejoin="round"
              strokeWidth={2}
              d="M3 12l2-2m0 0l7-7 7 7M5 10v10a1 1 0 001 1h3m10-11l2 2m-2-2v10a1 1 0 01-1 1h-3m-6 0a1 1 0 001-1v-4a1 1 0 011-1h2a1 1 0 011 1v4a1 1 0 001 1m-6 0h6"
            />
          </svg>
        </Link>
      </div>
    </div>
  );
};

export default ErrorPage;

import React, {useState} from 'react';
import {Link} from 'react-router-dom';
import '../../styles/pages/footer/faqpage.css';
import {
    FaChevronDown,
    FaChevronUp,
    FaCreditCard,
    FaGamepad,
    FaHeadset,
    FaSearch,
    FaShieldAlt,
    FaTools,
    FaUser
} from 'react-icons/fa';

function FAQPage() {
    // State cho tìm kiếm và danh mục đang chọn
    const [searchTerm, setSearchTerm] = useState('');
    const [activeCategory, setActiveCategory] = useState(null);
    const [openQuestions, setOpenQuestions] = useState({});

    // Dữ liệu mẫu cho các câu hỏi thường gặp
    const faqCategories = [{
        id: 1, name: 'Tài khoản & Đăng nhập', icon: <FaUser/>, faqs: [{
            id: 101,
            question: 'Làm thế nào để tạo tài khoản mới?',
            answer: 'Để tạo tài khoản mới, hãy nhấp vào nút "Đăng ký" ở góc trên bên phải của trang web. Sau đó, điền thông tin cá nhân của bạn và làm theo hướng dẫn để hoàn tất quá trình đăng ký. Quá trình này chỉ mất khoảng 2 phút và bạn sẽ nhận được email xác nhận ngay sau khi hoàn tất.'
        }, {
            id: 102,
            question: 'Tôi quên mật khẩu, làm cách nào để đặt lại?',
            answer: 'Nếu bạn quên mật khẩu, hãy nhấp vào liên kết "Quên mật khẩu" trên trang đăng nhập. Nhập địa chỉ email đã đăng ký của bạn và chúng tôi sẽ gửi cho bạn hướng dẫn đặt lại mật khẩu. Đường link đặt lại mật khẩu có hiệu lực trong vòng 24 giờ.'
        }, {
            id: 103,
            question: 'Làm thế nào để thay đổi thông tin cá nhân?',
            answer: 'Để thay đổi thông tin cá nhân, hãy đăng nhập vào tài khoản của bạn, sau đó truy cập vào trang "Hồ sơ". Tại đây, bạn có thể chỉnh sửa thông tin cá nhân của mình như tên, ảnh đại diện, ngày sinh và các thông tin khác. Nhớ nhấn nút "Lưu thay đổi" sau khi hoàn tất.'
        }, {
            id: 104,
            question: 'Làm thế nào để xóa tài khoản của tôi?',
            answer: 'Để xóa tài khoản, vui lòng đăng nhập và truy cập vào trang "Cài đặt tài khoản". Tại đây, bạn sẽ tìm thấy tùy chọn "Xóa tài khoản" ở cuối trang. Lưu ý rằng hành động này không thể hoàn tác và tất cả dữ liệu của bạn sẽ bị xóa vĩnh viễn, bao gồm tiến trình học tập, điểm số và lịch sử thanh toán.'
        }]
    }, {
        id: 2, name: 'Trò chơi & Tính năng', icon: <FaGamepad/>, faqs: [{
            id: 201,
            question: 'Làm thế nào để bắt đầu chơi trò chơi?',
            answer: 'Để bắt đầu chơi trò chơi, hãy đăng nhập vào tài khoản của bạn, sau đó truy cập vào trang "Trò chơi". Tại đây, bạn sẽ thấy danh sách các trò chơi có sẵn. Chọn trò chơi bạn muốn chơi và nhấp vào nút "Chơi ngay". Mỗi trò chơi đều có hướng dẫn chi tiết trước khi bắt đầu.'
        }, {
            id: 202,
            question: 'Các trò chơi có miễn phí không?',
