    const handleSubmit = (e) => {
        e.preventDefault();
        // Xử lý gửi phản hồi ở đây

        // Reset form sau khi gửi
        setRating(0);
        setFeedbackType('');
        setFormData({
            name: '', email: '', subject: '', message: '', experience: ''
        });

        // Hiển thị thông báo thành công (trong thực tế sẽ có xử lý API)
        alert('Cảm ơn bạn đã gửi phản hồi!');
