export default HelpPage;

import React, { useEffect, useState } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import useGameStore from '../../stores/use-game-store';
import authStore from '../../stores/auth-store';
import socketService from '../../services/socket-service';
import { useTheme } from '../../contexts/theme-context';
import '../../styles/pages/game/game-play.css';

import {
    FiCheckCircle,
    FiXCircle,
    FiClock,
    FiUsers,
    FiAward,
    FiChevronRight,
    FiBarChart2,
    FiMessageCircle
} from 'react-icons/fi';

const GamePlay = () => {
    const { roomCode } = useParams();
    const navigate = useNavigate();
    const { theme } = useTheme();
    const currentUser = authStore((state) => state.user);

    const {
        isGameActive,
        isGameStarting,
        isGameFinished,
        currentQuestion,
        answerResult,
        leaderboard,
        timeRemaining,
        hasAnswered,
        selectedAnswer,
        error,
        initGame,
        submitAnswer,
        nextQuestion,
        setupSocketListeners,
        cleanupSocketListeners,
        reset
    } = useGameStore();

    const [localSelectedAnswer, setLocalSelectedAnswer] = useState(null);

    useEffect(() => {
        if (roomCode && currentUser?.id) {
            // Khởi tạo trạng thái game
            initGame(roomCode, false); // Giả sử không phải host hiện tại
            
            // Thiết lập các listener socket
            setupSocketListeners();
            
            // Tham gia phòng nếu chưa tham gia
            if (!socketService.getJoinedRooms().has(roomCode)) {
                socketService.joinRoom(roomCode, (response) => {
                    if (response.success) {
                    } else {
                    }
                });
            }
        }

        return () => {
            cleanupSocketListeners();
            reset();
        };
    }, [roomCode, currentUser?.id]);

    useEffect(() => {
        // Đặt lại trạng thái cục bộ khi câu hỏi mới đến
        setLocalSelectedAnswer(null);
    }, [currentQuestion]);

    const handleAnswerClick = (answerId) => {
        if (!hasAnswered) {
            setLocalSelectedAnswer(answerId);
        }
    };

    const handleSubmitAnswer = () => {
        if (localSelectedAnswer !== null && !hasAnswered) {
            submitAnswer(localSelectedAnswer);
        }
    };

    const handleNextQuestion = () => {
        nextQuestion();
    };

    const handleViewResults = () => {
        navigate(`/results/${roomCode}`);
    };

    // Hiển thị trạng thái đang tải
    if (isGameStarting || (!isGameActive && !isGameFinished)) {
        return (
            <div className={`game-play-container ${theme}`}>
                <div className="loading-screen">
                    <div className="loading-spinner"></div>
                    <p>{isGameStarting ? 'Starting game...' : 'Waiting for game to start...'}</p>
                </div>
            </div>
        );
    }

    // Hiển thị trạng thái chờ câu hỏi
    if (isGameActive && !currentQuestion) {
        return (
            <div className={`game-play-container ${theme}`}>
                <div className="loading-screen">
                    <div className="loading-spinner"></div>
                    <p>Loading next question...</p>
                </div>
            </div>
        );
    }

    // Hiển thị trạng thái lỗi
    if (error) {
        return (
            <div className={`game-play-container ${theme}`}>
                <div className="error-screen">
                    <h2>Something went wrong</h2>
                    <p>{error}</p>
                    <button onClick={() => navigate('/dashboard')}>Go to Dashboard</button>
                </div>
            </div>
        );
    }

    // Hiển thị màn hình kết thúc game
    if (isGameFinished) {
        return (
            <div className={`game-play-container ${theme}`}>
                <div className="game-over-screen">
                    <h2>Game Over!</h2>
                    <p>The game has finished. Let's see the final results.</p>
                    <div className="final-rankings">
                        <h3><FiAward /> Final Rankings</h3>
                        <ul>
                            {leaderboard.map((player, index) => (
                                <li key={player.userId}>
                                    <span className={`rank-${index + 1}`}>#{index + 1}</span>
                                    <span className="player-name">{player.username}</span>
                                    <span className="player-score">{player.totalScore || 0} pts</span>
                                </li>
                            ))}
                        </ul>
                    </div>
                    <button className="view-results-button" onClick={handleViewResults}>
                        <FiBarChart2 /> View Detailed Results
                    </button>
                </div>
            </div>
        );
    }

    // Hiển thị màn hình kết quả câu hỏi
    if (answerResult && hasAnswered) {
        const isCorrect = answerResult.isCorrect;
        return (
            <div className={`game-play-container ${theme}`}>
                <div className={`question-result-screen ${isCorrect ? 'correct' : 'incorrect'}`}>
                    <div className="result-icon">
                        {isCorrect ? <FiCheckCircle /> : <FiXCircle />}
                    </div>
                    <h2>{isCorrect ? 'Correct!' : 'Incorrect!'}</h2>
                    <p>You earned {answerResult.score || 0} points.</p>
                    <div className="leaderboard-preview">
                        <h4><FiUsers /> Leaderboard</h4>
                        <ul>
                            {leaderboard.slice(0, 5).map((player, index) => (
                                <li key={player.userId}>
                                    <span>#{index + 1} {player.username}</span>
                                    <span>{player.totalScore || 0}</span>
                                </li>
                            ))}
                        </ul>
                    </div>
                    <button className="next-question-button" onClick={handleNextQuestion}>
                        Next <FiChevronRight />
                    </button>
                </div>
            </div>
        );
    }

    // Hiển thị màn hình chơi game chính (câu hỏi và câu trả lời)
    return (
        <div className={`game-play-container ${theme}`}>
            <div className="game-header">
                <div className="question-counter">
                    Question {currentQuestion.sequence} of {currentQuestion.totalQuestions}
                </div>
                <div className="timer">
                    <FiClock />
                    <span>{timeRemaining}s</span>
                </div>
                <div className="player-score">
                    <FiAward />
                    <span>{leaderboard.find(p => p.userId === currentUser?.id)?.totalScore || 0} pts</span>
                </div>
            </div>

            <div className="question-section">
                <h2>{currentQuestion.content}</h2>
                {currentQuestion.imageUrl && (
                    <div className="question-image">
                        <img src={currentQuestion.imageUrl} alt="Question visual aid" />
                    </div>
                )}
            </div>

            <div className="answers-section">
                {currentQuestion.answers.map((answer, index) => (
                    <button
                        key={index}
                        className={`answer-option color-${index} ${localSelectedAnswer === index ? 'selected' : ''}`}
                        onClick={() => handleAnswerClick(index)}
                        disabled={hasAnswered}
                    >
                        <span className="answer-text">{answer.content}</span>
                    </button>
                ))}
            </div>

            <div className="game-footer">
                {!hasAnswered ? (
                    <button
                        className="submit-answer-button"
                        onClick={handleSubmitAnswer}
                        disabled={localSelectedAnswer === null}
                    >
                        Submit Answer
                    </button>
                ) : (
                    <div className="waiting-for-results">
                        <div className="loading-spinner-small"></div>
                        <p>Waiting for other players...</p>
                    </div>
                )}
            </div>
        </div>
    );
};

export default GamePlay;

import { useState } from 'react';
import { FaExclamationTriangle } from 'react-icons/fa';
import { FiEdit, FiMail, FiUser, FiCalendar, FiCamera, FiSettings, FiSave, FiX, FiCheck, FiLock, FiEye, FiEyeOff, FiRefreshCw, FiUpload, FiLoader } from 'react-icons/fi';
import authStore from '../stores/auth-store';
import useDocumentTitle from '../hooks/use-document-title';
import { useProfileData } from '../hooks/use-profile-data';
import { useProfileEdit } from '../hooks/use-profile-edit';
import { usePasswordChange } from '../hooks/use-password-change';
import { useAvatarUpload } from '../hooks/use-avatar-upload';
import ProfileHeader from '../components/Profile/ProfileHeader';
import ProfileDetails from '../components/Profile/ProfileDetails';
import ProfileStats from '../components/Profile/ProfileStats';
import SuccessModal from '../components/Profile/SuccessModal';
import EditActions from '../components/Profile/EditActions';
import PasswordChangeModal from '../components/Profile/PasswordChangeModal';
import '../styles/pages/profile.css';
import Decoration from '../components/Decoration';

function Profile() {
    const { isAuthenticated, user, setUser } = authStore();
    const [error, setError] = useState('');
    const [successMessage, setSuccessMessage] = useState('');
    const [showPasswordModal, setShowPasswordModal] = useState(false);

    // Custom hooks
    const { profileData, loading, isOwnProfile, setProfileData, setError: setProfileError } = useProfileData();
    const profileEdit = useProfileEdit(profileData, setProfileData);
    const passwordChange = usePasswordChange();
    const avatarUpload = useAvatarUpload(profileData);

    useDocumentTitle(isOwnProfile ? 'Hồ sơ của tôi' : `Hồ sơ của ${profileData?.username}`);

    // Handlers
    const handleUpdateProfile = () => {
        profileEdit.handleUpdateProfile(setError, setSuccessMessage);
    };

    const handleChangePassword = () => {
        passwordChange.handleChangePassword(setError, setSuccessMessage);
    };

    const handleOpenPasswordModal = () => {
        setShowPasswordModal(true);
    };

    const handleClosePasswordModal = () => {
        setShowPasswordModal(false);
        // Reset form errors when closing
        passwordChange.setFormErrors({});
    };

    const handlePasswordSubmit = () => {
        passwordChange.handleChangePassword(setError, setSuccessMessage);
        if (!passwordChange.updateLoading) {
            setShowPasswordModal(false);
        }
    };

    if (loading) {
        return (
            <div className="pf-loading-container">
                <FiLoader className="pf-loading-spinner" />
                <p>Đang tải thông tin...</p>
            </div>
        );
    }

    if (error) {
        return (
            <div className="pf-error-container">
                <p className="pf-error-message">{error}</p>
                <button onClick={() => window.history.back()} className="pf-back-button">
                    Quay lại trang chủ
                </button>
            </div>
        );
    }

    return (
        <div className="pf-layout">
            <Decoration />
            <main className="pf-content">
                {(error || avatarUpload.uploadError) && (
                    <div className="pf-error-container">
                        <FaExclamationTriangle />
                        <span>{error || avatarUpload.uploadError}</span>
                    </div>
                )}

                {profileData && (
                    <div className="pf-profile-container">
                        {/* Profile Header */}
                        <ProfileHeader
                            profileData={profileData}
                            isOwnProfile={isOwnProfile}
                            avatarUrl={avatarUpload.avatarUrl}
                            avatarLoading={avatarUpload.avatarLoading}
                            isEditing={profileEdit.isEditing}
                            isChangingPassword={passwordChange.isChangingPassword}
                            setIsEditing={profileEdit.setIsEditing}
                            setIsChangingPassword={passwordChange.setIsChangingPassword}
                            handleFileSelect={(event) => avatarUpload.handleFileSelect(event, setUser)}
                            uploadingAvatar={avatarUpload.uploadingAvatar}
                            handleOpenPasswordModal={handleOpenPasswordModal}
                        />

                        {/* Profile Details */}
                        <ProfileDetails
                            profileData={profileData}
                            isOwnProfile={isOwnProfile}
                            isEditing={profileEdit.isEditing}
                            formData={profileEdit.formData}
                            formErrors={profileEdit.formErrors}
                            handleProfileChange={profileEdit.handleProfileChange}
                        />

                        {/* Edit Actions */}
                        <EditActions
                            isEditing={profileEdit.isEditing}
                            isChangingPassword={passwordChange.isChangingPassword}
                            updateLoading={profileEdit.updateLoading || passwordChange.updateLoading}
                            handleUpdateProfile={handleUpdateProfile}
                            handleOpenPasswordModal={handleOpenPasswordModal}
                            setIsEditing={profileEdit.setIsEditing}
                            setIsChangingPassword={passwordChange.setIsChangingPassword}
                            setFormErrors={() => { }} // Có thể implement sau
                        />

                        {/* Profile Stats */}
                        <ProfileStats profileData={profileData} />
                    </div>
                )}

                {/* Success Modal for Avatar Upload */}
                <SuccessModal
                    show={avatarUpload.showSuccessModal}
                    message={avatarUpload.successMessage}
                    onClose={avatarUpload.closeSuccessModal}
                />

                {/* Password Change Modal */}
                <PasswordChangeModal
                    showModal={showPasswordModal}
                    onClose={handleClosePasswordModal}
                    passwordData={passwordChange.passwordData}
                    formErrors={passwordChange.formErrors}
                    updateLoading={passwordChange.updateLoading}
                    handlePasswordChange={passwordChange.handlePasswordChange}
                    handleSubmit={handlePasswordSubmit}
                />
            </main>
        </div>
    );
}

