import { create } from 'zustand';
import authApi from '../services/auth-api';
import { jwtDecode } from 'jwt-decode';
import Cookies from 'js-cookie';

const authStore = create((set) => ({
  user: null,
  isAuthenticated: false,
  isLoading: false,
  error: null,
  typeAccount: null, // PLAYER, TEACHER, ADMIN

  setUser: (user) =>
      set((state) => {
        return {
          user,
          isAuthenticated: !!user,
          typeAccount: user?.role || null,
          error: null,
        };
      }),

  clearUser: () =>
      set({
        user: null,
        isAuthenticated: false,
        typeAccount: null,
        error: null,
      }),

  setLoading: (isLoading) => set({ isLoading }),

  setError: (error) => set({ error }),

  initialize: async () => {
    // Kiểm tra token từ Cookies trước, nếu không có thì từ sessionStorage
    let token = Cookies.get('accessToken');
    let refreshToken = Cookies.get('refreshToken');

    if (!token) {
      token = sessionStorage.getItem('accessToken');
      refreshToken = sessionStorage.getItem('refreshToken');
      // Nếu có token từ sessionStorage, đồng bộ lại vào Cookies
      if (token && refreshToken) {
        Cookies.set('accessToken', token, { expires: 7, secure: true, sameSite: 'strict' });
        Cookies.set('refreshToken', refreshToken, { expires: 7, secure: true, sameSite: 'strict' });
      }
    }

    if (!token || !refreshToken) {
      set({ user: null, isAuthenticated: false });
      return;
    }

    try {
      let decoded;
      try {
        decoded = jwtDecode(token);
      } catch (decodeError) {
        // Token không hợp lệ, clear và return
        Cookies.remove('accessToken');
        Cookies.remove('refreshToken');
        sessionStorage.removeItem('accessToken');
        sessionStorage.removeItem('refreshToken');
        set({ user: null, isAuthenticated: false });
        return;
      }

      if (decoded.exp * 1000 < Date.now()) {
        // Token hết hạn, thử refresh
        const refreshResponse = await authApi.refreshToken();
        const { accessToken: newAccessToken, refreshToken: newRefreshToken } = refreshResponse.data.data;

        // Cập nhật token mới
        Cookies.set('accessToken', newAccessToken, { expires: 7, secure: true, sameSite: 'strict' });
        Cookies.set('refreshToken', newRefreshToken, { expires: 7, secure: true, sameSite: 'strict' });
        sessionStorage.setItem('accessToken', newAccessToken);
        sessionStorage.setItem('refreshToken', newRefreshToken);

        token = newAccessToken;
      }

      // Set role from decoded token immediately
      const userWithRole = { role: decoded.typeAccount };
      set({ 
        user: userWithRole, 
        isAuthenticated: true, 
        typeAccount: decoded.typeAccount,
        isLoading: true 
      });
      
      // Then fetch full user data
      try {
        const response = await authApi.getUser();
        const fullUserWithRole = { ...response.data, role: decoded.typeAccount };
        set({ 
          user: fullUserWithRole, 
          isAuthenticated: true, 
          typeAccount: decoded.typeAccount,
          isLoading: false 
        });
      } catch (getUserError) {
        // If getUser fails, keep the basic user with role
        set({ isLoading: false });
      }
    } catch (error) {
      // Nếu refresh thất bại, clear token và chuyển về login
      Cookies.remove('accessToken');
      Cookies.remove('refreshToken');
      sessionStorage.removeItem('accessToken');
      sessionStorage.removeItem('refreshToken');
      // Chỉ set error nếu đã có token (đã từng đăng nhập)
      if (token) {
        set({ user: null, isAuthenticated: false, error: error.message, isLoading: false });
      } else {
        set({ user: null, isAuthenticated: false, isLoading: false });
      }
    }
  },

  login: async (username, password) => {
    try {
      set({ isLoading: true, error: null });
      const response = await authApi.login({ username, password });
      const { accessToken, refreshToken, ...user } = response.data.data;

      // Decode token to get typeAccount
      const decoded = jwtDecode(accessToken);
      const userWithRole = { ...user, role: decoded.typeAccount };

      // Lưu token vào Cookies và sessionStorage để persist khi reload
      Cookies.set('accessToken', accessToken, { expires: 7, secure: true, sameSite: 'strict' });
      Cookies.set('refreshToken', refreshToken, { expires: 7, secure: true, sameSite: 'strict' });
      sessionStorage.setItem('accessToken', accessToken);
      sessionStorage.setItem('refreshToken', refreshToken);

      set({ 
        user: userWithRole, 
        isAuthenticated: true, 
        typeAccount: decoded.typeAccount,
        isLoading: false 
      });
      return response;
    } catch (error) {
      set({ isLoading: false, error: error.message });
      throw error;
    }
  },

  logout: async () => {
    try {
      set({ isLoading: true, error: null });
      await authApi.logout();
      Cookies.remove('accessToken');
      Cookies.remove('refreshToken');
      sessionStorage.removeItem('accessToken');
      sessionStorage.removeItem('refreshToken');
      set({ 
        user: null, 
        isAuthenticated: false, 
        typeAccount: null,
        isLoading: false 
      });
    } catch (error) {
      set({ isLoading: false, error: error.message });
      throw error;
    }
  },
}));

export default authStore;

import { create } from 'zustand';
import socketService from '../services/socket-service';

/**
 * Game Store - Real-time game state management
 */
const useGameStore = create((set, get) => ({
    // Game state
    isGameActive: false,
    isGameStarting: false,
    isGameFinished: false,

    // Current question state
    currentQuestion: null,
    currentQuestionIndex: 0,
    totalQuestions: 0,

    // Timer state
    timeRemaining: 0,
    timerInterval: null,
    questionStartTime: null,

    // Player answers
    selectedAnswer: null,
    hasAnswered: false,
    answerResult: null,

    // Leaderboard
    players: [],
    leaderboard: [],

    // Room info
    roomId: null,
    isHost: false,

    // Loading & errors
    isLoading: false,
    error: null,

    // ==================== GAME ACTIONS ====================

    /**
     * Initialize game state for a room
     */
    initGame: (roomId, isHost = false) => {
        set({
            roomId,
            isHost,
            isGameActive: false,
            isGameStarting: false,
            isGameFinished: false,
            currentQuestion: null,
            currentQuestionIndex: 0,
            selectedAnswer: null,
            hasAnswered: false,
            answerResult: null,
            error: null
        });
    },

    /**
     * Start the game (host only)
     */
    startGame: () => {
        const { roomId, isHost } = get();

        if (!isHost) {
            set({ error: 'Only host can start the game' });
            return;
        }
        set({ isGameStarting: true, error: null });

        socketService.startGame(roomId);
    },

    /**
     * Handle game started event
     */
    onGameStarted: (data) => {
        set({
            isGameActive: true,
            isGameStarting: false,
            isGameFinished: false,
            currentQuestionIndex: 0
        });
    },

    /**
     * Load next question
     */
    loadNextQuestion: (questionData) => {
        const { currentQuestionIndex } = get();
        // Stop previous timer
        get().stopTimer();

        set({
            currentQuestion: questionData.question || questionData,
            currentQuestionIndex: currentQuestionIndex + 1,
            totalQuestions: questionData.totalQuestions || get().totalQuestions,
            selectedAnswer: null,
            hasAnswered: false,
            answerResult: null,
            questionStartTime: Date.now()
        });

        // Start timer for this question
        if (questionData.question?.timeLimit) {
            get().startTimer(questionData.question.timeLimit);
        }
    },

    /**
     * Submit answer for current question
     */
    submitAnswer: (answerId) => {
        const {
            roomId,
            currentQuestion,
            hasAnswered,
            questionStartTime
        } = get();

        if (hasAnswered) {
            return;
        }

        if (!currentQuestion) {
            return;
        }

        const timeTaken = Date.now() - questionStartTime;
        set({
            selectedAnswer: answerId,
            hasAnswered: true
        });

        socketService.submitAnswer(
            roomId,
            currentQuestion.questionId,
            answerId,
            timeTaken
        );

        // Stop timer after answer
        get().stopTimer();
    },

    /**
     * Handle answer result from server
     */
    onAnswerResult: (result) => {
        set({
            answerResult: result
        });

        // Update player score in leaderboard
        const { players } = get();
        const updatedPlayers = players.map(player => {
            if (player.userId === result.userId) {
                return {
                    ...player,
                    score: result.score,
                    totalScore: result.totalScore
                };
            }
            return player;
        });

        set({ players: updatedPlayers });
        get().updateLeaderboard();
    },

    /**
     * Request next question (host only)
     */
    nextQuestion: () => {
        const { roomId, isHost } = get();

        if (!isHost) {
            return;
        }
        socketService.nextQuestion(roomId);

        set({
            selectedAnswer: null,
            hasAnswered: false,
            answerResult: null
        });
    },

    /**
     * Handle game finished
     */
    onGameFinished: (data) => {
        get().stopTimer();

        set({
            isGameActive: false,
            isGameFinished: true,
            currentQuestion: null
        });

        get().updateLeaderboard();
    },

    /**
     * End/leave game
     */
    endGame: () => {
        get().stopTimer();

        set({
            isGameActive: false,
            isGameFinished: false,
            currentQuestion: null,
            currentQuestionIndex: 0,
            selectedAnswer: null,
            hasAnswered: false,
            answerResult: null,
            players: [],
            leaderboard: []
        });
    },

    // ==================== TIMER ACTIONS ====================

    /**
     * Start countdown timer for question
     */
    startTimer: (duration) => {
        // Clear existing timer
        get().stopTimer();

        set({ timeRemaining: duration });

        const interval = setInterval(() => {
            const { timeRemaining } = get();

            if (timeRemaining <= 0) {
                get().stopTimer();
                get().onTimerExpired();
            } else {
                set({ timeRemaining: timeRemaining - 1 });
            }
        }, 1000);

        set({ timerInterval: interval });
    },

    /**
     * Stop timer
     */
    stopTimer: () => {
        const { timerInterval } = get();

        if (timerInterval) {
            clearInterval(timerInterval);
            set({ timerInterval: null });
        }
    },

    /**
     * Handle timer expiration
     */
    onTimerExpired: () => {
        const { hasAnswered, isHost } = get();
        if (!hasAnswered) {
            // Auto-submit null answer if player didn't answer
            set({ hasAnswered: true });
        }

        // Host auto-advances to next question
        if (isHost) {
            setTimeout(() => {
                get().nextQuestion();
            }, 3000); // 3 second delay to show results
        }
    },

    // ==================== PLAYER ACTIONS ====================

    /**
     * Update players list
     */
    updatePlayers: (players) => {
        set({ players });
        get().updateLeaderboard();
    },

    /**
     * Add player to game
     */
    addPlayer: (player) => {
        const { players } = get();
        const exists = players.find(p => p.userId === player.userId);

        if (!exists) {
            set({ players: [...players, { ...player, score: 0, totalScore: 0 }] });
            get().updateLeaderboard();
        }
    },

    /**
     * Remove player from game
     */
    removePlayer: (userId) => {
        const { players } = get();
        set({
            players: players.filter(p => p.userId !== userId)
        });
        get().updateLeaderboard();
    },

    /**
     * Update leaderboard based on scores
     */
    updateLeaderboard: () => {
        const { players } = get();

        const sorted = [...players].sort((a, b) => {
            return (b.totalScore || 0) - (a.totalScore || 0);
        });

        set({ leaderboard: sorted });
    },

    // ==================== SOCKET EVENT SETUP ====================

    /**
     * Setup socket event listeners for game
     */
    setupSocketListeners: () => {
        // Game events
        socketService.onGameStarted((data) => {
            get().onGameStarted(data);
        });

        socketService.onNextQuestion((data) => {
            get().loadNextQuestion(data);
        });

        socketService.onAnswerSubmitted((result) => {
            get().onAnswerResult(result);
        });

        socketService.onGameFinished((data) => {
            get().onGameFinished(data);
        });

        // Player events
        socketService.onPlayerJoined((data) => {
            get().addPlayer(data);
        });

        socketService.onPlayerLeft((data) => {
            get().removePlayer(data.userId);
        });

        socketService.onRoomPlayers((data) => {
            get().updatePlayers(data.players);
        });

        // Error handling
        socketService.onError((error) => {
            set({ error: error.message || 'An error occurred' });
        });
    },

    /**
     * Cleanup socket listeners
     */
    cleanupSocketListeners: () => {
        // Remove all game-related listeners
        socketService.off('game-started');
        socketService.off('next-question');
        socketService.off('answer-submitted');
        socketService.off('game-finished');
        socketService.off('player-joined');
        socketService.off('player-left');
        socketService.off('room-players');
    },

    // ==================== UTILITY ====================

    /**
     * Reset game store to initial state
     */
    reset: () => {
        get().stopTimer();
        get().cleanupSocketListeners();

        set({
            isGameActive: false,
            isGameStarting: false,
            isGameFinished: false,
            currentQuestion: null,
            currentQuestionIndex: 0,
            totalQuestions: 0,
            timeRemaining: 0,
            timerInterval: null,
            questionStartTime: null,
            selectedAnswer: null,
            hasAnswered: false,
            answerResult: null,
            players: [],
            leaderboard: [],
            roomId: null,
            isHost: false,
            isLoading: false,
            error: null
        });
    },

    /**
     * Clear error
     */
    clearError: () => set({ error: null })
}));

export default useGameStore;

import { create } from 'zustand';
import roomApi from '../services/room-api';
import socketService from '../services/socket-service';
import socketManager from '../utils/socket-manager';

/**
 * ✅ ĐÃ SỬA: Kho lưu trữ phòng với cập nhật thời gian thực Socket.IO
 * Được chuẩn hóa để phù hợp với kiến trúc Kahoot/Quizizz
 */
const useRoomStore = create((set, get) => ({
    // Trạng thái phòng
    currentRoom: null,
    rooms: [],
    roomPlayers: [],
    myRooms: [],
    isLoading: false,
    loading: false,
    error: null,
    isConnectedToRoom: false,
    isSubscribedToRoomList: false,

    // Trạng thái hoạt hình để phản hồi giao diện người dùng
    animatingRooms: new Set(),
    newRoomIds: new Set(),

    // Hành động phòng
    setCurrentRoom: (room) => set({ currentRoom: room }),

    clearCurrentRoom: () => {
        const state = get();
        if (state.currentRoom) {
            get().disconnectFromRoom(state.currentRoom.id);
        }
        set({
            currentRoom: null,
            roomPlayers: [],
            isConnectedToRoom: false,
            error: null  // ✅ Xóa mọi lỗi hiện có khi xóa phòng
        });

        // Buộc làm mới danh sách phòng khi xóa phòng hiện tại
        setTimeout(() => {
            get().fetchRooms();
        }, 100);
    },

    setLoading: (isLoading) => set({ isLoading, loading: isLoading }),
    setError: (error) => set({ error }),
    setRoomPlayers: (players) => set({ roomPlayers: players }),
    clearError: () => set({ error: null }),

    // Trợ giúp hoạt hình
    addAnimatingRoom: (roomId) => {
        set(state => ({
            animatingRooms: new Set(state.animatingRooms).add(roomId)
        }));

        setTimeout(() => {
            set(state => {
                const newSet = new Set(state.animatingRooms);
                newSet.delete(roomId);
                return { animatingRooms: newSet };
            });
        }, 1000);
    },

    addNewRoom: (roomId) => {
        set(state => ({
            newRoomIds: new Set(state.newRoomIds).add(roomId)
        }));

        setTimeout(() => {
            set(state => {
                const newSet = new Set(state.newRoomIds);
                newSet.delete(roomId);
                return { newRoomIds: newSet };
            });
        }, 3000);
    },

    // ========== ĐĂNG KÝ THỜI GIAN THỰC SOCKET.IO ==========

    subscribeToRoomList: async () => {
        try {
            const state = get();
            if (state.isSubscribedToRoomList) {
                return;
            }

            await socketManager.initialize();

            // ✅ Đảm bảo socket được kết nối trước khi đăng ký
            if (!socketManager.isConnected()) {
                return;
            }

            socketService.subscribeToRoomList((message) => {

                if (message.type === 'CREATE_ROOM') {
                    const { room } = message.data;
                    set(state => {
                        const exists = state.rooms.find(r => r.id === room.id);
                        if (!exists) {
                            get().addNewRoom(room.id);
                            get().addAnimatingRoom(room.id);
                            return {
                                rooms: [...state.rooms, room]
                            };
                        }
                        return state;
                    });
                } else if (message.type === 'ROOM_DELETED') {
                    const { roomId } = message.data;
                    get().addAnimatingRoom(roomId);

                    setTimeout(() => {
                        set(state => ({
                            rooms: state.rooms.filter(room => room.id !== roomId)
                        }));
                    }, 500);
                } else if (message.type === 'ROOM_UPDATED') {
                    const { room } = message.data;

                    set(state => {
                        const updatedRooms = state.rooms.map(r => {
                            if (r.id === room.id) {
                                return { ...r, ...room };
                            }
                            return r;
                        });

                        return { rooms: updatedRooms };
                    });
                }
            });

            set({ isSubscribedToRoomList: true });
        } catch (error) {
            set({ error: 'Không thể kết nối real-time updates' });
        }
    },

    unsubscribeFromRoomList: () => {
        socketService.unsubscribeFromRoomList();
        set({ isSubscribedToRoomList: false });
    },

    /**
     * ✅ ĐÃ SỬA: Kết nối đến phòng với xử lý sự kiện đúng cách
     */
    connectToRoom: async (roomId) => {
        try {
            set({ error: null }); // Xóa mọi lỗi trước đó

            // Khởi tạo kết nối socket trước
            await socketManager.initialize();

            if (!socketManager.isConnected()) {
                set({ error: 'Không thể kết nối Socket.IO server' });
                return;
            }

            // ✅ SỬA: Lấy roomCode từ currentRoom thay vì sử dụng roomId trực tiếp
            const state = get();
            const roomCode = state.currentRoom?.roomCode || state.currentRoom?.code || state.currentRoom?.Code;

            if (!roomCode) {
                set({ error: 'Không tìm thấy mã phòng' });
                return;
            }

            // Thiết lập listeners trước - SỬA loại sự kiện để phù hợp với backend
            socketService.subscribeToRoom(roomId, (message) => {

                // ✅ SỬA: Xử lý CHÍNH XÁC loại sự kiện backend
                if (message.type === 'PLAYER_JOINED') {
                    const { userId, username } = message.data;

                    // Lấy danh sách người chơi mới thay vì cập nhật thủ công
                    get().fetchRoomPlayers(roomId);

                } else if (message.type === 'PLAYER_LEFT') {
                    const { userId } = message.data;

                    // Lấy danh sách người chơi mới thay vì cập nhật thủ công
                    get().fetchRoomPlayers(roomId);

                } else if (message.type === 'ROOM_PLAYERS_UPDATED') {
                    const { players } = message.data;
                    set({ roomPlayers: players });

                } else if (message.type === 'ROOM_UPDATED') {
                    const roomData = message.data;
                    set({ currentRoom: roomData });

                } else if (message.type === 'GAME_STARTED') {
                    // Gửi sự kiện tùy chỉnh để điều hướng
                    window.dispatchEvent(new CustomEvent('gameStarted', {
                        detail: { roomId: message.data.roomId }
                    }));

                } else if (message.type === 'PLAYER_KICKED') {
                    const { playerId, reason } = message.data;
                    const currentUserId = socketManager.getCurrentUserId();

                    if (playerId === currentUserId) {
                        get().clearCurrentRoom();
                        set({ error: reason || 'Bạn đã bị đuổi khỏi phòng' });
                    } else {
                        // Làm mới danh sách người chơi
                        get().fetchRoomPlayers(roomId);
                    }

                } else if (message.type === 'HOST_CHANGED') {
                    const { newHostId } = message.data;
                    set(state => ({
                        currentRoom: state.currentRoom ? {
                            ...state.currentRoom,
                            ownerId: newHostId,
                            hostId: newHostId
                        } : null
                    }));

                    // Làm mới danh sách người chơi để cập nhật trạng thái host
                    get().fetchRoomPlayers(roomId);
                }
            });

            // ✅ SỬA: Tham gia phòng qua Socket.IO sử dụng roomCode thay vì roomId
            return new Promise((resolve, reject) => {
                const timeout = setTimeout(() => {
                    set({ error: 'Timeout khi kết nối đến phòng' });
                    reject(new Error('Join room timeout'));
                }, 10000);

                socketService.joinRoom(roomCode, (response) => {
                    clearTimeout(timeout);

                    if (response?.success !== false) {
                        set({ isConnectedToRoom: true });

                        // Lấy người chơi ban đầu sau khi kết nối thành công
                        get().fetchRoomPlayers(roomId);
                        resolve();
                    } else {
                        const errorMsg = response?.message || response?.error || 'Không thể kết nối đến phòng';

                        if (errorMsg.includes('Room is full') ||
                            errorMsg.includes('User already joined') ||
                            errorMsg.includes('already joined')) {
                            set({
                                isConnectedToRoom: true,
                                error: null  // Xóa mọi trạng thái lỗi
                            });

                            // Vẫn thử lấy người chơi để đảm bảo UI được cập nhật
                            get().fetchRoomPlayers(roomId);
                            resolve();
                        } else {
                            set({ error: errorMsg });
                            reject(new Error(errorMsg));
                        }
                    }
                });
            });
        } catch (error) {
            set({ error: error.message || 'Không thể kết nối đến phòng' });
            throw error;
        }
    },

    /**
     * Ngắt kết nối khỏi phòng hiện tại
     */
    disconnectFromRoom: (roomId) => {
        if (!roomId) {
            return;
        }

        // Hủy đăng ký sự kiện phòng
        socketService.unsubscribeFromRoom(roomId);

        // Rời phòng Socket.IO nếu đã kết nối
        if (socketService.isConnected()) {
            socketService.leaveRoom(roomId, (response) => {
            });
        }

        set({ isConnectedToRoom: false });
    },

    // ========== HÀNH ĐỘNG TÍCH HỢP API ==========

    createRoom: async (roomData) => {
        set({ isLoading: true, loading: true, error: null });

        try {
            const response = await roomApi.createRoom(roomData);

            if (response.success) {
                const newRoom = response.data;

                set({
                    currentRoom: newRoom,
                    isLoading: false,
                    loading: false
                });

                // Kết nối đến phòng vừa tạo với xử lý lỗi được cải thiện
                try {
                    await get().connectToRoom(newRoom.id);
                } catch (connectError) {
                    // ✅ CẢI THIỆN: Xử lý các lỗi kết nối phổ biến một cách nhẹ nhàng
                    if (connectError.message.includes('Room is full') ||
                        connectError.message.includes('User already joined') ||
                        connectError.message.includes('already joined')) {
                        // Người dùng đã ở trong phòng (từ việc tạo), đây là trạng thái mong muốn
                        set({
                            isConnectedToRoom: true,
                            error: null  // Xóa mọi trạng thái lỗi
                        });
                        // Lấy người chơi để đảm bảo UI được cập nhật đúng cách
                        get().fetchRoomPlayers(newRoom.id);
                    } else {
                        // Không thất bại toàn bộ hoạt động cho các lỗi socket khác
                        // Phòng được tạo thành công, người dùng vẫn có thể sử dụng
                    }
                }

                return { success: true, room: newRoom };
            } else {
                set({ error: response.error, isLoading: false, loading: false });
                return { success: false, error: response.error };
            }
        } catch (error) {
            const errorMessage = error.message || 'Có lỗi xảy ra khi tạo phòng';
            set({ error: errorMessage, isLoading: false, loading: false });
            return { success: false, error: errorMessage };
        }
    },

    joinRoomByCode: async (roomCode) => {
        set({ isLoading: true, loading: true, error: null });

        try {
            const response = await roomApi.joinRoomByCode(roomCode);

            if (response.success) {
                const room = response.data;
                set({ currentRoom: room, isLoading: false, loading: false });

                // ✅ CẢI THIỆN: Xử lý lỗi kết nối nhẹ nhàng cho việc tham gia dựa trên mã
                try {
                    await get().connectToRoom(room.id);
                    return {
                        success: true,
                        room,
                        data: {
                            Code: room.code || room.roomCode,
                            message: 'Tham gia phòng thành công'
                        }
                    };
                } catch (connectError) {
                    if (connectError.message.includes('Room is full') ||
                        connectError.message.includes('User already joined') ||
                        connectError.message.includes('already joined')) {
                        set({
                            isConnectedToRoom: true,
                            error: null
                        });
                        get().fetchRoomPlayers(room.id);
                        return {
                            success: true,
                            room,
                            data: {
                                Code: room.code || room.roomCode,
                                message: 'Tham gia phòng thành công'
                            }
                        };
                    } else {
                        throw connectError; // Ném lại các lỗi kết nối khác
                    }
                }
            } else {
                set({ error: response.error, isLoading: false, loading: false });
                return { success: false, error: response.error };
            }
        } catch (error) {
            const errorMessage = error.message || 'Không thể tham gia phòng';
            set({ error: errorMessage, isLoading: false, loading: false });
            return { success: false, error: errorMessage };
        }
    },

    joinRoomDirect: async (roomId) => {
        set({ isLoading: true, loading: true, error: null });

        try {
            const response = await roomApi.joinRoomDirect(roomId);

            if (response.success) {
                const room = response.data;
                set({ currentRoom: room, isLoading: false, loading: false });

                // ✅ CẢI THIỆN: Xử lý lỗi kết nối nhẹ nhàng cho việc tham gia trực tiếp
                try {
                    await get().connectToRoom(room.id);
                    return { success: true, room };
                } catch (connectError) {
                    if (connectError.message.includes('Room is full') ||
                        connectError.message.includes('User already joined') ||
                        connectError.message.includes('already joined')) {
                        set({
                            isConnectedToRoom: true,
                            error: null
                        });
                        get().fetchRoomPlayers(room.id);
                        return { success: true, room };
                    } else {
                        throw connectError; // Ném lại các lỗi kết nối khác
                    }
                }
            } else {
                set({ error: response.error, isLoading: false, loading: false });
                return { success: false, error: response.error };
            }
        } catch (error) {
            const errorMessage = error.message || 'Không thể tham gia phòng';
            set({ error: errorMessage, isLoading: false, loading: false });
            return { success: false, error: errorMessage };
        }
    },

    // Bí danh để tương thích ngược
    joinRoom: async (roomCode) => {
        return await get().joinRoomByCode(roomCode);
    },

    leaveRoom: async () => {
        const state = get();
        if (!state.currentRoom) {
            return { success: false, error: 'Không có phòng để rời' };
        }

        const roomId = state.currentRoom.id;

        try {
            // Ngắt kết nối từ Socket.IO trước
            get().disconnectFromRoom(roomId);

            // Xóa trạng thái phòng ngay lập tức để cập nhật UI tức thì
            get().clearCurrentRoom();

            // Sau đó gọi REST API để rời phòng
            const response = await roomApi.leaveRoom(roomId);

            if (response.success) {

                // Buộc làm mới danh sách phòng để đảm bảo UI được cập nhật
                setTimeout(() => {
                    get().fetchRooms();
                }, 100);

                // ✅ Kích hoạt điều hướng đến RoomPage sau khi rời thành công
                window.dispatchEvent(new CustomEvent('navigateToRoomList', {
                    detail: {
                        reason: 'left_room',
                        message: 'Đã rời phòng thành công'
                    }
                }));

                return { success: true };
            } else {
                set({ error: response.error });
                return { success: false, error: response.error };
            }
        } catch (error) {
            const errorMessage = error.message || 'Không thể rời phòng';
            set({ error: errorMessage });
            return { success: false, error: errorMessage };
        }
    },

    fetchRooms: async (params = {}) => {
        const state = get();
        if (state.isLoading) {
            return { success: false, error: 'Yêu cầu đang được xử lý' };
        }

        set({ isLoading: true, loading: true, error: null });

        try {
            const response = await roomApi.getPublicRooms(params);

            if (response.success) {
                const roomsData = response.data.content || response.data.rooms || response.data || [];
                set({ rooms: roomsData, isLoading: false, loading: false });

                // Đăng ký cập nhật thời gian thực sau khi tải ban đầu
                if (!state.isSubscribedToRoomList) {
                    get().subscribeToRoomList();
                }

                return { success: true, rooms: roomsData };
            } else {
                set({ error: response.error, isLoading: false, loading: false });
                return { success: false, error: response.error };
            }
        } catch (error) {
            const errorMessage = error.message || 'Không thể tải danh sách phòng';
            set({ error: errorMessage, isLoading: false, loading: false });
            return { success: false, error: errorMessage };
        }
    },

    /**
     * ✅ ĐÃ SỬA: Lấy người chơi phòng với xử lý lỗi đúng cách
     */
    fetchRoomPlayers: async (roomId) => {
        if (!roomId) {
            return { success: false, error: 'Không có ID phòng' };
        }

        try {
            const response = await roomApi.getRoomPlayers(roomId);
            if (response.success) {
                const players = response.data || [];
                set({ roomPlayers: players });
                return { success: true, players };
            } else {
                return { success: false, error: response.error };
            }
        } catch (error) {
            return { success: false, error: error.message };
        }
    },

    fetchMyRooms: async () => {
        set({ isLoading: true, loading: true, error: null });

        try {
            const response = await roomApi.getMyRooms();

            if (response.success) {
                const myRoomsData = response.data || [];
                set({ myRooms: myRoomsData, isLoading: false, loading: false });
                return { success: true, rooms: myRoomsData };
            } else {
                set({ error: response.error, isLoading: false, loading: false });
                return { success: false, error: response.error };
            }
        } catch (error) {
            const errorMessage = error.message || 'Không thể tải phòng của bạn';
            set({ error: errorMessage, isLoading: false, loading: false });
            return { success: false, error: errorMessage };
        }
    },

    kickPlayer: async (playerId) => {
        const state = get();
        if (!state.currentRoom) {
            return { success: false, error: 'Không có phòng hiện tại' };
        }

        try {
            const response = await roomApi.kickPlayer(state.currentRoom.id, playerId);
            return response;
        } catch (error) {
            const errorMessage = error.message || 'Không thể đuổi người chơi';
            return { success: false, error: errorMessage };
        }
    },

    deleteRoom: async (roomId) => {
        try {
            const response = await roomApi.deleteRoom(roomId);

            if (response.success) {
                set(state => ({
                    rooms: state.rooms.filter(room => room.id !== roomId),
                    myRooms: state.myRooms.filter(room => room.id !== roomId),
                    currentRoom: state.currentRoom?.id === roomId ? null : state.currentRoom
                }));
            }

            return response;
        } catch (error) {
            const errorMessage = error.message || 'Không thể xóa phòng';
            return { success: false, error: errorMessage };
        }
    },

    // ========== HÀNH ĐỘNG GAME ==========

    /**
     * ✅ ĐÃ SỬA: Bắt đầu game sử dụng Socket.IO
     */
    startGame: async () => {
        const state = get();
        if (!state.currentRoom) {
            return { success: false, error: 'Không có phòng để bắt đầu game' };
        }

        try {
            return new Promise((resolve) => {
                socketService.startGame(state.currentRoom.id, (response) => {
                    if (response?.success !== false) {
                        resolve({ success: true });
                    } else {
                        const errorMessage = response?.message || 'Không thể bắt đầu game';
                        set({ error: errorMessage });
                        resolve({ success: false, error: errorMessage });
                    }
                });
            });
        } catch (error) {
            const errorMessage = error.message || 'Có lỗi xảy ra khi bắt đầu game';
            set({ error: errorMessage });
            return { success: false, error: errorMessage };
        }
    },

    // ========== TỰ ĐỘNG LÀM MỚI & DỌN DẸP ==========

    autoRefreshInterval: null,

    startAutoRefresh: () => {
        const interval = setInterval(() => {
            if (!get().isSubscribedToRoomList) {
                get().fetchRooms();
            }
        }, 60000);

        set({ autoRefreshInterval: interval });
    },

    stopAutoRefresh: () => {
        const { autoRefreshInterval } = get();
        if (autoRefreshInterval) {
            clearInterval(autoRefreshInterval);
            set({ autoRefreshInterval: null });
        }
    },

    // Phương thức bí danh để tương thích ngược
    loadRooms: async (params = {}) => {
        return get().fetchRooms(params);
    },

    cleanup: () => {

        const state = get();

        if (state.currentRoom) {
            get().disconnectFromRoom(state.currentRoom.id);
        }

        get().unsubscribeFromRoomList();
        get().stopAutoRefresh();

        socketManager.disconnect();

        set({
            isConnectedToRoom: false,
            isSubscribedToRoomList: false,
            currentRoom: null,
            roomPlayers: [],
            autoRefreshInterval: null,
            animatingRooms: new Set(),
            newRoomIds: new Set()
        });

    }
}));

export default useRoomStore;

import { create } from 'zustand';
import roomApi from '../services/room-api';
import socketService from '../services/socket-service';
import socketManager from '../utils/socket-manager';

const useRoomStore = create((set, get) => ({
    // Trạng thái phòng
    currentRoom: null,
    rooms: [],
    roomPlayers: [],
    myRooms: [],
    isLoading: false,
    loading: false,
    error: null,
    isConnectedToRoom: false,
    isSubscribedToRoomList: false,

    // Trạng thái hoạt hình để phản hồi giao diện người dùng
    animatingRooms: new Set(),
    newRoomIds: new Set(),

    // Trạng thái nội bộ để tối ưu hóa
    _fetchPlayersTimer: null,

    // Hành động phòng
    setCurrentRoom: (room) => set({ currentRoom: room }),

    clearCurrentRoom: () => {
        const state = get();
        set({
            currentRoom: null,
            roomPlayers: [],
            isConnectedToRoom: false
        });
    },

    setLoading: (isLoading) => set({ isLoading, loading: isLoading }),

    setError: (error) => set({ error }),

    setRoomPlayers: (players) => set({ roomPlayers: players }),

    clearError: () => set({ error: null }),

    // Trợ giúp hoạt hình
    addAnimatingRoom: (roomId) => {
        set(state => ({
            animatingRooms: new Set(state.animatingRooms).add(roomId)
        }));
        setTimeout(() => {
            set(state => {
                const newSet = new Set(state.animatingRooms);
                newSet.delete(roomId);
                return { animatingRooms: newSet };
            });
        }, 1000);
    },

    addNewRoom: (roomId) => {
        set(state => ({
            newRoomIds: new Set(state.newRoomIds).add(roomId)
        }));
        setTimeout(() => {
            set(state => {
                const newSet = new Set(state.newRoomIds);
                newSet.delete(roomId);
                return { newRoomIds: newSet };
            });
        }, 3000);
    },

    // Quản lý kết nối WebSocket
    connectToRoom: async (roomId) => {
        try {
            // Kết nối đến Socket.IO nếu chưa kết nối
            if (!socketService.isConnected()) {
                await socketService.connect();
            }

            const state = get();
            if (state.isConnectedToRoom) {
                return;
            }

            // Thiết lập listeners sự kiện phòng
            get().setupRoomListeners();

            set({ isConnectedToRoom: true });
        } catch (error) {
            set({ isConnectedToRoom: false, error: error.message });
        }
    },

    disconnectFromRoom: (shouldLeaveRoom = false) => {
        const state = get();

        // Điều này ngăn phòng bị hủy khi tải lại/trở về trang
        if (shouldLeaveRoom && state.currentRoom) {
            socketService.leaveRoom(state.currentRoom.id);
        }
        // Ngắt kết nối im lặng cho việc unmount trang

        get().cleanupRoomListeners();
        set({ isConnectedToRoom: false });
    },

    // Thiết lập listeners Socket.IO cho sự kiện phòng
    setupRoomListeners: () => {
        get().cleanupRoomListeners();

        socketService.onPlayerJoined((data) => {
            // TỐI ƯU: Backend đã gửi mảng người chơi đầy đủ, không cần fetch
            if (data.players) {
                set({ roomPlayers: data.players });
            } else {
                // Fallback để fetch nếu không bao gồm người chơi
                get().fetchRoomPlayersDebounced(data.room?.id || data.roomId);
            }
        });

        socketService.onPlayerLeft((data) => {
            // TỐI ƯU: Sử dụng mảng người chơi từ sự kiện nếu có
            if (data.players) {
                set({ roomPlayers: data.players });
            } else {
                get().fetchRoomPlayersDebounced(data.roomId);
            }
        });

        socketService.onPlayerKicked((data) => {
            const state = get();
            const currentUserId = socketManager.getCurrentUserId();
            if (data.playerId === currentUserId) {
                set({ error: data.reason || 'Bạn đã bị đuổi khỏi phòng' });
                get().clearCurrentRoom();
                window.location.href = '/dashboard'; // Điều hướng về dashboard
            } else {
                get().fetchRoomPlayersDebounced(data.roomId);
            }
        });

        socketService.onGameStarted((data) => {
            const state = get();
            if (state.currentRoom && data.roomId === state.currentRoom.id) {
                window.dispatchEvent(new CustomEvent('gameStarted', { detail: data }));
            }
        });

        socketService.onRoomDeleted((data) => {
            const state = get();
            if (state.currentRoom && state.currentRoom.id === data.roomId) {
                set({ error: 'Phòng đã bị xóa', currentRoom: null, roomPlayers: [] });
                window.location.href = '/dashboard';
            }
        });

        // MỚI: Lắng nghe sự kiện host-changed khi host rời đi
        socketService.on('host-changed', (data) => {
            const state = get();
            if (state.currentRoom && state.currentRoom.id === data.roomId) {
                set({
                    currentRoom: {
                        ...state.currentRoom,
                        hostId: data.newHostId,
                        ownerId: data.newHostId,
                        ownerUsername: data.newHostUsername
                    }
                });
                // Làm mới danh sách người chơi để hiển thị host mới
                get().fetchRoomPlayersDebounced(data.roomId);
            }
        });
    },

    // Dọn dẹp listeners Socket.IO
    cleanupRoomListeners: () => {
        socketService.off('player-joined');
        socketService.off('player-left');
        socketService.off('player-kicked');
        socketService.off('game-started');
        socketService.off('room-players');
        socketService.off('host-changed'); // ✅ NEW: Clean up host-changed listener
    },

    // Hoạt động CRUD phòng
    createRoom: async (roomData) => {
        set({ isLoading: true, loading: true, error: null });

        try {
            const result = await roomApi.createRoom(roomData);

            if (result.success) {
                set({
                    currentRoom: result.data,
                    isLoading: false,
                    loading: false
                });

                // MỚI: Tự động tham gia phòng Socket.IO sau khi tạo
                if (!socketService.isConnected()) {
                    await socketService.connect();
                }

                const roomCodeToJoin = result.data.roomCode || result.data.code;
                if (roomCodeToJoin) {
                    // Thiết lập listeners trước khi tham gia
                    get().setupRoomListeners();

                    socketService.joinRoom(roomCodeToJoin, (response) => {
                        if (response?.success) {
                        } else {
                        }
                    });
                }

                return result;
            } else {
                set({
                    error: result.error,
                    isLoading: false,
                    loading: false
                });
                return result;
            }
        } catch (error) {
            const errorMessage = error.message || 'Có lỗi xảy ra khi tạo phòng';
            set({
                error: errorMessage,
                isLoading: false,
                loading: false
            });
            return { success: false, error: errorMessage };
        }
    },

    joinRoomByCode: async (roomCode) => {
        set({ isLoading: true, loading: true, error: null });

        try {
            // Join via REST API
            const result = await roomApi.joinRoomByCode(roomCode);

            if (result.success) {
                set({
                    currentRoom: result.data,
                    isLoading: false,
                    loading: false,
                    error: null
                });

                // Kết nối đến Socket.IO sau khi tham gia thành công
                if (!socketService.isConnected()) {
                    await socketService.connect();
                }

                // Thiết lập listeners sau khi tham gia
                get().setupRoomListeners();

                // ĐÃ SỬA: Tham gia phòng Socket.IO sử dụng roomCode (backend mong đợi roomCode)
                const roomCodeToJoin = result.data.roomCode || result.data.code || roomCode;
                socketService.joinRoom(roomCodeToJoin, (response) => {
                    if (response?.success) {
                    } else {
                        // Không thất bại toàn bộ hoạt động tham gia - Socket.IO chỉ dành cho real-time
                    }
                });

                return result;
            } else {
                set({
                    error: result.error,
                    isLoading: false,
                    loading: false
                });
                return result;
            }
        } catch (error) {
            const errorMessage = error.message || 'Có lỗi xảy ra khi tham gia phòng';
            set({
                error: errorMessage,
                isLoading: false,
                loading: false
            });
            return { success: false, error: errorMessage };
        }
    },

    leaveRoom: async () => {
        const state = get();
        if (!state.currentRoom) {
            return { success: false, error: 'Không có phòng để rời' };
        }

        try {
            // Leave room
            const result = await roomApi.leaveRoom(state.currentRoom.id);

            if (result.success) {
                // Ngắt kết nối và thực sự rời phòng
                get().disconnectFromRoom(true); // Truyền true để thực sự rời
                get().clearCurrentRoom();

                return { success: true };
            } else {
                set({ error: result.error });
                return result;
            }
        } catch (error) {
            const errorMessage = error.message || 'Có lỗi xảy ra khi rời phòng';
            set({ error: errorMessage });
            return { success: false, error: errorMessage };
        }
    },

    fetchRooms: async (params = {}) => {
        set({ isLoading: true, loading: true, error: null });

        try {
            const result = await roomApi.getPublicRooms(params);

            if (result.success) {
                const rooms = result.data.content || result.data.rooms || result.data || [];
                set({
                    rooms,
                    isLoading: false,
                    loading: false
                });
                return { success: true, data: rooms };
            } else {
                set({
                    error: result.error,
                    isLoading: false,
                    loading: false
                });
                return result;
            }
        } catch (error) {
            const errorMessage = error.message || 'Có lỗi xảy ra khi tải danh sách phòng';
            set({
                error: errorMessage,
                isLoading: false,
                loading: false
            });
            return { success: false, error: errorMessage };
        }
    },

    fetchRoomPlayers: async (roomId) => {
        if (!roomId) {
            return { success: false, error: 'Không có ID phòng' };
        }

        try {
            const result = await roomApi.getRoomPlayers(roomId);

            if (result.success) {
                set({ roomPlayers: result.data || [] });
                return { success: true, data: result.data };
            } else {
                // Im lặng thất bại cho lỗi "không tìm thấy phòng" (phòng zombie)
                if (result.error?.includes('not found') || result.error?.includes('không tìm thấy')) {
                    return { success: false, error: null };
                }
                return result;
            }
        } catch (error) {
            // Im lặng thất bại cho lỗi "không tìm thấy phòng"
            const errorMsg = error.message || 'Có lỗi xảy ra khi tải danh sách người chơi';
            if (errorMsg.includes('not found') || errorMsg.includes('không tìm thấy')) {
                return { success: false, error: null };
            }
            return { success: false, error: errorMsg };
        }
    },

    // Phiên bản debounced để ngăn nhiều cuộc gọi nhanh liên tiếp
    fetchRoomPlayersDebounced: (roomId, delay = 300) => {
        const state = get();

        // Xóa timer hiện có
        if (state._fetchPlayersTimer) {
            clearTimeout(state._fetchPlayersTimer);
        }

        // Đặt timer mới
        const timer = setTimeout(() => {
            get().fetchRoomPlayers(roomId);
            set({ _fetchPlayersTimer: null });
        }, delay);

        set({ _fetchPlayersTimer: timer });
    },

    // Các phương thức bí danh để tương thích ngược
    loadRooms: async (params = {}) => {
        return get().fetchRooms(params);
    },

    joinRoom: async (roomCode) => {
        return get().joinRoomByCode(roomCode);
    },

    // Các phương thức tự động làm mới
    startAutoRefresh: () => {
        // Có thể thêm implementation nếu cần
    },

    stopAutoRefresh: () => {
        // Có thể thêm implementation nếu cần
    },

    subscribeToRoomList: async () => {
        try {
            const state = get();
            if (state.isSubscribedToRoomList) {
                return;
            }

            if (!socketService.isConnected()) {
                await socketService.connect();
            }

            socketService.subscribeToRoomList((message) => {

                if (message.type === 'CREATE_ROOM') {
                    const room = message.data?.room || message.data;
                    if (room && room.id) {
                        set(state => {
                            const exists = state.rooms.find(r => r.id === room.id);
                            if (!exists) {
                                get().addNewRoom(room.id);
                                get().addAnimatingRoom(room.id);
                                return { rooms: [room, ...state.rooms] };
                            }
                            return state;
                        });
                    }
                } else if (message.type === 'ROOM_DELETED') {
                    const roomId = message.data?.roomId || message.data?.id;
                    if (roomId) {
                        set(state => {
                            const updatedRooms = state.rooms.filter(room => room.id !== roomId);
                            if (state.currentRoom?.id === roomId) {
                                window.location.href = '/dashboard';
                                return { rooms: updatedRooms, currentRoom: null, roomPlayers: [] };
                            }
                            return { rooms: updatedRooms };
                        });
                    }
                } else if (message.type === 'ROOM_UPDATED') {
                    const room = message.data?.room || message.data;
                    if (room && room.id) {
                        set(state => ({
                            rooms: state.rooms.map(r => r.id === room.id ? room : r),
                            currentRoom: state.currentRoom?.id === room.id ? room : state.currentRoom
                        }));
                    }
                }
            });

            set({ isSubscribedToRoomList: true });
        } catch (error) {
            set({ error: 'Không thể kết nối real-time updates' });
        }
    },

    unsubscribeFromRoomList: () => {
        try {
            socketService.unsubscribeFromRoomList();
        } catch {}
        socketService.setOnRoomCreated(null);
        socketService.setOnRoomDeleted(null);
        socketService.setOnRoomUpdated(null);
        set({ isSubscribedToRoomList: false });
    },

    startGame: async () => {
        const state = get();
        if (!state.currentRoom) {
            return { success: false, error: 'Không có phòng để bắt đầu game' };
        }

        try {
            // Sử dụng Socket.IO để bắt đầu game real-time
            return new Promise((resolve) => {
                socketService.startGame(state.currentRoom.id, (response) => {
                    if (response?.success !== false) {
                        resolve({ success: true });
                    } else {
                        const errorMessage = response?.message || 'Không thể bắt đầu game';
                        set({ error: errorMessage });
                        resolve({ success: false, error: errorMessage });
                    }
                });
            });
        } catch (error) {
            const errorMessage = error.message || 'Có lỗi xảy ra khi bắt đầu game';
            set({ error: errorMessage });
            return { success: false, error: errorMessage };
        }
    },

    // Dọn dẹp - chỉ sử dụng cho việc dọn dẹp cấp ứng dụng
    cleanup: () => {
        // Ngắt kết nối KHÔNG rời phòng (cho việc điều hướng trang/tải lại)
        get().disconnectFromRoom(false);

        set({
            isConnectedToRoom: false,
            isSubscribedToRoomList: false,
            currentRoom: null,
            roomPlayers: [],
            animatingRooms: new Set(),
            newRoomIds: new Set()
        });
    },

    fullCleanup: () => {
        // Ngắt kết nối VÀ rời phòng
        get().disconnectFromRoom(true);

        set({
            isConnectedToRoom: false,
            isSubscribedToRoomList: false,
            currentRoom: null,
            roomPlayers: [],
            rooms: [],
            myRooms: [],
            animatingRooms: new Set(),
            newRoomIds: new Set()
        });
    }
}));

